INSERT INTO "sources" ("id", "title", "author", "type", "citation_short", "url", "language", "corpus_id", "note", "raw_json") VALUES ('zizhi-tongjian-75', '资治通鉴·卷七十五', '司马光', 'chronicle', '《资治通鉴》卷七十五', 'https://www.guoxue.com/shibu/zztj/content/zztj_075.htm', 'zh-Hans', 'china-three-kingdoms', '覆盖正始后期至嘉平三年前后，高平陵政变、王凌谋立曹彪案等曹魏后期权力转折。', '{"id":"zizhi-tongjian-75","title":"资治通鉴·卷七十五","author":"司马光","type":"chronicle","citationShort":"《资治通鉴》卷七十五","url":"https://www.guoxue.com/shibu/zztj/content/zztj_075.htm","note":"覆盖正始后期至嘉平三年前后，高平陵政变、王凌谋立曹彪案等曹魏后期权力转折。"}');
INSERT INTO "sources" ("id", "title", "author", "type", "citation_short", "url", "language", "corpus_id", "note", "raw_json") VALUES ('zizhi-tongjian-76', '资治通鉴·卷七十六', '司马光', 'chronicle', '《资治通鉴》卷七十六', 'https://www.guoxue.com/shibu/zztj/content/zztj_076.htm', 'zh-Hans', 'china-three-kingdoms', '覆盖嘉平五年至正元、甘露之际，司马师废曹芳、立曹髦以及魏吴蜀后期政局。', '{"id":"zizhi-tongjian-76","title":"资治通鉴·卷七十六","author":"司马光","type":"chronicle","citationShort":"《资治通鉴》卷七十六","url":"https://www.guoxue.com/shibu/zztj/content/zztj_076.htm","note":"覆盖嘉平五年至正元、甘露之际，司马师废曹芳、立曹髦以及魏吴蜀后期政局。"}');
INSERT INTO "sources" ("id", "title", "author", "type", "citation_short", "url", "language", "corpus_id", "note", "raw_json") VALUES ('zizhi-tongjian-77', '资治通鉴·卷七十七', '司马光', 'chronicle', '《资治通鉴》卷七十七', 'https://www.guoxue.com/shibu/zztj/content/zztj_077.htm', 'zh-Hans', 'china-three-kingdoms', '覆盖甘露、景元初年前后，曹髦反抗司马昭、被弑及曹奂继立。', '{"id":"zizhi-tongjian-77","title":"资治通鉴·卷七十七","author":"司马光","type":"chronicle","citationShort":"《资治通鉴》卷七十七","url":"https://www.guoxue.com/shibu/zztj/content/zztj_077.htm","note":"覆盖甘露、景元初年前后，曹髦反抗司马昭、被弑及曹奂继立。"}');
