INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-193-severus-army-proclamation', 'rome-source-history-of-the-empire-after-marcus-herodian', NULL, '2.9-2.12', 0, 193, 193, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '赫罗狄安叙述佩尔蒂纳克斯遇害后，禁卫军与尤利安努斯造成罗马政局崩坏，塞维鲁依托潘诺尼亚军队入局并重塑首都军事秩序。', 'zh-Hans', '赫罗狄安有强烈道德叙事色彩，但事件主线可与其他古代叙事互证。', 'high', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-193-severus-army-proclamation","sourceId":"rome-source-history-of-the-empire-after-marcus-herodian","sourceTitle":"History of the Empire after Marcus","sourceCitation":"Herodian, History of the Empire","sourceUrl":"https://www.tertullian.org/fathers/herodian_01_book1.htm","locator":"2.9-2.12","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"赫罗狄安叙述佩尔蒂纳克斯遇害后，禁卫军与尤利安努斯造成罗马政局崩坏，塞维鲁依托潘诺尼亚军队入局并重塑首都军事秩序。","titleZh":"塞维鲁由潘诺尼亚军队拥立并进军罗马","titleEn":"Severus is proclaimed by the Pannonian army and marches on Rome","factBrief":"赫罗狄安把 193 年的权力转移写成军队政治的转折点：潘诺尼亚军团拥立塞维鲁，他随后迅速进军罗马，清算尤利安努斯和旧禁卫军。","factBriefEn":"Herodian presents 193 as a turning point in army politics: the Pannonian legions acclaimed Severus, who then marched rapidly on Rome and broke the old Praetorian settlement.","peopleCore":["Septimius Severus","Didius Julianus","Pertinax"],"peopleMentioned":[],"places":["Pannonia","Rome"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"塞维鲁由潘诺尼亚军队拥立并进军罗马","eventLabelEn":"Severus is proclaimed by the Pannonian army and marches on Rome","factType":"military","confidence":"high","disputeNote":"赫罗狄安有强烈道德叙事色彩，但事件主线可与其他古代叙事互证。","tags":["succession","army","civil-war"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-194-niger-defeat-issus', 'rome-source-roman-history-cassius-dio', NULL, '75.6-75.7', 1, 194, 194, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '材料显示，塞维鲁先控制罗马与西方，再转向东方，击败叙利亚军团拥立的佩斯森尼乌斯·尼格尔，并处置支持尼格尔的东方城市。', 'zh-Hans', '战役地点和围城细节在古代叙述中有压缩，具体战术细节不宜过度展开。', 'high', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-194-niger-defeat-issus","sourceId":"rome-source-roman-history-cassius-dio","sourceTitle":"Roman History","sourceCitation":"Cassius Dio, Roman History","sourceUrl":"https://penelope.uchicago.edu/Thayer/E/Roman/Texts/Cassius_Dio/home.html","locator":"75.6-75.7","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"材料显示，塞维鲁先控制罗马与西方，再转向东方，击败叙利亚军团拥立的佩斯森尼乌斯·尼格尔，并处置支持尼格尔的东方城市。","titleZh":"塞维鲁击败尼格尔并取得东方行省","titleEn":"Severus defeats Niger and secures the eastern provinces","factBrief":"狄奥把尼格尔战争作为塞维鲁统一帝国的关键阶段：叙利亚军团支持尼格尔，塞维鲁在伊苏斯附近击败他。","factBriefEn":"Dio treats the war against Niger as the eastern stage of Severus'' consolidation, ending with Niger''s defeat near Issus.","peopleCore":["Septimius Severus","Pescennius Niger"],"peopleMentioned":[],"places":["Issus","Syria","Antioch","Byzantium"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"塞维鲁击败尼格尔并取得东方行省","eventLabelEn":"Severus defeats Niger and secures the eastern provinces","factType":"military","confidence":"high","disputeNote":"战役地点和围城细节在古代叙述中有压缩，具体战术细节不宜过度展开。","tags":["war","civil-war","frontier"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-197-lugdunum-albinus', 'rome-source-roman-history-cassius-dio', NULL, '76.6-76.7', 2, 197, 197, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '阿尔比努斯原被塞维鲁用作西方盟友和储君式人物，后来双方决裂。197 年战败后，塞维鲁的皇权不再有同等级内战对手。', 'zh-Hans', '兵力数字和清洗规模应标为古代叙事数字，不宜直接当作精确统计。', 'high', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-197-lugdunum-albinus","sourceId":"rome-source-roman-history-cassius-dio","sourceTitle":"Roman History","sourceCitation":"Cassius Dio, Roman History","sourceUrl":"https://penelope.uchicago.edu/Thayer/E/Roman/Texts/Cassius_Dio/home.html","locator":"76.6-76.7","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"阿尔比努斯原被塞维鲁用作西方盟友和储君式人物，后来双方决裂。197 年战败后，塞维鲁的皇权不再有同等级内战对手。","titleZh":"里昂战役后塞维鲁消灭阿尔比努斯","titleEn":"After Lugdunum, Severus destroys Albinus'' western challenge","factBrief":"狄奥记载里昂战役是塞维鲁与阿尔比努斯之间的大规模内战，胜利后塞维鲁完成对西方军政集团的清洗。","factBriefEn":"Dio describes Lugdunum as a major civil-war battle between Severus and Albinus, after which Severus purged the western opposition.","peopleCore":["Septimius Severus","Clodius Albinus"],"peopleMentioned":[],"places":["Lugdunum","Gaul","Britannia"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"里昂战役后塞维鲁消灭阿尔比努斯","eventLabelEn":"After Lugdunum, Severus destroys Albinus'' western challenge","factType":"military","confidence":"high","disputeNote":"兵力数字和清洗规模应标为古代叙事数字，不宜直接当作精确统计。","tags":["war","succession","civil-war"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-211-geta-murder', 'rome-source-roman-history-cassius-dio', NULL, '78.2-78.4', 3, 211, 211, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '塞维鲁死后，卡拉卡拉与盖塔共同继位，但矛盾无法调和。盖塔被杀后，卡拉卡拉成为唯一皇帝，并展开对盖塔支持者的清算。', 'zh-Hans', '细节受狄奥反卡拉卡拉立场影响，但盖塔被杀及随后清洗是稳固事实。', 'high', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-211-geta-murder","sourceId":"rome-source-roman-history-cassius-dio","sourceTitle":"Roman History","sourceCitation":"Cassius Dio, Roman History","sourceUrl":"https://penelope.uchicago.edu/Thayer/E/Roman/Texts/Cassius_Dio/home.html","locator":"78.2-78.4","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"塞维鲁死后，卡拉卡拉与盖塔共同继位，但矛盾无法调和。盖塔被杀后，卡拉卡拉成为唯一皇帝，并展开对盖塔支持者的清算。","titleZh":"卡拉卡拉杀死共治兄弟盖塔","titleEn":"Caracalla kills his co-emperor Geta","factBrief":"狄奥把盖塔之死写成塞维鲁王朝内部共治失败的核心事件：兄弟共治迅速转为宫廷暴力和政治清洗。","factBriefEn":"Dio presents Geta''s death as the collapse of Severan co-rule: fraternal power-sharing turned into palace violence and political purge.","peopleCore":["Caracalla","Geta","Julia Domna"],"peopleMentioned":[],"places":["Rome"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"卡拉卡拉杀死共治兄弟盖塔","eventLabelEn":"Caracalla kills his co-emperor Geta","factType":"succession","confidence":"high","disputeNote":"细节受狄奥反卡拉卡拉立场影响，但盖塔被杀及随后清洗是稳固事实。","tags":["succession","assassination","dynasty"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-212-constitutio-antoniniana', 'rome-source-roman-history-cassius-dio', NULL, '78.9', 4, 212, 212, 'Short source note based on Dio 78.9; no extended excerpt stored.', '狄奥认为卡拉卡拉名义上是在给帝国臣民荣誉，实际也扩大了某些税种的征收范围。该事件应同时关联法律、财政和帝国身份。', 'zh-Hans', '敕令原件残缺，狄奥的动机解释可能带有元老院立场；事实和动机应分开展示。', 'high', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-212-constitutio-antoniniana","sourceId":"rome-source-roman-history-cassius-dio","sourceTitle":"Roman History","sourceCitation":"Cassius Dio, Roman History","sourceUrl":"https://penelope.uchicago.edu/Thayer/E/Roman/Texts/Cassius_Dio/home.html","locator":"78.9","originalText":"Short source note based on Dio 78.9; no extended excerpt stored.","originalTextMissing":true,"translation":"狄奥认为卡拉卡拉名义上是在给帝国臣民荣誉，实际也扩大了某些税种的征收范围。该事件应同时关联法律、财政和帝国身份。","titleZh":"安东尼努斯敕令扩大罗马公民权","titleEn":"The Antonine Constitution extends Roman citizenship","factBrief":"狄奥解释卡拉卡拉授予帝国内自由民公民权带有财政动机；这为理解三世纪帝国身份、税收和法律整合提供主证。","factBriefEn":"Dio explains Caracalla''s grant of citizenship to free inhabitants of the empire as fiscally motivated, making it central evidence for imperial identity and taxation.","peopleCore":["Caracalla"],"peopleMentioned":[],"places":["Roman Empire"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"安东尼努斯敕令扩大罗马公民权","eventLabelEn":"The Antonine Constitution extends Roman citizenship","factType":"political_structure","confidence":"high","disputeNote":"敕令原件残缺，狄奥的动机解释可能带有元老院立场；事实和动机应分开展示。","tags":["law","taxation","political-structure"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-235-alexander-death-maximinus', 'rome-source-history-of-the-empire-after-marcus-herodian', NULL, '6.8-6.9', 5, 235, 235, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '亚历山大·塞维鲁在莱茵前线处理日耳曼问题时失去军心，被士兵杀死；出身军旅的马克西米努斯随即被拥立。', 'zh-Hans', '“三世纪危机起点”是现代分期，古代材料只提供政变和军队不满的叙述。', 'high', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-235-alexander-death-maximinus","sourceId":"rome-source-history-of-the-empire-after-marcus-herodian","sourceTitle":"History of the Empire after Marcus","sourceCitation":"Herodian, History of the Empire","sourceUrl":"https://www.tertullian.org/fathers/herodian_01_book1.htm","locator":"6.8-6.9","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"亚历山大·塞维鲁在莱茵前线处理日耳曼问题时失去军心，被士兵杀死；出身军旅的马克西米努斯随即被拥立。","titleZh":"亚历山大·塞维鲁遇害，马克西米努斯被军队拥立","titleEn":"Alexander Severus is killed and Maximinus is raised by the army","factBrief":"赫罗狄安将 235 年描述为军队不满和边境压力引发的政权断裂，通常被视为三世纪危机的开端。","factBriefEn":"Herodian frames 235 as a rupture produced by army resentment and frontier pressure, often treated as the opening of the Third Century Crisis.","peopleCore":["Alexander Severus","Maximinus Thrax","Julia Mamaea"],"peopleMentioned":[],"places":["Rhine frontier","Mogontiacum"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"亚历山大·塞维鲁遇害，马克西米努斯被军队拥立","eventLabelEn":"Alexander Severus is killed and Maximinus is raised by the army","factType":"military","confidence":"high","disputeNote":"“三世纪危机起点”是现代分期，古代材料只提供政变和军队不满的叙述。","tags":["succession","army","frontier","assassination"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-238-six-emperors', 'rome-source-history-of-the-empire-after-marcus-herodian', NULL, '7.5-8.8', 6, 238, 238, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '戈尔迪安父子、普皮恩努斯、巴尔比努斯、戈尔迪安三世与马克西米努斯的命运交织，说明罗马皇权已高度依赖军队和首都暴力。', 'zh-Hans', '赫罗狄安是关键叙事源，但对群众心理和演说的描写带有文学加工。', 'high', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-238-six-emperors","sourceId":"rome-source-history-of-the-empire-after-marcus-herodian","sourceTitle":"History of the Empire after Marcus","sourceCitation":"Herodian, History of the Empire","sourceUrl":"https://www.tertullian.org/fathers/herodian_01_book1.htm","locator":"7.5-8.8","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"戈尔迪安父子、普皮恩努斯、巴尔比努斯、戈尔迪安三世与马克西米努斯的命运交织，说明罗马皇权已高度依赖军队和首都暴力。","titleZh":"六帝之年显示军队、元老院与地方起义的多重冲突","titleEn":"The Year of the Six Emperors exposes army, senate, and provincial conflict","factBrief":"赫罗狄安对 238 年的长篇叙述展示了非洲起义、元老院拥立、禁卫军和边防军之间的连锁冲突。","factBriefEn":"Herodian''s long account of 238 shows the chain reaction among the African revolt, senatorial politics, Praetorian violence, and frontier armies.","peopleCore":["Maximinus Thrax","Gordian I","Gordian II","Pupienus","Balbinus","Gordian III"],"peopleMentioned":[],"places":["Africa","Rome","Aquileia"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"六帝之年显示军队、元老院与地方起义的多重冲突","eventLabelEn":"The Year of the Six Emperors exposes army, senate, and provincial conflict","factType":"military","confidence":"high","disputeNote":"赫罗狄安是关键叙事源，但对群众心理和演说的描写带有文学加工。","tags":["succession","usurpation","army"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-249-decius-accession', 'rome-source-breviarium-ab-urbe-condita-eutropius', NULL, '9.4', 7, 249, 249, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '该卡用于补足 249 年前后皇帝更替的年表节点，细节仍需与钱币、铭文和其他叙事材料互证。', 'zh-Hans', '欧特罗庇乌斯文字压缩，不足以单独解释政变原因。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-249-decius-accession","sourceId":"rome-source-breviarium-ab-urbe-condita-eutropius","sourceTitle":"Breviarium ab Urbe Condita","sourceCitation":"Eutropius, Breviarium","sourceUrl":"https://www.tertullian.org/fathers/eutropius_breviarium_2_text.htm","locator":"9.4","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"该卡用于补足 249 年前后皇帝更替的年表节点，细节仍需与钱币、铭文和其他叙事材料互证。","titleZh":"德西乌斯取代腓力并开启短命军人皇帝阶段","titleEn":"Decius replaces Philip and marks the brief soldier-emperor pattern","factBrief":"欧特罗庇乌斯简要记录腓力之后德西乌斯称帝，这类摘要虽然简短，却能为三世纪皇帝更替建立基础年表。","factBriefEn":"Eutropius briefly records Decius'' succession after Philip; such epitomes are useful for the basic chronology of rapid third-century imperial turnover.","peopleCore":["Decius","Philip the Arab"],"peopleMentioned":[],"places":["Roman Empire"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"德西乌斯取代腓力并开启短命军人皇帝阶段","eventLabelEn":"Decius replaces Philip and marks the brief soldier-emperor pattern","factType":"military","confidence":"medium","disputeNote":"欧特罗庇乌斯文字压缩，不足以单独解释政变原因。","tags":["succession","army"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-250-decius-persecution', 'rome-source-ecclesiastical-history-eusebius', NULL, '6.39-6.41', 8, 250, 250, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '该材料应作为宗教政策和帝国治理证据，而不是只放在教会史脉络中。迫害范围、执行差异和地方文书证据需要单独标注。', 'zh-Hans', '优西比乌从基督徒受迫害立场书写，行政层面的全貌需要结合纸草和地方材料。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-250-decius-persecution","sourceId":"rome-source-ecclesiastical-history-eusebius","sourceTitle":"Ecclesiastical History","sourceCitation":"Eusebius, Ecclesiastical History","sourceUrl":"https://www.newadvent.org/fathers/250108.htm","locator":"6.39-6.41","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"该材料应作为宗教政策和帝国治理证据，而不是只放在教会史脉络中。迫害范围、执行差异和地方文书证据需要单独标注。","titleZh":"德西乌斯迫害与帝国祭祀忠诚测试","titleEn":"The Decian persecution and imperial tests of sacrificial loyalty","factBrief":"优西比乌把德西乌斯时期的迫害作为教会史关键转折；它也反映帝国在危机中通过祭祀和忠诚证明强化秩序。","factBriefEn":"Eusebius treats the Decian persecution as a major turn in church history; it also reflects imperial attempts to enforce loyalty through sacrifice.","peopleCore":["Decius"],"peopleMentioned":[],"places":["Roman Empire","Alexandria","Carthage"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"德西乌斯迫害与帝国祭祀忠诚测试","eventLabelEn":"The Decian persecution and imperial tests of sacrificial loyalty","factType":"source_criticism","confidence":"medium","disputeNote":"优西比乌从基督徒受迫害立场书写，行政层面的全貌需要结合纸草和地方材料。","tags":["persecution","religion","political-structure"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-251-abrittus-decius', 'rome-source-breviarium-ab-urbe-condita-eutropius', NULL, '9.4', 9, 251, 251, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '德西乌斯及其子在对哥特人的战争中失败身亡，说明多瑙河边境压力已经直接威胁皇权稳定。', 'zh-Hans', '战场具体过程和古代作者对责任的判断需谨慎处理。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-251-abrittus-decius","sourceId":"rome-source-breviarium-ab-urbe-condita-eutropius","sourceTitle":"Breviarium ab Urbe Condita","sourceCitation":"Eutropius, Breviarium","sourceUrl":"https://www.tertullian.org/fathers/eutropius_breviarium_2_text.htm","locator":"9.4","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"德西乌斯及其子在对哥特人的战争中失败身亡，说明多瑙河边境压力已经直接威胁皇权稳定。","titleZh":"阿布里图斯战役中德西乌斯阵亡","titleEn":"Decius dies at Abrittus","factBrief":"欧特罗庇乌斯把德西乌斯之死与哥特战争相连；皇帝战死于外敌战场，是三世纪边防危机的重要标志。","factBriefEn":"Eutropius links Decius'' death to the Gothic war; an emperor dying in battle against external enemies became a stark marker of the frontier crisis.","peopleCore":["Decius","Herennius Etruscus"],"peopleMentioned":[],"places":["Abrittus","Lower Danube"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"阿布里图斯战役中德西乌斯阵亡","eventLabelEn":"Decius dies at Abrittus","factType":"military","confidence":"medium","disputeNote":"战场具体过程和古代作者对责任的判断需谨慎处理。","tags":["war","frontier","army"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-260-valerian-captured', 'rome-source-breviarium-ab-urbe-condita-eutropius', NULL, '9.7', 10, 260, 260, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '瓦勒良在东方战争中落入沙普尔一世之手，罗马叙事强调这是帝国前所未有的屈辱。该事件应与萨珊 SKZ 铭文并列展示。', 'zh-Hans', '瓦勒良结局的羞辱性细节在拉克坦修等基督教作者处更强烈，需与萨珊铭文分层展示。', 'high', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-260-valerian-captured","sourceId":"rome-source-breviarium-ab-urbe-condita-eutropius","sourceTitle":"Breviarium ab Urbe Condita","sourceCitation":"Eutropius, Breviarium","sourceUrl":"https://www.tertullian.org/fathers/eutropius_breviarium_2_text.htm","locator":"9.7","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"瓦勒良在东方战争中落入沙普尔一世之手，罗马叙事强调这是帝国前所未有的屈辱。该事件应与萨珊 SKZ 铭文并列展示。","titleZh":"瓦勒良被沙普尔一世俘虏","titleEn":"Valerian is captured by Shapur I","factBrief":"欧特罗庇乌斯保存了罗马传统中的瓦勒良被俘叙述；这是罗马东部边境威望崩塌和萨珊扩张的核心节点。","factBriefEn":"Eutropius preserves the Roman tradition of Valerian''s capture, a central moment in the collapse of Roman prestige on the eastern frontier.","peopleCore":["Valerian","Shapur I","Gallienus"],"peopleMentioned":[],"places":["Edessa","Mesopotamia","Persia"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"瓦勒良被沙普尔一世俘虏","eventLabelEn":"Valerian is captured by Shapur I","factType":"military","confidence":"high","disputeNote":"瓦勒良结局的羞辱性细节在拉克坦修等基督教作者处更强烈，需与萨珊铭文分层展示。","tags":["war","frontier","sasanian"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-260-odaenathus-counterattack', 'rome-source-historia-nova-zosimus', NULL, '1.39-1.40', 11, 262, 262, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '瓦勒良被俘后，奥登纳图斯攻击波斯军并取得声望，成为罗马东部局势暂时稳定的关键人物。', 'zh-Hans', '佐西穆斯较晚，依赖失传材料；需要与碑铭、钱币和后世叙事互证。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-260-odaenathus-counterattack","sourceId":"rome-source-historia-nova-zosimus","sourceTitle":"Historia Nova","sourceCitation":"Zosimus, Historia Nova","sourceUrl":"https://www.tertullian.org/fathers/zosimus01_book1.htm","locator":"1.39-1.40","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"瓦勒良被俘后，奥登纳图斯攻击波斯军并取得声望，成为罗马东部局势暂时稳定的关键人物。","titleZh":"奥登纳图斯代表罗马反击沙普尔","titleEn":"Odaenathus counterattacks Shapur on Rome''s behalf","factBrief":"佐西穆斯把东方防线的恢复与帕尔米拉统治者奥登纳图斯联系起来，说明罗马在 260 年后依赖地方强人维持东部秩序。","factBriefEn":"Zosimus links the recovery of the eastern frontier to Odaenathus of Palmyra, showing Rome''s dependence on regional strongmen after 260.","peopleCore":["Odaenathus","Shapur I","Gallienus"],"peopleMentioned":[],"places":["Palmyra","Ctesiphon","Syria"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"奥登纳图斯代表罗马反击沙普尔","eventLabelEn":"Odaenathus counterattacks Shapur on Rome''s behalf","factType":"military","confidence":"medium","disputeNote":"佐西穆斯较晚，依赖失传材料；需要与碑铭、钱币和后世叙事互证。","tags":["war","frontier","palmyra"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-268-gallienus-claudius', 'rome-source-historia-nova-zosimus', NULL, '1.40-1.41', 12, 268, 268, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '加里恩努斯在对付奥勒olus一类西方军事竞争者时被杀，克劳狄二世获得皇位并面对哥特压力。', 'zh-Hans', '政变细节多出自较晚传统，具体参与者名单不能过度确定。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-268-gallienus-claudius","sourceId":"rome-source-historia-nova-zosimus","sourceTitle":"Historia Nova","sourceCitation":"Zosimus, Historia Nova","sourceUrl":"https://www.tertullian.org/fathers/zosimus01_book1.htm","locator":"1.40-1.41","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"加里恩努斯在对付奥勒olus一类西方军事竞争者时被杀，克劳狄二世获得皇位并面对哥特压力。","titleZh":"加里恩努斯遇害，克劳狄二世上台","titleEn":"Gallienus is killed and Claudius II takes power","factBrief":"佐西穆斯记述加里恩努斯在意大利战局中遇害，克劳狄二世继位；这连接了分裂帝国、米兰战局和后续哥特战争。","factBriefEn":"Zosimus records Gallienus'' murder during the Italian campaign and Claudius II''s accession, linking the fragmented empire to the Gothic war that followed.","peopleCore":["Gallienus","Claudius II Gothicus","Aureolus"],"peopleMentioned":[],"places":["Milan","Italy"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"加里恩努斯遇害，克劳狄二世上台","eventLabelEn":"Gallienus is killed and Claudius II takes power","factType":"military","confidence":"medium","disputeNote":"政变细节多出自较晚传统，具体参与者名单不能过度确定。","tags":["succession","assassination","army"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-269-claudius-goths', 'rome-source-breviarium-ab-urbe-condita-eutropius', NULL, '9.11', 13, 269, 269, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '克劳狄因击败哥特人而获得 Gothicus 之名；该事件应与后续奥勒良在多瑙河和东方的重建放在同一恢复脉络中。', 'zh-Hans', '战役地点和战斗规模在传统中有差异；标题可用概括，不宜写死所有战术细节。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-269-claudius-goths","sourceId":"rome-source-breviarium-ab-urbe-condita-eutropius","sourceTitle":"Breviarium ab Urbe Condita","sourceCitation":"Eutropius, Breviarium","sourceUrl":"https://www.tertullian.org/fathers/eutropius_breviarium_2_text.htm","locator":"9.11","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"克劳狄因击败哥特人而获得 Gothicus 之名；该事件应与后续奥勒良在多瑙河和东方的重建放在同一恢复脉络中。","titleZh":"克劳狄二世击败哥特人","titleEn":"Claudius II defeats the Goths","factBrief":"欧特罗庇乌斯把克劳狄二世的声望与对哥特人的胜利相连，这是三世纪危机中多瑙河防线恢复的关键节点。","factBriefEn":"Eutropius connects Claudius II''s prestige to his victory over the Goths, an important marker in the partial recovery of the Danubian frontier.","peopleCore":["Claudius II Gothicus"],"peopleMentioned":[],"places":["Naissus","Balkans","Lower Danube"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"克劳狄二世击败哥特人","eventLabelEn":"Claudius II defeats the Goths","factType":"military","confidence":"medium","disputeNote":"战役地点和战斗规模在传统中有差异；标题可用概括，不宜写死所有战术细节。","tags":["war","frontier","army"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-272-aurelian-palmyra', 'rome-source-historia-augusta-scriptores-historiae-augustae', NULL, 'Aurelian 24-30', 14, 272, 272, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '奥勒良东征击败芝诺比娅，恢复叙利亚、埃及等东部地区。资料卡需要并列佐西穆斯，以免过度依赖《罗马帝王传》。', 'zh-Hans', '《罗马帝王传》包含可疑书信和修辞桥段；事件主线可信度高于叙事细节。', 'low', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-272-aurelian-palmyra","sourceId":"rome-source-historia-augusta-scriptores-historiae-augustae","sourceTitle":"Historia Augusta","sourceCitation":"Historia Augusta","sourceUrl":"https://penelope.uchicago.edu/Thayer/E/Roman/Texts/Historia_Augusta/home.html","locator":"Aurelian 24-30","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"奥勒良东征击败芝诺比娅，恢复叙利亚、埃及等东部地区。资料卡需要并列佐西穆斯，以免过度依赖《罗马帝王传》。","titleZh":"奥勒良击败芝诺比娅并恢复东方","titleEn":"Aurelian defeats Zenobia and recovers the East","factBrief":"《罗马帝王传》奥勒良传详述安条克、埃梅萨与帕尔米拉战事，但该书晚出且文学性强，应作为低可信度叙事证据使用。","factBriefEn":"The Historia Augusta gives a detailed narrative of Antioch, Emesa, and Palmyra, but it is late and literary, so it should be used as low-confidence narrative evidence.","peopleCore":["Aurelian","Zenobia","Zabdas"],"peopleMentioned":[],"places":["Antioch","Emesa","Palmyra","Egypt"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"奥勒良击败芝诺比娅并恢复东方","eventLabelEn":"Aurelian defeats Zenobia and recovers the East","factType":"military","confidence":"low","disputeNote":"《罗马帝王传》包含可疑书信和修辞桥段；事件主线可信度高于叙事细节。","tags":["war","palmyra","frontier"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-272-zosimus-palmyra', 'rome-source-historia-nova-zosimus', NULL, '1.50-1.61', 15, 272, 272, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '佐西穆斯强调帕尔米拉在供应耗尽后寻求波斯援助，芝诺比娅在幼发拉底河附近被捕；这应作为帕尔米拉事件的平行证据。', 'zh-Hans', '佐西穆斯年代较晚，但可能保存德克西普斯等失传材料；仍需标注来源层级。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-272-zosimus-palmyra","sourceId":"rome-source-historia-nova-zosimus","sourceTitle":"Historia Nova","sourceCitation":"Zosimus, Historia Nova","sourceUrl":"https://www.tertullian.org/fathers/zosimus01_book1.htm","locator":"1.50-1.61","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"佐西穆斯强调帕尔米拉在供应耗尽后寻求波斯援助，芝诺比娅在幼发拉底河附近被捕；这应作为帕尔米拉事件的平行证据。","titleZh":"佐西穆斯版本的帕尔米拉战争","titleEn":"Zosimus'' version of the Palmyrene war","factBrief":"佐西穆斯提供另一套奥勒良对帕尔米拉和芝诺比娅的叙述，可用于校正《罗马帝王传》的文学化细节。","factBriefEn":"Zosimus provides another account of Aurelian''s war against Palmyra and Zenobia, useful for checking the more literary Historia Augusta.","peopleCore":["Aurelian","Zenobia"],"peopleMentioned":[],"places":["Palmyra","Euphrates","Syria"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"佐西穆斯版本的帕尔米拉战争","eventLabelEn":"Zosimus'' version of the Palmyrene war","factType":"military","confidence":"medium","disputeNote":"佐西穆斯年代较晚，但可能保存德克西普斯等失传材料；仍需标注来源层级。","tags":["war","palmyra","source"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-274-aurelian-triumph-reunification', 'rome-source-historia-augusta-scriptores-historiae-augustae', NULL, 'Aurelian 32-34', 16, 274, 274, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '资料卡应把 274 年凯旋和帕尔米拉帝国、高卢帝国的终结相连，用于解释奥勒良为何被称为“世界复原者”式人物。', 'zh-Hans', '凯旋细节包含强烈文学装饰，但“东西恢复”的政治意义可由多源互证。', 'low', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-274-aurelian-triumph-reunification","sourceId":"rome-source-historia-augusta-scriptores-historiae-augustae","sourceTitle":"Historia Augusta","sourceCitation":"Historia Augusta","sourceUrl":"https://penelope.uchicago.edu/Thayer/E/Roman/Texts/Historia_Augusta/home.html","locator":"Aurelian 32-34","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"资料卡应把 274 年凯旋和帕尔米拉帝国、高卢帝国的终结相连，用于解释奥勒良为何被称为“世界复原者”式人物。","titleZh":"奥勒良凯旋象征东西两端重新归入罗马","titleEn":"Aurelian''s triumph symbolizes the recovery of East and West","factBrief":"《罗马帝王传》把奥勒良凯旋写成芝诺比娅和泰特里库斯同时被展示的场景，适合作为“帝国重合一”的象征性证据。","factBriefEn":"The Historia Augusta frames Aurelian''s triumph with Zenobia and Tetricus as visible symbols of the recovery of East and West.","peopleCore":["Aurelian","Zenobia","Tetricus"],"peopleMentioned":[],"places":["Rome","Gaul","Palmyra"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"奥勒良凯旋象征东西两端重新归入罗马","eventLabelEn":"Aurelian''s triumph symbolizes the recovery of East and West","factType":"political_structure","confidence":"low","disputeNote":"凯旋细节包含强烈文学装饰，但“东西恢复”的政治意义可由多源互证。","tags":["political-structure","reunification","triumph"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-276-probus-frontiers', 'rome-source-breviarium-ab-urbe-condita-eutropius', NULL, '9.17', 17, 276, 276, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '普罗布斯时期应放在奥勒良重建与戴克里先制度改革之间，作为军事恢复仍依赖皇帝个人军功的过渡阶段。', 'zh-Hans', '欧特罗庇乌斯偏摘要，具体战役和移民政策需要其他材料补证。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-276-probus-frontiers","sourceId":"rome-source-breviarium-ab-urbe-condita-eutropius","sourceTitle":"Breviarium ab Urbe Condita","sourceCitation":"Eutropius, Breviarium","sourceUrl":"https://www.tertullian.org/fathers/eutropius_breviarium_2_text.htm","locator":"9.17","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"普罗布斯时期应放在奥勒良重建与戴克里先制度改革之间，作为军事恢复仍依赖皇帝个人军功的过渡阶段。","titleZh":"普罗布斯与三世纪后期边防恢复","titleEn":"Probus and the late third-century recovery of the frontiers","factBrief":"欧特罗庇乌斯把普罗布斯描写为能战且恢复边防秩序的皇帝，可作为奥勒良之后帝国继续修复的年表证据。","factBriefEn":"Eutropius presents Probus as a capable military emperor who restored frontier order, extending the recovery after Aurelian.","peopleCore":["Probus"],"peopleMentioned":[],"places":["Rhine frontier","Danube frontier"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"普罗布斯与三世纪后期边防恢复","eventLabelEn":"Probus and the late third-century recovery of the frontiers","factType":"military","confidence":"medium","disputeNote":"欧特罗庇乌斯偏摘要，具体战役和移民政策需要其他材料补证。","tags":["war","frontier","army"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-284-diocletian-accession', 'rome-source-breviarium-ab-urbe-condita-eutropius', NULL, '9.20-9.21', 18, 284, 284, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '戴克里先即位不是“四帝共治”本身，而是其后制度改革的起点；时间线应区分 284 即位、286 双帝、293 四帝。', 'zh-Hans', '古代摘要对努梅里安之死和戴克里先责任的处理不同，需保留争议说明。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-284-diocletian-accession","sourceId":"rome-source-breviarium-ab-urbe-condita-eutropius","sourceTitle":"Breviarium ab Urbe Condita","sourceCitation":"Eutropius, Breviarium","sourceUrl":"https://www.tertullian.org/fathers/eutropius_breviarium_2_text.htm","locator":"9.20-9.21","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"戴克里先即位不是“四帝共治”本身，而是其后制度改革的起点；时间线应区分 284 即位、286 双帝、293 四帝。","titleZh":"戴克里先即位并结束军人皇帝快速更替阶段","titleEn":"Diocletian''s accession closes the rapid soldier-emperor phase","factBrief":"欧特罗庇乌斯记录卡鲁斯、努梅里安、卡里努斯之后戴克里先上台；该节点应作为 284 年制度重建前的政权转换入口。","factBriefEn":"Eutropius records Diocletian''s rise after Carus, Numerian, and Carinus, making 284 the entry point to institutional reconstruction.","peopleCore":["Diocletian","Numerian","Carinus","Carus"],"peopleMentioned":[],"places":["Nicomedia","Roman Empire"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"戴克里先即位并结束军人皇帝快速更替阶段","eventLabelEn":"Diocletian''s accession closes the rapid soldier-emperor phase","factType":"military","confidence":"medium","disputeNote":"古代摘要对努梅里安之死和戴克里先责任的处理不同，需保留争议说明。","tags":["succession","army","political-structure"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-293-tetrarchy', 'rome-source-de-mortibus-persecutorum-lactantius', NULL, '7-8', 19, 293, 293, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '四帝共治应标为 293 年形成：两位奥古斯都配两位凯撒，用分区统治和继承安排回应边境、内战和行政压力。', 'zh-Hans', '拉克坦修敌视迫害者，政治动机解释偏负面；制度事实应与铭文、钱币、法令互证。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-293-tetrarchy","sourceId":"rome-source-de-mortibus-persecutorum-lactantius","sourceTitle":"De Mortibus Persecutorum","sourceCitation":"Lactantius, De Mortibus Persecutorum","sourceUrl":"https://www.newadvent.org/fathers/0705.htm","locator":"7-8","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"四帝共治应标为 293 年形成：两位奥古斯都配两位凯撒，用分区统治和继承安排回应边境、内战和行政压力。","titleZh":"四帝共治的形成","titleEn":"Formation of the Tetrarchy","factBrief":"拉克坦修从批判立场描述戴克里先、马克西米安、伽列里乌斯和君士坦提乌斯的权力安排；这可作为四帝共治的古代叙事证据。","factBriefEn":"Lactantius describes the arrangement among Diocletian, Maximian, Galerius, and Constantius from a hostile Christian perspective, but it remains key narrative evidence for tetrarchic rule.","peopleCore":["Diocletian","Maximian","Galerius","Constantius Chlorus"],"peopleMentioned":[],"places":["Nicomedia","Milan","Trier","Sirmium"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"四帝共治的形成","eventLabelEn":"Formation of the Tetrarchy","factType":"succession","confidence":"medium","disputeNote":"拉克坦修敌视迫害者，政治动机解释偏负面；制度事实应与铭文、钱币、法令互证。","tags":["political-structure","succession","tetrarchy"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-303-great-persecution', 'rome-source-ecclesiastical-history-eusebius', NULL, '8.2-8.6', 20, 303, 303, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '大迫害不应只作为宗教史事件，也应放入四帝共治末期的中央命令、地方执行和帝国忠诚政治中。', 'zh-Hans', '优西比乌是当事时代基督徒作者，受害叙事可靠性高，但行政全貌需补法令和地方证据。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-303-great-persecution","sourceId":"rome-source-ecclesiastical-history-eusebius","sourceTitle":"Ecclesiastical History","sourceCitation":"Eusebius, Ecclesiastical History","sourceUrl":"https://www.newadvent.org/fathers/250108.htm","locator":"8.2-8.6","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"大迫害不应只作为宗教史事件，也应放入四帝共治末期的中央命令、地方执行和帝国忠诚政治中。","titleZh":"大迫害开始","titleEn":"The Great Persecution begins","factBrief":"优西比乌第八卷直接叙述戴克里先迫害时期的教会遭遇，是 303 年以后宗教政策和帝国治理的重要古代证据。","factBriefEn":"Book 8 of Eusebius directly narrates the church under Diocletian''s persecution, making it central evidence for religious policy after 303.","peopleCore":["Diocletian","Galerius","Eusebius of Caesarea"],"peopleMentioned":[],"places":["Nicomedia","Roman Empire","Palestine"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"大迫害开始","eventLabelEn":"The Great Persecution begins","factType":"source_criticism","confidence":"medium","disputeNote":"优西比乌是当事时代基督徒作者，受害叙事可靠性高，但行政全貌需补法令和地方证据。","tags":["persecution","religion","political-structure"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-305-abdication', 'rome-source-de-mortibus-persecutorum-lactantius', NULL, '18-19', 21, 305, 305, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '退位后伽列里乌斯和君士坦提乌斯升为奥古斯都，塞维鲁和马克西米努斯·达扎成为凯撒；君士坦丁和马克森提乌斯被排除在正式安排之外。', 'zh-Hans', '拉克坦修特别强调伽列里乌斯操控继承，需标明其敌对立场。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-305-abdication","sourceId":"rome-source-de-mortibus-persecutorum-lactantius","sourceTitle":"De Mortibus Persecutorum","sourceCitation":"Lactantius, De Mortibus Persecutorum","sourceUrl":"https://www.newadvent.org/fathers/0705.htm","locator":"18-19","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"退位后伽列里乌斯和君士坦提乌斯升为奥古斯都，塞维鲁和马克西米努斯·达扎成为凯撒；君士坦丁和马克森提乌斯被排除在正式安排之外。","titleZh":"戴克里先与马克西米安退位","titleEn":"Diocletian and Maximian abdicate","factBrief":"拉克坦修记述 305 年两位奥古斯都退位及继承安排，说明四帝共治制度真正接受压力测试的时刻到来。","factBriefEn":"Lactantius records the abdication of the two Augusti in 305 and the succession arrangement, the first major stress test of the Tetrarchic system.","peopleCore":["Diocletian","Maximian","Galerius","Constantius Chlorus","Severus II","Maximinus Daia","Constantine","Maxentius"],"peopleMentioned":[],"places":["Nicomedia","Milan","Roman Empire"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"戴克里先与马克西米安退位","eventLabelEn":"Diocletian and Maximian abdicate","factType":"succession","confidence":"medium","disputeNote":"拉克坦修特别强调伽列里乌斯操控继承，需标明其敌对立场。","tags":["succession","tetrarchy","political-structure"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-218-elagabalus-accession', 'rome-source-history-of-the-empire-after-marcus-herodian', NULL, '5.3-5.4', 22, 218, 218, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '尤利娅·玛伊萨利用塞维鲁家族记忆和军队赏赐，推动埃拉伽巴路斯在东方被拥立，马克里努斯最终败亡。', 'zh-Hans', '赫罗狄安对东方宫廷和宗教习俗的描写带有罗马化偏见，政治主线可信度高于风俗细节。', 'high', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-218-elagabalus-accession","sourceId":"rome-source-history-of-the-empire-after-marcus-herodian","sourceTitle":"History of the Empire after Marcus","sourceCitation":"Herodian, History of the Empire","sourceUrl":"https://www.tertullian.org/fathers/herodian_01_book1.htm","locator":"5.3-5.4","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"尤利娅·玛伊萨利用塞维鲁家族记忆和军队赏赐，推动埃拉伽巴路斯在东方被拥立，马克里努斯最终败亡。","titleZh":"埃拉伽巴路斯在叙利亚军队支持下取代马克里努斯","titleEn":"Elagabalus replaces Macrinus with Syrian army support","factBrief":"赫罗狄安把埃拉伽巴路斯的上台放在塞维鲁女性亲族、叙利亚军团和马克里努斯合法性危机的交点上。","factBriefEn":"Herodian places Elagabalus'' rise at the intersection of Severan women, the Syrian legions, and Macrinus'' weak legitimacy.","peopleCore":["Elagabalus","Macrinus","Julia Maesa","Julia Soaemias"],"peopleMentioned":[],"places":["Emesa","Syria","Antioch"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"埃拉伽巴路斯在叙利亚军队支持下取代马克里努斯","eventLabelEn":"Elagabalus replaces Macrinus with Syrian army support","factType":"military","confidence":"high","disputeNote":"赫罗狄安对东方宫廷和宗教习俗的描写带有罗马化偏见，政治主线可信度高于风俗细节。","tags":["succession","army","dynasty"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-222-alexander-severus-accession', 'rome-source-history-of-the-empire-after-marcus-herodian', NULL, '5.8', 23, 222, 222, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '埃拉伽巴路斯与其母被杀后，亚历山大·塞维鲁成为皇帝，尤利娅·玛迈亚在早期统治中具有关键影响。', 'zh-Hans', '禁卫军参与细节和宫廷冲突经过具有文学化叙事痕迹。', 'high', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-222-alexander-severus-accession","sourceId":"rome-source-history-of-the-empire-after-marcus-herodian","sourceTitle":"History of the Empire after Marcus","sourceCitation":"Herodian, History of the Empire","sourceUrl":"https://www.tertullian.org/fathers/herodian_01_book1.htm","locator":"5.8","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"埃拉伽巴路斯与其母被杀后，亚历山大·塞维鲁成为皇帝，尤利娅·玛迈亚在早期统治中具有关键影响。","titleZh":"亚历山大·塞维鲁取代埃拉伽巴路斯","titleEn":"Alexander Severus replaces Elagabalus","factBrief":"赫罗狄安叙述禁卫军和塞维鲁女性亲族如何抛弃埃拉伽巴路斯，扶立亚历山大·塞维鲁。","factBriefEn":"Herodian describes how the Praetorians and Severan women abandoned Elagabalus and elevated Alexander Severus.","peopleCore":["Alexander Severus","Elagabalus","Julia Mamaea","Julia Maesa"],"peopleMentioned":[],"places":["Rome"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"亚历山大·塞维鲁取代埃拉伽巴路斯","eventLabelEn":"Alexander Severus replaces Elagabalus","factType":"succession","confidence":"high","disputeNote":"禁卫军参与细节和宫廷冲突经过具有文学化叙事痕迹。","tags":["succession","assassination","dynasty"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-231-alexander-persian-war', 'rome-source-history-of-the-empire-after-marcus-herodian', NULL, '6.2-6.6', 24, 231, 231, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '阿尔达希尔对罗马东方边界提出压力后，亚历山大组织远征，但战果和叙事评价复杂，随后他又被莱茵前线危机牵制。', 'zh-Hans', '赫罗狄安对战役成败叙述不够清晰，需与萨珊和后世罗马材料互证。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-231-alexander-persian-war","sourceId":"rome-source-history-of-the-empire-after-marcus-herodian","sourceTitle":"History of the Empire after Marcus","sourceCitation":"Herodian, History of the Empire","sourceUrl":"https://www.tertullian.org/fathers/herodian_01_book1.htm","locator":"6.2-6.6","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"阿尔达希尔对罗马东方边界提出压力后，亚历山大组织远征，但战果和叙事评价复杂，随后他又被莱茵前线危机牵制。","titleZh":"亚历山大·塞维鲁对阿尔达希尔一世的东方战争","titleEn":"Alexander Severus'' eastern war against Ardashir I","factBrief":"赫罗狄安将亚历山大·塞维鲁的东方战争作为新兴萨珊压力进入罗马政治中心的关键证据。","factBriefEn":"Herodian makes Alexander Severus'' eastern campaign key evidence for the rise of Sasanian pressure in Roman politics.","peopleCore":["Alexander Severus","Ardashir I","Julia Mamaea"],"peopleMentioned":[],"places":["Mesopotamia","Syria","Antioch"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"亚历山大·塞维鲁对阿尔达希尔一世的东方战争","eventLabelEn":"Alexander Severus'' eastern war against Ardashir I","factType":"military","confidence":"medium","disputeNote":"赫罗狄安对战役成败叙述不够清晰，需与萨珊和后世罗马材料互证。","tags":["war","frontier","sasanian"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-244-gordian-philip-transition', 'rome-source-breviarium-ab-urbe-condita-eutropius', NULL, '9.2-9.3', 25, 244, 244, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '戈尔迪安三世在东方战争中死亡，腓力继位并与波斯议和。罗马和萨珊关于死因的叙事存在明显张力。', 'zh-Hans', '戈尔迪安三世究竟战死、病死还是被腓力谋害，古代材料分歧明显。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-244-gordian-philip-transition","sourceId":"rome-source-breviarium-ab-urbe-condita-eutropius","sourceTitle":"Breviarium ab Urbe Condita","sourceCitation":"Eutropius, Breviarium","sourceUrl":"https://www.tertullian.org/fathers/eutropius_breviarium_2_text.htm","locator":"9.2-9.3","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"戈尔迪安三世在东方战争中死亡，腓力继位并与波斯议和。罗马和萨珊关于死因的叙事存在明显张力。","titleZh":"戈尔迪安三世死后腓力阿拉伯人即位","titleEn":"Philip the Arab succeeds after Gordian III''s death","factBrief":"欧特罗庇乌斯提供罗马摘要传统中的 244 年皇权转移节点，可与沙普尔铭文的 Misiche 叙事对读。","factBriefEn":"Eutropius provides the Roman epitome tradition for the 244 succession, to be read against Shapur''s Misiche narrative.","peopleCore":["Gordian III","Philip the Arab","Shapur I","Timesitheus"],"peopleMentioned":[],"places":["Mesopotamia","Persia"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"戈尔迪安三世死后腓力阿拉伯人即位","eventLabelEn":"Philip the Arab succeeds after Gordian III''s death","factType":"military","confidence":"medium","disputeNote":"戈尔迪安三世究竟战死、病死还是被腓力谋害，古代材料分歧明显。","tags":["succession","war","sasanian"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-257-valerian-persecution', 'rome-source-ecclesiastical-history-eusebius', NULL, '7.10-7.11', 26, 257, 257, 'Paraphrased evidence note; no verbatim Greek excerpt stored.', '瓦勒良早期政策并非始终迫害，但 257-258 年转向压迫教会领袖和集会，成为拉克坦修叙事中的重要背景。', 'zh-Hans', '教会史资料对受害经历保存较多，但行政命令细节仍需与其他材料分开标注。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-257-valerian-persecution","sourceId":"rome-source-ecclesiastical-history-eusebius","sourceTitle":"Ecclesiastical History","sourceCitation":"Eusebius, Ecclesiastical History","sourceUrl":"https://www.newadvent.org/fathers/250108.htm","locator":"7.10-7.11","originalText":"Paraphrased evidence note; no verbatim Greek excerpt stored.","originalTextMissing":true,"translation":"瓦勒良早期政策并非始终迫害，但 257-258 年转向压迫教会领袖和集会，成为拉克坦修叙事中的重要背景。","titleZh":"瓦勒良迫害与教会领袖受压","titleEn":"Valerian''s persecution pressures church leaders","factBrief":"优西比乌保存瓦勒良迫害基督徒的教会史叙事，是理解瓦勒良被俘后基督教作者如何解释其命运的前提。","factBriefEn":"Eusebius preserves the church-historical narrative of Valerian''s persecution, explaining why later Christian authors framed his capture as divine punishment.","peopleCore":["Valerian","Gallienus","Eusebius of Caesarea"],"peopleMentioned":[],"places":["Roman Empire","Carthage","Rome"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"瓦勒良迫害与教会领袖受压","eventLabelEn":"Valerian''s persecution pressures church leaders","factType":"source_criticism","confidence":"medium","disputeNote":"教会史资料对受害经历保存较多，但行政命令细节仍需与其他材料分开标注。","tags":["persecution","religion","source"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-260-postumus-gallic-empire', 'rome-source-de-caesaribus-aurelius-victor', NULL, '33', 27, 260, 260, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '瓦勒良被俘和边境危机背景下，波斯图穆斯控制高卢、不列颠和西班牙方向，形成所谓高卢帝国。', 'zh-Hans', '高卢帝国的独立程度与合法性表达需要结合钱币、铭文和地方行政材料。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-260-postumus-gallic-empire","sourceId":"rome-source-de-caesaribus-aurelius-victor","sourceTitle":"De Caesaribus","sourceCitation":"Aurelius Victor, De Caesaribus","sourceUrl":"https://topostext.org/work/745","locator":"33","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"瓦勒良被俘和边境危机背景下，波斯图穆斯控制高卢、不列颠和西班牙方向，形成所谓高卢帝国。","titleZh":"波斯图穆斯在高卢自立","titleEn":"Postumus establishes a breakaway Gallic regime","factBrief":"奥勒留·维克托的摘要传统把波斯图穆斯统治高卢约十年作为加里恩努斯时代帝国分裂的重要证据。","factBriefEn":"Aurelius Victor''s epitome tradition treats Postumus'' rule in Gaul for about ten years as evidence of imperial fragmentation under Gallienus.","peopleCore":["Postumus","Gallienus","Valerian"],"peopleMentioned":[],"places":["Gaul","Britannia","Hispania","Cologne"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"波斯图穆斯在高卢自立","eventLabelEn":"Postumus establishes a breakaway Gallic regime","factType":"military","confidence":"medium","disputeNote":"高卢帝国的独立程度与合法性表达需要结合钱币、铭文和地方行政材料。","tags":["usurpation","frontier","political-structure"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-286-carausius-britain', 'rome-source-breviarium-ab-urbe-condita-eutropius', NULL, '9.21', 28, 286, 286, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '卡劳修斯因海防和战利品问题与中央冲突，在不列颠建立割据政权，直到君士坦提乌斯系统收复。', 'zh-Hans', '卡劳修斯的政治宣传和实际控制范围应结合钱币证据细化。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-286-carausius-britain","sourceId":"rome-source-breviarium-ab-urbe-condita-eutropius","sourceTitle":"Breviarium ab Urbe Condita","sourceCitation":"Eutropius, Breviarium","sourceUrl":"https://www.tertullian.org/fathers/eutropius_breviarium_2_text.htm","locator":"9.21","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"卡劳修斯因海防和战利品问题与中央冲突，在不列颠建立割据政权，直到君士坦提乌斯系统收复。","titleZh":"卡劳修斯割据不列颠","titleEn":"Carausius secedes in Britain","factBrief":"欧特罗庇乌斯简要记录卡劳修斯在不列颠割据，为理解四帝共治西部海防压力提供年表证据。","factBriefEn":"Eutropius briefly records Carausius'' secession in Britain, key chronological evidence for western naval pressure under the Tetrarchy.","peopleCore":["Carausius","Maximian","Constantius Chlorus"],"peopleMentioned":[],"places":["Britannia","Gaul","English Channel"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"卡劳修斯割据不列颠","eventLabelEn":"Carausius secedes in Britain","factType":"military","confidence":"medium","disputeNote":"卡劳修斯的政治宣传和实际控制范围应结合钱币证据细化。","tags":["usurpation","frontier","tetrarchy"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-296-constantius-recovers-britain', 'rome-source-breviarium-ab-urbe-condita-eutropius', NULL, '9.22', 29, 296, 296, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '卡劳修斯死后阿莱克图斯继续割据，君士坦提乌斯在西部凯撒任内完成收复，增强四帝共治合法性。', 'zh-Hans', '具体登陆路线、战场和伦敦解救叙事需补颂辞等材料。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-296-constantius-recovers-britain","sourceId":"rome-source-breviarium-ab-urbe-condita-eutropius","sourceTitle":"Breviarium ab Urbe Condita","sourceCitation":"Eutropius, Breviarium","sourceUrl":"https://www.tertullian.org/fathers/eutropius_breviarium_2_text.htm","locator":"9.22","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"卡劳修斯死后阿莱克图斯继续割据，君士坦提乌斯在西部凯撒任内完成收复，增强四帝共治合法性。","titleZh":"君士坦提乌斯收复不列颠","titleEn":"Constantius recovers Britain","factBrief":"欧特罗庇乌斯把君士坦提乌斯击败阿莱克图斯、收复不列颠作为四帝共治军事成效的代表事件。","factBriefEn":"Eutropius presents Constantius'' defeat of Allectus and recovery of Britain as a major tetrarchic military success.","peopleCore":["Constantius Chlorus","Allectus","Carausius"],"peopleMentioned":[],"places":["Britannia","Londinium","Gaul"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"君士坦提乌斯收复不列颠","eventLabelEn":"Constantius recovers Britain","factType":"military","confidence":"medium","disputeNote":"具体登陆路线、战场和伦敦解救叙事需补颂辞等材料。","tags":["war","frontier","tetrarchy"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-298-nisibis-treaty', 'rome-source-breviarium-ab-urbe-condita-eutropius', NULL, '9.24-9.25', 30, 298, 298, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '伽列里乌斯初败后反攻成功，纳尔塞赫家属被俘，罗马取得有利条款，尼西比斯成为长期贸易和外交节点。', 'zh-Hans', '条约条款的完整形式主要依赖后世整理，需与彼得罗加尔和其他晚期材料互证。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-298-nisibis-treaty","sourceId":"rome-source-breviarium-ab-urbe-condita-eutropius","sourceTitle":"Breviarium ab Urbe Condita","sourceCitation":"Eutropius, Breviarium","sourceUrl":"https://www.tertullian.org/fathers/eutropius_breviarium_2_text.htm","locator":"9.24-9.25","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"伽列里乌斯初败后反攻成功，纳尔塞赫家属被俘，罗马取得有利条款，尼西比斯成为长期贸易和外交节点。","titleZh":"伽列里乌斯击败纳尔塞赫并形成尼西比斯体系","titleEn":"Galerius defeats Narseh and shapes the Nisibis settlement","factBrief":"欧特罗庇乌斯记录伽列里乌斯对波斯的胜利，可作为 298 年罗马-萨珊边界重整的罗马摘要证据。","factBriefEn":"Eutropius records Galerius'' victory over Persia, providing Roman epitome evidence for the frontier settlement around 298.","peopleCore":["Galerius","Diocletian","Narseh"],"peopleMentioned":[],"places":["Nisibis","Armenia","Mesopotamia"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"伽列里乌斯击败纳尔塞赫并形成尼西比斯体系","eventLabelEn":"Galerius defeats Narseh and shapes the Nisibis settlement","factType":"military","confidence":"medium","disputeNote":"条约条款的完整形式主要依赖后世整理，需与彼得罗加尔和其他晚期材料互证。","tags":["war","frontier","sasanian","tetrarchy"],"reviewStatus":"reviewed"}');
INSERT INTO "source_passages" ("id", "source_id", "parent_passage_id", "locator", "sequence", "year_start", "year_end", "text", "translation", "language", "notes", "confidence", "review_status", "raw_json") VALUES ('rome-ancient-passage:rome-306-constantine-maxentius', 'rome-source-de-mortibus-persecutorum-lactantius', NULL, '24-26', 31, 306, 306, 'Paraphrased evidence note; no verbatim Latin excerpt stored.', '君士坦提乌斯死后，君士坦丁被拥立；不久马克森提乌斯也在罗马取得权力。305 年的继承安排迅速失效。', 'zh-Hans', '拉克坦修亲君士坦丁，需把事件事实和政治评价拆开。', 'medium', 'reviewed', '{"importedFromBatch":"manual-rome-ancient-190-310","cardId":"rome-306-constantine-maxentius","sourceId":"rome-source-de-mortibus-persecutorum-lactantius","sourceTitle":"De Mortibus Persecutorum","sourceCitation":"Lactantius, De Mortibus Persecutorum","sourceUrl":"https://www.newadvent.org/fathers/0705.htm","locator":"24-26","originalText":"Paraphrased evidence note; no verbatim Latin excerpt stored.","originalTextMissing":true,"translation":"君士坦提乌斯死后，君士坦丁被拥立；不久马克森提乌斯也在罗马取得权力。305 年的继承安排迅速失效。","titleZh":"君士坦丁和马克森提乌斯进入四帝共治继承危机","titleEn":"Constantine and Maxentius enter the Tetrarchic succession crisis","factBrief":"拉克坦修把 306 年后的继承危机写成四帝共治安排崩解的开始：君士坦丁被军队拥立，马克森提乌斯在罗马起事。","factBriefEn":"Lactantius frames the post-306 succession crisis as the breakdown of tetrarchic design: Constantine is raised by the army and Maxentius rises in Rome.","peopleCore":["Constantine","Maxentius","Constantius Chlorus","Galerius"],"peopleMentioned":[],"places":["Eboracum","Rome","Britannia"],"macroEvent":"Roman Empire 190-310 ancient-source knowledge","eventLabel":"君士坦丁和马克森提乌斯进入四帝共治继承危机","eventLabelEn":"Constantine and Maxentius enter the Tetrarchic succession crisis","factType":"succession","confidence":"medium","disputeNote":"拉克坦修亲君士坦丁，需把事件事实和政治评价拆开。","tags":["succession","tetrarchy","usurpation"],"reviewStatus":"reviewed"}');

