INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('zhang-jiao', 'zh', '张角', NULL, '?-184', '太平道 / 黄巾军', '太平道领袖，发动黄巾起义，成为东汉末年地方军事化和群雄割据的起点之一。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('dong-zhuo', 'zh', '董卓', '仲颖', '?-192', '东汉朝廷 / 凉州军', '凉州军阀，189 年入洛阳控制朝廷，废立皇帝并迁都长安，引发关东诸军讨伐。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('han-xiandi', 'zh', '汉献帝', NULL, '181-234', '东汉', '东汉末代皇帝，先后受董卓、李傕郭汜、曹操集团控制，220 年禅位于曹丕。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('yuan-shao', 'zh', '袁绍', '本初', '?-202', '袁绍集团', '汝南袁氏出身，控制河北四州，是官渡之战前北方最强势力之一。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('yan-liang', 'zh', '颜良', NULL, '?-200', '袁绍集团', '袁绍麾下大将，200 年进攻白马时被关羽斩杀。其列入“河北四庭柱”属于后世通俗归类，不是汉末正式称号。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('wen-chou', 'zh', '文丑', NULL, '?-200', '袁绍集团', '袁绍麾下名将，官渡前哨战中在延津方向败亡，与颜良常并称为袁绍军中勇将。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('zhang-he', 'zh', '张郃', '儁乂', '?-231', '袁绍集团 / 曹魏', '初属韩馥、袁绍，官渡之战中归降曹操，后成为曹魏重要将领，231 年在木门中箭而卒。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('gao-lan', 'zh', '高览', NULL, '生卒未详', '袁绍集团 / 曹操集团', '袁绍部将，官渡之战中与张郃相关的降曹记载相连；后续仕历不详。其“四庭柱”身份属后世传统归类。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('xu-you', 'zh', '许攸', '子远', '生卒未详', '袁绍集团 / 曹操集团', '袁绍旧友和谋士，官渡相持时投奔曹操，提供袁军粮秣情报，是乌巢转折的重要人物。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('ju-shou', 'zh', '沮授', NULL, '?-200?', '袁绍集团', '袁绍重要谋臣，多次提出稳健策略，官渡失败后被曹操俘获，拒绝归附，结局记载略有不确定。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('tian-feng', 'zh', '田丰', '元皓', '?-200', '袁绍集团', '袁绍谋士，主张审慎用兵并多次进谏，官渡前后被袁绍囚禁，战败后遇害。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('shen-pei', 'zh', '审配', '正南', '?-204', '袁绍集团', '袁绍集团核心僚佐，袁氏内争中守邺，204 年邺城陷落后被杀。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('yuan-shu', 'zh', '袁术', '公路', '?-199', '袁术集团', '控制淮南一带，197 年称帝导致政治孤立，势力迅速瓦解。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('tao-qian', 'zh', '陶谦', '恭祖', '132-194', '徐州陶谦集团', '东汉末年据徐州，曾与曹操发生冲突；临终前徐州转由刘备接掌，是刘备早期获得州级政治基础的关键节点。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('gongsun-zan', 'zh', '公孙瓒', '伯圭', '?-199', '公孙瓒集团', '在幽州、冀北与袁绍长期争夺，199 年败亡后河北格局转向袁绍主导。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('lu-bu', 'zh', '吕布', '奉先', '?-199', '吕布集团', '先后依附董卓、袁绍、刘备等势力，194 年袭取兖州，后据徐州，下邳败亡。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('chen-gong', 'zh', '陈宫', '公台', '?-199', '吕布集团', '初与曹操有交集，后与张邈等迎吕布入兖州，成为吕布集团重要谋士；下邳败亡后被曹操处死。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-cao', 'zh', '曹操', '孟德', '155-220', '曹操集团 / 曹魏', '从讨董、兖州危机中起势，迎汉献帝至许后掌握朝廷名义，击败吕布、袁绍并统一北方，晚年进爵魏公、魏王，奠定曹魏政权基础。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('xun-yu', 'zh', '荀彧', '文若', '163-212', '曹操集团 / 东汉朝廷', '曹操最重要的中枢谋臣之一，参与迎献帝、守许与官渡战略判断，后因魏公问题与曹操产生裂痕。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('xun-you', 'zh', '荀攸', '公达', '157-214', '曹操集团', '曹操军中谋主，参与下邳、白马、官渡等关键战役谋划，以临战计策见长。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('guo-jia', 'zh', '郭嘉', '奉孝', '170-207', '曹操集团', '曹操早期重要谋士，参与对吕布、袁绍及河北后续战事判断，207 年北征乌桓后不久去世。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('jia-xu', 'zh', '贾诩', '文和', '147-223', '凉州军 / 张绣集团 / 曹魏', '先后服务凉州军、张绣和曹操集团，199 年随张绣归曹，后在曹魏中枢以谨慎谋略著称。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('liu-ye', 'zh', '刘晔', '子扬', '?-234', '曹操集团 / 曹魏', '淮南出身的曹魏谋臣，早年在江淮乱局中显名，入曹操幕府后多次参与对汉中、孙权和边境形势的判断。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('jiang-ji', 'zh', '蒋济', '子通', '?-249', '曹魏', '曹魏中后期重臣，早年以合肥疑兵计见称，后长期参与军政奏议，并卷入高平陵前后的朝局转折。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('chen-qun', 'zh', '陈群', '长文', '?-237', '刘备集团 / 曹魏', '颍川名士，早年曾为刘备别驾，后入曹操幕府；曹丕时期创设九品官人法，明帝初与曹真、司马懿等同受遗诏辅政。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('zhong-yao', 'zh', '钟繇', '元常', '151-230', '东汉朝廷 / 曹魏', '曹操集团在关中方向的重要重臣，长期镇抚关中并维系西线秩序；入魏后位至太傅，亦以书法名重后世。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('dong-zhao', 'zh', '董昭', '公仁', '156-236', '袁绍集团 / 张杨集团 / 曹操集团 / 曹魏', '先后服务袁绍、张杨、曹操与曹魏朝廷，在迎献帝、曹操进位魏公、襄樊危机和魏初朝政中多有政治谋划。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('liu-fang', 'zh', '刘放', '子弃', '?-250', '曹操集团 / 曹魏', '曹魏机要文臣，善为书檄诏命，与孙资长期掌管中书机密，对魏明帝以后朝政影响很大。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('sun-zi', 'zh', '孙资', '彦龙', '?-251', '曹操集团 / 曹魏', '曹魏中书重臣，与刘放并掌机要，参与魏明帝时期北边、辽东和朝廷人事判断，后卷入高平陵前后的政治转折。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('liu-yi', 'zh', '刘廙', '恭嗣', '180-221', '荆州刘表集团 / 曹操集团 / 曹魏', '南阳士人，早年与荆州刘表集团相关，后入曹操幕府，因弟事被牵连而获赦，魏初任侍中。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('sima-lang', 'zh', '司马朗', '伯达', '171-217', '曹操集团', '司马懿之兄，早年避乱迁徙，入曹操幕府后以地方治理和宽厚政风见称，建安二十二年军中疫病时去世。', '{}');
