INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('wang-can', 'zh', '王粲', '仲宣', '177-217', '荆州刘表集团 / 曹操集团', '建安七子之一，避乱荆州，刘表死后劝刘琮归曹；入曹操集团后参与魏国制度礼仪，亦以文学才名著称。', '{}');
