INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-pi', 'zh', '曹丕', '子桓', '187-226', '曹魏', '曹操之子，220 年受汉献帝禅让称帝，建立曹魏。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('liu-biao', 'zh', '刘表', '景升', '142-208', '荆州刘表集团', '长期据有荆州，维持长江中游相对稳定，其死后荆州成为曹操、刘备、孙权争夺焦点。', '{}');
