INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('fa-zheng', 'zh', '法正', '孝直', '176-220', '刘璋集团 / 刘备集团', '原属刘璋，后协助刘备入主益州，并在汉中之战中提出关键战略建议，是刘备前期最重要谋臣之一。', '{}');
