INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('liu-zhang', 'zh', '刘璋', '季玉', '?-219', '益州刘璋集团', '继承益州割据格局，后邀请刘备入蜀，214 年向刘备投降。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('zhang-lu', 'zh', '张鲁', '公祺', '?-216', '汉中张鲁集团', '长期控制汉中，215 年降曹操，汉中随后成为曹刘争夺核心区域。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('sun-quan', 'zh', '孙权', '仲谋', '182-252', '孙吴', '孙策死后继承江东基业，依托江东士族与周瑜、鲁肃等臣僚稳固统治；赤壁联合刘备抗曹，后取荆州、守江淮，229 年称帝建立孙吴。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('shi-xie', 'zh', '士燮', '威彦', '137-226', '交州士氏 / 孙吴', '长期控制交州，以贡纳和子弟入质维持对孙权的名义臣属；其死后士氏独立地位削弱，交州逐渐纳入孙吴直接经营。', '{}');
