INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('lu-su', 'zh', '鲁肃', '子敬', '172-217', '孙吴', '主张联刘抗曹，赤壁前后在孙刘关系和荆州安排中作用突出。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('lu-meng', 'zh', '吕蒙', '子明', '178-220', '孙吴', '孙权集团重要将领，继鲁肃后主持荆州方向，219 年袭取荆州导致关羽败亡。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('lu-xun', 'zh', '陆逊', '伯言', '183-245', '孙吴', '参与孙吴袭取荆州，222 年在夷陵之战击败刘备，后为吴国重臣。', '{}');
