INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('sima-yi', 'zh', '司马懿', '仲达', '179-251', '曹魏 / 司马氏', '曹魏后期重臣，多次与诸葛亮对峙，249 年高平陵之变后司马氏控制魏政。', '{}');
