INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('ma-su', 'zh', '马谡', '幼常', '190-228', '蜀汉', '襄阳宜城人，马良之弟，以才器和谈兵受诸葛亮器重；228 年街亭失守后被处置，是蜀汉第一次北伐失败的关键人物。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('sun-ce', 'zh', '孙策', '伯符', '175-200', '孙策集团 / 江东', '孙坚长子，依附袁术后承继父部曲，渡江开拓江东诸郡，200 年遇刺身亡，将基业交给孙权。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cheng-pu', 'zh', '程普', '德谋', '?-?', '孙坚集团 / 孙吴', '右北平土垠人，历事孙坚、孙策、孙权三代，赤壁之战时与周瑜分任左右督，是江东早期宿将。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('li-dian', 'zh', '李典', '曼成', '?-?', '曹操集团 / 曹魏', '山阳钜野人，早年随曹操集团征战，合肥之战中与张辽、乐进协同击破孙权军。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('xiahou-dun', 'zh', '夏侯惇', '元让', '?-220', '曹操集团 / 曹魏', '沛国谯人，早随曹操起兵，长期承担军事和州郡事务，曹丕受禅前后位至大将军。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-ren', 'zh', '曹仁', '子孝', '168-223', '曹操集团 / 曹魏', '曹仁，字子孝，曹操从弟。早年从曹操征伐，赤壁后守江陵，219 年襄樊危机中坚守樊城，曹丕时期拜大将军、迁大司马。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('zhang-miao', 'zh', '张邈', '孟卓', '?-195', '陈留张邈集团', '东平寿张人，早与曹操、袁绍相友并参与讨董；194 年与陈宫迎吕布入兖州，随后败亡。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cheng-yu', 'zh', '程昱', '仲德', '141-220', '曹操集团 / 曹魏', '东郡东阿人，兖州危机中与荀彧等守住鄄城、东阿等地，是曹操早期根据地得以保全的重要谋臣。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('liu-cong', 'zh', '刘琮', NULL, '?-?', '荆州刘表集团 / 曹魏', '刘表少子，建安十三年刘表卒后被拥为继承人，曹操南下时举荆州归降，直接改变赤壁前局势。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('sun-jian', 'zh', '孙坚', '文台', '155-191', '东汉 / 孙坚集团', '吴郡富春人，讨黄巾、讨董卓中成名，后与刘表作战时死于襄阳方向，是孙策、孙权江东基业的前史核心。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('wei-yan', 'zh', '魏延', '文长', '?-234', '刘备集团 / 蜀汉', '义阳人，随刘备入蜀，219 年被拔为汉中都督，后长期随诸葛亮北伐，234 年诸葛亮死后与杨仪冲突败亡。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('yue-jin', 'zh', '乐进', '文谦', '?-218', '曹操集团 / 曹魏', '阳平卫国人，以胆烈从曹操，屡立先登战功；官渡、南皮等战事有功，后与张辽、李典共同镇守合肥方向。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('yu-jin', 'zh', '于禁', '文则', '?-221', '鲍信部 / 曹操集团 / 曹魏', '泰山钜平人，早随鲍信，后归曹操；以军纪严整著称，219 年襄樊战事中为关羽所俘并投降。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('xu-huang', 'zh', '徐晃', '公明', '?-227', '杨奉部 / 曹操集团 / 曹魏', '河东杨人，先属杨奉，后归曹操；官渡、关中、汉中、襄樊等战事屡有功，219 年解曹仁樊城之围。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-xiu', 'zh', '曹休', '文烈', '?-228', '曹操集团 / 曹魏', '曹休，字文烈，曹操族子。少孤归曹操，被称为“千里驹”，曹丕、曹叡时期长期主持东南对吴方向，228 年石亭战败后病逝。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-zhen', 'zh', '曹真', '子丹', '?-231', '曹操集团 / 曹魏', '曹真，字子丹，曹操族子，少孤后由曹操收养。曹丕时期都督雍凉，文帝临终受遗诏辅政；明帝时任大将军、大司马，应对诸葛亮北伐并主持西线军政。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('man-chong', 'zh', '满宠', '伯宁', '?-242', '曹操集团 / 曹魏', '山阳昌邑人，早以执法严整著称；襄樊战事中辅佐曹仁坚守，曹魏后期主持合肥、淮南东线防御。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('wen-pin', 'zh', '文聘', '仲业', '?-?', '刘表集团 / 曹操集团 / 曹魏', '南阳宛人，原为刘表大将；刘琮降曹后归曹操，长期镇守江夏，承担曹魏荆州、江夏方向防务。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('zang-ba', 'zh', '臧霸', '宣高', '?-?', '陶谦部 / 吕布集团 / 曹操集团 / 曹魏', '泰山华人，早年聚兵于徐州、泰山一带，先助吕布后归曹操；曹操借其控制青徐东方，减轻官渡前后东线压力。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('li-tong', 'zh', '李通', '文达', '?-209', '汝南地方势力 / 曹操集团', '江夏平春人，早据汝南一带，后归曹操；张绣、刘表相关战事中有功，江陵方向作战后病卒。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-rui', 'zh', '曹叡', '元仲', '204-239', '曹魏', '曹丕之子，魏明帝。226 年即位，统治期间应对诸葛亮北伐、孙吴压力和辽东公孙渊问题，239 年去世后曹芳继位。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-fang', 'zh', '曹芳', NULL, '232-274', '曹魏', '曹芳，字兰卿，魏明帝养子。239 年即位后先由曹爽、司马懿辅政，高平陵政变后司马氏掌权，254 年被司马师废为齐王。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-mao', 'zh', '曹髦', '彦士', '241-260', '曹魏', '曹髦，字彦士，曹丕之孙、东海定王曹霖之子。254 年曹芳被废后即位，260 年因不满司马昭专权亲自出讨，被贾充部下成济弑杀。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-huan', 'zh', '曹奂', NULL, '246-302', '曹魏', '曹奂，字景明，曹操之孙、燕王曹宇之子。260 年曹髦死后即位，263 年魏灭蜀汉，265 年禅位于司马炎，曹魏由此结束。', '{}');
