INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('yan-wen', 'zh', '阎温', NULL, NULL, '曹操集团 / 曹魏', '阎温见于《三国志·魏书·阎温传》。本轮先建立人物档案、原文入口和待整理状态，详细生平节点将按本传、裴注与《资治通鉴》逐段补齐。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-zhang', 'zh', '曹彰', '子文', '?-223', '曹魏', '曹操子，字子文，以武勇见称。建安二十三年北征代郡乌丸有功，黄初三年立任城王，次年入朝病逝。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-zhi', 'zh', '曹植', '子建', '192-232', '曹魏', '曹操子，字子建，建安文学代表人物。因才华受曹操赏识并卷入继承竞争，曹丕即位后屡遭贬徙，太和六年封陈王后病逝。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-xiong', 'zh', '曹熊', NULL, NULL, '曹魏', '曹熊，曹操子，早逝。魏文帝黄初二年追封萧怀公，魏明帝太和三年又追进为萧怀王。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-ang', 'zh', '曹昂', NULL, '?-197', '曹魏', '曹操长子，字子修，弱冠举孝廉。建安二年随曹操南征宛城，张绣复叛时遇害。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-shuo', 'zh', '曹铄', NULL, NULL, '曹魏', '曹铄，曹操子，早逝。魏明帝太和三年追封谥，后嗣曹潜、曹偃相继承袭，终因无子国除。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-chong', 'zh', '曹冲', '仓舒', '196-208', '曹魏', '曹操子，字仓舒，幼年早慧，以称象和为库吏解罪等故事见称。建安十三年十三岁病逝，曹操深为哀痛。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-ju', 'zh', '曹据', NULL, NULL, '曹魏', '曹据，曹操子，建安十六年封范阳侯，曹丕、曹叡时期多次徙封，最终复封彭城王；景初元年因私作禁物被削户。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-yu', 'zh', '曹宇', NULL, NULL, '曹魏', '曹宇，字彭祖，曹操子。太和六年改封燕王，曹叡末年曾短暂被拜为大将军、托以后事，后被免；其子曹奂后来入继帝位。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-lin', 'zh', '曹林', NULL, NULL, '曹魏', '曹林，曹操子，建安十六年封饶阳侯，曹魏建国后屡次徙封，太和六年改封沛王，薨后谥穆。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-gun', 'zh', '曹衮', NULL, NULL, '曹魏', '曹衮，曹操子，中山恭王。少好学、能属文，传称其尚约俭、谨慎自守，是武文世王公传中事迹较丰富的宗室王之一。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-xuan', 'zh', '曹玹', NULL, NULL, '曹魏', '曹玹，曹操子，建安十六年封西乡侯，早逝无子；太和年间追进爵号为济阳怀王。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-jun', 'zh', '曹峻', NULL, NULL, '曹魏', '曹峻，字子安，曹操子。建安二十一年封郿侯，黄初三年为陈留王，太和六年复封陈留，甘露四年去世。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-ju-fanyang', 'zh', '曹矩', NULL, NULL, '曹魏', '曹矩，曹操子，早逝无子。建安二十二年以曹敏奉其后，太和六年追进号为范阳闵王。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-gan', 'zh', '曹干', NULL, NULL, '曹魏', '曹干，曹操子，一名良。幼年丧母，又逢曹操病笃，曹丕因遗命亲待甚厚；太和六年改封赵王。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-shang', 'zh', '曹上', NULL, NULL, '曹魏', '曹上，曹操子，早逝无后；太和五年追封谥为临邑殇公子。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-biao', 'zh', '曹彪', NULL, '195-251', '曹魏', '曹彪，字朱虎，曹操子。历封寿春侯、弋阳王、吴王、白马王、楚王；251 年因王凌、令狐愚谋立案被赐死。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-qin', 'zh', '曹勤', NULL, NULL, '曹魏', '曹勤，曹操子，早逝无后；太和五年追封谥为刚殇公子。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-cheng', 'zh', '曹乘', NULL, NULL, '曹魏', '曹乘，曹操子，早逝无后；太和五年追封谥为谷城殇公子。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-zheng', 'zh', '曹整', NULL, NULL, '曹魏', '曹整，曹操子，奉从叔父曹绍后。建安二十二年封郿侯，二十三年去世无子，黄初二年追进爵、谥戴公。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-jing', 'zh', '曹京', NULL, NULL, '曹魏', '曹京，曹操子，早逝无后；太和五年追封谥为灵殇公子。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-jun-fan', 'zh', '曹均', NULL, NULL, '曹魏', '曹均，曹操子，奉叔父蓟恭公曹彬后。建安二十二年封樊侯，建安二十四年去世，后追进公爵。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-ji', 'zh', '曹棘', NULL, NULL, '曹魏', '曹棘，曹操子，早逝无后；太和五年追封谥为广宗殇公子。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-hui', 'zh', '曹徽', NULL, NULL, '曹魏', '曹徽，曹操子，奉叔公朗陵哀侯后。历封历城侯、庐江王、寿张王，太和六年改封东平王，正始三年去世。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-mao-prince', 'zh', '曹茂', NULL, NULL, '曹魏', '曹茂，曹操子。传称其性慠佷、少无宠于曹操，曹丕时独不王；曹叡时封聊城王，后徙封乐陵王。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-xie', 'zh', '曹协', NULL, NULL, '曹魏', '曹协，曹丕子，早逝。太和五年追封经殇公，青龙二年追改号谥为赞哀王。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-rui-prince', 'zh', '曹蕤', NULL, NULL, '曹魏', '曹蕤，曹丕子。黄初七年魏明帝即位后立为阳平县王，太和六年改封北海，青龙元年去世。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-jian', 'zh', '曹鉴', NULL, NULL, '曹魏', '曹鉴，曹丕子。黄初六年立为东武阳王，当年去世，青龙三年赐谥，无子国除。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-lin-donghai', 'zh', '曹霖', NULL, NULL, '曹魏', '曹霖，曹丕子，东海定王。黄初三年立为河东王，太和六年改封东海，嘉平元年去世；其子曹髦后入继曹魏帝位。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-li', 'zh', '曹礼', NULL, NULL, '曹魏', '曹礼，曹丕子。黄初二年封秦公，以京兆郡为国，后改封京兆王、元城王，太和三年去世。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-yong', 'zh', '曹邕', NULL, NULL, '曹魏', '曹邕，曹丕子。黄初二年封淮南公，后进淮南王，改封陈、邯郸，太和三年去世。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-gong', 'zh', '曹贡', NULL, NULL, '曹魏', '曹贡，曹丕子，黄初三年封清河王，黄初四年去世，无子国除。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('cao-yan', 'zh', '曹俨', NULL, NULL, '曹魏', '曹俨，曹丕子，黄初三年封广平王，黄初四年去世，无子国除。', '{}');
INSERT INTO "person_i18n" ("person_id", "locale", "name", "courtesy_name", "life", "primary_polity", "summary", "raw_json") VALUES ('liu-shao', 'zh', '刘劭', NULL, NULL, '曹操集团 / 曹魏', '刘劭见于《三国志·魏书·刘劭传》。本轮先建立人物档案、原文入口和待整理状态，详细生平节点将按本传、裴注与《资治通鉴》逐段补齐。', '{}');
