    "Eboracum"
  ],
  "macroEvent": "Severan Dynasty",
  "eventLabel": "Severus'' British campaign",
  "factType": "military-event",
  "questions": [
    "罗马军队的具体损失数字 Cassius Dio 和 Herodian 是否一致？",
    "塞维鲁在不列颠的军事基地考古证据如何？"
  ],
  "confidence": "high",
  "importance": "medium",
  "sourceRefs": [
