  "questions": [
    "Eutropius 对普罗布斯的积极评价是否存在偏袒？普罗布斯是否也犯过重大的战略错误？"
  ],
  "confidence": "high",
  "importance": "medium",
  "sourceRefs": [
    {
      "sourceId": "rome-source-breviarium-ab-urbe-condita-eutropius",
      "locator": "9.16–9.20"
    }
  ],
  "tags": [
