  ],
  "promotedAt": "2026-06-26T07:04:30.464Z",
  "reviewStatus": "reviewed",
  "reviewedBy": "manual-rome-core-event-review-190-310",
  "detail": {
    "overview": "戴克里先建立了四帝共治制度（Tetrarchy），以四人分工治理的方式取代一人独治。",
