INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-184-yellow-turban-rebellion', 'zh', '黄巾起义爆发', '东汉各地', '太平道领袖张角发动大规模起义，东汉中央权威进一步崩溃，州郡军事化和地方豪强扩张由此加速。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-189-dong-zhuo-enters-luoyang', 'zh', '董卓入洛阳控制朝廷', '洛阳', '何进被杀后，董卓率凉州军入洛阳，废少帝、立献帝，东汉朝廷被军事强人直接控制。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-190-coalition-against-dong-zhuo', 'zh', '关东诸军起兵讨董', '关东、洛阳周边', '袁绍、袁术、曹操等关东军阀以讨伐董卓为名起兵。联盟本身松散，却标志着州郡军阀公开进入全国政治舞台。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-192-dong-zhuo-killed', 'zh', '董卓被杀，长安政局再度失控', '长安', '王允与吕布等诛杀董卓，但董卓旧部随后攻入长安，献帝朝廷继续在军阀挟持中动荡。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-194-tao-qian-yields-xuzhou', 'zh', '陶谦病卒，刘备领徐州', '徐州', '陶谦病重后将徐州托付给刘备，陶谦死后刘备在徐州士民推举下接掌州事，第一次获得较完整的州级政治基础。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-194-lu-bu-seizes-yan', 'zh', '吕布袭取兖州，曹操根据地受挫', '兖州', '曹操东征徐州期间，吕布与兖州部分士人、将领结合，袭取兖州多地。曹操一度只保有少数城邑，北方格局仍未稳定。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-196-cao-cao-escorts-emperor', 'zh', '曹操迎汉献帝至许', '许', '曹操迎接汉献帝至许，以东汉朝廷名义发布诏令、整合政治合法性，形成“挟天子以令诸侯”的政治优势。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-196-lu-bu-seizes-xuzhou', 'zh', '吕布袭下邳，刘备失徐州', '下邳、徐州', '刘备与袁术交战时，吕布袭取下邳并控制徐州。刘备失去刚取得的州级基础，转入依附吕布、曹操之间的夹缝状态。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-197-yuan-shu-declares-emperor', 'zh', '袁术称帝，淮南集团迅速孤立', '寿春', '袁术在淮南称帝，破坏东汉名义秩序，也使自己成为其他势力共同排斥的对象，淮南势力开始瓦解。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-199-yuan-shu-collapse', 'zh', '袁术败亡，淮南集团瓦解', '淮南、江亭一带', '称帝后的袁术先后受吕布、曹操等压力，粮尽势孤，欲北投袁谭未成，最终病死。淮南袁术集团作为独立势力瓦解。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-199-gongsun-zan-defeated', 'zh', '易京陷落，公孙瓒败亡', '易京', '袁绍长期围攻公孙瓒，易京最终陷落。公孙瓒败亡后，幽州与冀北格局转向袁绍主导，为官渡前袁绍强势地位提供基础。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-199-lu-bu-defeated', 'zh', '下邳陷落，吕布败亡', '下邳', '曹操围攻下邳，吕布被俘后处死。徐州局势重新洗牌，曹操在官渡前清除了东南方向的重要威胁。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-200-guandu', 'zh', '官渡之战', '官渡', '曹操与袁绍在官渡决战。曹操袭破乌巢后取得战略胜利，河北袁绍集团由盛转衰，北方统一的方向基本确定。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-207-longzhong-plan', 'zh', '刘备得诸葛亮，隆中对成形', '隆中', '刘备延揽诸葛亮，诸葛亮提出据荆益、联孙抗曹、待天下有变的战略构想，为后来蜀汉路线奠定思想框架。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-208-red-cliffs', 'zh', '赤壁之战', '赤壁、长江中游', '曹操南下荆州后，孙权与刘备联合抵抗。赤壁之战阻止了曹操迅速统一南方，三分格局开始显现。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-214-liu-bei-takes-yi', 'zh', '刘备入主益州', '成都', '刘备与刘璋决裂后攻取益州，取得稳定的西南根据地。荆州、益州并重的战略开始具备现实基础。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-215-cao-cao-takes-hanzhong', 'zh', '曹操取汉中', '汉中', '张鲁向曹操投降，汉中纳入曹操控制。此后汉中成为曹操与刘备争夺关中、益州通道的关键区块。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-219-hanzhong-and-jingzhou-crisis', 'zh', '刘备称汉中王，关羽失荆州', '汉中、荆州', '刘备夺取汉中后称汉中王，关羽北伐襄樊一度震动曹魏。但孙吴袭取荆州，关羽败亡，蜀汉东西两线格局被迫收缩。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-220-cao-pi-founds-wei', 'zh', '曹丕称帝，曹魏建立', '洛阳', '曹丕接受汉献帝禅让，建立魏国，东汉正式结束。三国时期从割据事实进入正式政权并立阶段。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-221-liu-bei-founds-shu', 'zh', '刘备称帝，蜀汉建立', '成都', '刘备在成都称帝，以继承汉室为政治名义建立蜀汉。此举回应曹魏代汉，也使魏蜀对立正式制度化。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-222-yiling', 'zh', '夷陵之战', '夷陵、猇亭', '刘备为夺回荆州东征孙吴，陆逊据险相持并反击，蜀军大败。此战后吴蜀重新寻求缓和，三国边界趋于稳定。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('sasanian-224-ardashir-defeats-parthians', 'zh', '阿尔达希尔击败安息王朝', '霍尔米兹甘', '阿尔达希尔一世击败安息末代君主阿尔达班四世，萨珊波斯崛起，西亚政治格局发生重大变化。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-226-jiaozhou-incorporated-by-wu', 'zh', '士燮卒，交州士氏独立地位削弱', '交州、交趾', '士燮去世后，交州士氏长期自治的局面开始改变。孙吴通过刺史任命和军事处置加强交州控制，岭南逐渐纳入孙吴直接经营。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-229-sun-quan-emperor', 'zh', '孙权称帝，孙吴正式建国', '武昌、建业', '孙权称帝，国号吴，随后迁都建业。至此魏、蜀、吴三国都以皇帝名义建立政权。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('india-230-kushan-decline', 'zh', '贵霜帝国影响力持续衰退', '印度西北部与中亚南缘', '三世纪前中期，贵霜帝国对印度西北和中亚南部的控制减弱，区域政治力量逐渐重组。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-234-wuzhang-plains', 'zh', '诸葛亮卒于五丈原', '五丈原', '诸葛亮最后一次北伐时与司马懿对峙于渭水南北，后卒于五丈原。蜀汉北伐进入新的阶段，战略主动性逐渐减弱。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-sasanian-260-valerian-captured', 'zh', '沙普尔一世俘虏罗马皇帝瓦勒良', '埃德萨附近', '萨珊君主沙普尔一世在与罗马的战争中俘虏皇帝瓦勒良，这是罗马帝国对外战争中的重大打击。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-263-shu-han-conquered', 'zh', '蜀汉灭亡', '成都', '曹魏发动灭蜀之战，钟会主力牵制剑阁，邓艾偷渡阴平直入成都，刘禅投降，三国之一的蜀汉灭亡。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-265-jin-replaces-wei', 'zh', '司马炎代魏，西晋建立', '洛阳', '司马炎接受魏帝禅让，建立西晋。曹魏灭亡后，北方政权进入司马氏统治阶段。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-280-jin-conquers-wu', 'zh', '西晋灭吴，三国归一', '建业', '西晋多路伐吴，孙吴末帝投降。三国分裂局面结束，中国再次进入统一王朝框架。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-291-eight-princes-war', 'zh', '八王之乱展开', '洛阳及西晋核心州郡', '西晋宗室诸王和外戚、朝臣围绕中央权力反复争斗，通常称为八王之乱。其主要阶段一般定为 291-306 年，是西晋由统一转入失序的关键节点。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('china-304-five-barbarians-begin', 'zh', '五胡乱华开端', '并州、巴蜀及西晋边缘州郡', '304 年，刘渊在并州建立汉赵政权，李雄在成都称王，通常被视为十六国局面和五胡乱华开端的关键节点。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('sasanian-230-ardashir-roman-frontier', 'zh', '阿尔达希尔威胁罗马东方边境', 'Mesopotamia and Syria frontier', '阿尔达希尔一世在巩固萨珊王权后向罗马东方边境施压，罗马被迫准备大规模东征。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('sasanian-232-alexander-severus-expedition', 'zh', '亚历山大·塞维鲁远征波斯', 'Roman-Persian frontier', '亚历山大·塞维鲁组织对萨珊波斯的东征，但战果有限，双方边境压力并未根本解除。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('sasanian-244-battle-of-misiche', 'zh', '米西凯会战与戈尔迪安三世之死', 'Misiche / Mesopotamia', '沙普尔一世铭文宣称在米西凯击败罗马，戈尔迪安三世随后死亡，罗马与萨珊达成不利和约。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('sasanian-256-dura-europos', 'zh', '杜拉欧罗普斯陷落', 'Dura-Europos', '幼发拉底河边境要塞杜拉欧罗普斯被萨珊攻陷，考古证据显示围城战和坑道战极为激烈。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('sasanian-262-odaenathus-counteroffensive', 'zh', '奥登纳图斯反击萨珊', 'Mesopotamia', '帕尔米拉的奥登纳图斯代表罗马东方反击萨珊，缓解瓦勒良被俘后的边境危机。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('sasanian-280-kartir-priestly-power', 'zh', '卡尔提尔祭司权力上升', 'Sasanian heartland', '卡尔提尔铭文显示祆教祭司集团在萨珊国家结构中取得更突出地位，并影响王权合法性叙事。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('sasanian-293-narseh-paikuli', 'zh', '纳尔塞通过 Paikuli 政治联盟即位', 'Paikuli', 'Paikuli 铭文记录纳尔塞获得贵族和地方权力集团支持，击败巴赫拉姆三世并取得王位。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('sasanian-298-treaty-of-nisibis', 'zh', '尼西比斯和约', 'Nisibis', '纳尔塞败于罗马后签订和约，罗马获得美索不达米亚和亚美尼亚方向优势，形成三世纪末东方边界新格局。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-145-origins-of-septimius-severus-african-provincial-aristocrat', 'zh', 'Origins of Septimius Severus: African provincial aristocrat', 'Leptis Magna', '塞维鲁是第一位来自北非的罗马皇帝——他的出身代表了三世纪行省地方贵族上升至帝位的趋势。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-180-herodian-as-a-source-for-the-severan-and-early-crisis-period', 'zh', 'Herodian as a source for the Severan and early crisis period', 'Rome', 'Herodian 是覆盖从马可·奥勒留之死（180）到戈尔迪安三世登基（238）的唯一完整的当代史家。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-193-didius-julianus-buys-the-throne-severus-proclaimed-in-pannonia', 'zh', 'Didius Julianus buys the throne; Severus proclaimed in Pannonia', 'Rome', '公元 193 年四帝并立，帝国的统治权在禁卫军拍卖和行省军团拥立之间摇摆。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-193-severus-marches-on-rome-and-disbands-the-praetorian-guard', 'zh', 'Severus marches on Rome and disbands the Praetorian Guard', 'Rome', '塞维鲁从潘诺尼亚迅速进军罗马，解散了原有禁卫军并用自己的老兵重建。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-193-severus-establishes-military-monarchy', 'zh', 'Severus establishes military monarchy', 'Rome', '塞维鲁将帝国转变为以军队为核心的军事君主制。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-193-assassination-of-commodus-and-pertinax-auction-of-the-empire', 'zh', 'Assassination of Commodus and Pertinax; auction of the empire', 'Rome', '192 年末康茂德被弑，佩尔蒂纳克斯在位 87 天即被禁卫军杀害，随后禁卫军公开拍卖皇位。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-193-severus-enters-rome-and-addresses-the-senate', 'zh', 'Severus enters Rome and addresses the Senate', 'Rome', '塞维鲁入主罗马后向元老院发表安抚性讲话，但暗中的威胁令 Dio 深感不安。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-193-severan-military-reforms', 'zh', 'Severan military reforms', 'Rome', '塞维鲁大幅提高军饷并增设三个军团，强化了军队但也加重了财政负担。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-194-severus-defeats-pescennius-niger-at-issus', 'zh', 'Severus defeats Pescennius Niger at Issus', 'Issus', '塞维鲁于 194 年在伊苏斯击败东部对手尼格尔，统一东方行省。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-197-battle-of-lugdunum-severus-defeats-clodius-albinus', 'zh', 'Battle of Lugdunum: Severus defeats Clodius Albinus', 'Lugdunum', '197 年里昂战役，塞维鲁歼灭最后一个对手阿尔比努斯，结束了内战。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-198-severus-sacks-ctesiphon-and-creates-province-of-mesopotamia', 'zh', 'Severus sacks Ctesiphon and creates province of Mesopotamia', 'Mesopotamia', '塞维鲁攻陷帕提亚首都泰西封，设立美索不达米亚行省。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-200-palmyra-the-desert-metropolis-and-its-trade-empire', 'zh', 'Palmyra: the desert metropolis and its trade empire', 'Palmyra', '帕尔米拉是 3 世纪叙利亚沙漠中最为繁荣的商都，其财富和军事力量使它得以在罗马的混乱中崛起。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-208-severus-british-campaign', 'zh', 'Severus'' British campaign', 'Britannia', '塞维鲁晚年发动远征征服喀里多尼亚，但未能完成即病逝于约克。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-211-death-of-septimius-severus-at-eboracum', 'zh', 'Death of Septimius Severus at Eboracum', 'Eboracum', '公元 211 年 2 月，塞维鲁在不列颠的约克病逝，帝国由其子卡拉卡拉和盖塔共同继承。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-211-caracalla-and-geta-joint-rule-and-mutual-hostility', 'zh', 'Caracalla and Geta: joint rule and mutual hostility', 'Rome', '卡拉卡拉和盖塔在父亲去世后共同统治帝国，但兄弟之间极度不信任，不到一年即以血腥结局收场。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-211-caracalla-murders-geta', 'zh', 'Caracalla murders Geta', 'Rome', '211 年 12 月卡拉卡拉杀害弟弟盖塔，实行记忆抹除。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-211-death-of-geta-and-damnatio-memoriae', 'zh', 'Death of Geta and damnatio memoriae', 'Rome', '盖塔被杀后遭受记忆抹除，其支持者遭到大规模清洗。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-211-caracallas-building-program-and-coinage-reform', 'zh', 'Caracalla''s building program and coinage reform', 'Rome', '卡拉卡拉修建了宏伟的浴场，同时引入了安东尼尼安银币——开启了三世纪币值贬值的先例。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-211-the-severan-women-a-dynasty-of-empresses', 'zh', 'The Severan women: a dynasty of empresses', 'Rome', '塞维鲁王朝的女性——尤其是尤利娅·多姆娜——在政治、智识和军方都发挥了空前的影响力。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-212-constitutio-antoniniana-universal-citizenship', 'zh', 'Constitutio Antoniniana: universal citizenship', 'Rome', '212 年《安东尼努斯敕令》授予帝国境内所有自由居民罗马公民权，是罗马史上影响最深远的法令之一。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-212-constitutio-antoniniana-the-papyrus-evidence', 'zh', 'Constitutio Antoniniana: the papyrus evidence', 'Rome', '《安东尼努斯敕令》的原文仅存埃及出土的一页残片（P. Giss. 40），文本严重残缺。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-213-caracallas-german-campaign', 'zh', 'Caracalla''s German campaign', 'Rhine', '213 年卡拉卡拉发动莱茵河战役对抗阿勒曼尼人，赢得以金钱和阴谋而非军事才能换来的胜利。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-216-caracallas-parthian-war', 'zh', 'Caracalla''s Parthian war', 'Mesopotamia', '卡拉卡拉以联姻为名背信弃义对帕提亚发动战争，虽个人获取了一些战利品但军事上无功而返。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-217-assassination-of-caracalla-macrinus-proclaimed-emperor', 'zh', 'Assassination of Caracalla; Macrinus proclaimed emperor', 'Carrhae', '217 年 4 月卡拉卡拉遇刺身亡，禁卫军长官马克里努斯被拥立为帝。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-217-macrinus-defeated-elagabalus-proclaimed-emperor', 'zh', 'Macrinus defeated; Elagabalus proclaimed emperor', 'Antioch', '马克里努斯削减军饷引发军队不满，塞维鲁家族借机拥立埃拉伽巴路斯。218 年马克里努斯战败被杀。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-217-reign-of-macrinus', 'zh', 'Reign of Macrinus', 'Rome', '马克里努斯是第一位骑士出身的皇帝，在位仅 14 个月，因军队不满而覆灭。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-217-cassius-dio-as-eyewitness-the-senator-under-tyranny', 'zh', 'Cassius Dio as eyewitness: the senator under tyranny', 'Rome', 'Cassius Dio 以第一人称亲历者的身份记录了塞维鲁王朝末期元老与皇帝之间的恐怖关系。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-218-julia-maesa-orchestrates-the-restoration-of-the-severan-dynasty', 'zh', 'Julia Maesa orchestrates the restoration of the Severan dynasty', 'Emesa', '尤利娅·梅萨利用塞维鲁家族的财富和军队忠诚，成功拥立外孙埃拉伽巴路斯复辟塞维鲁王朝。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-219-elagabalus-introduces-the-cult-of-elagabal-to-rome', 'zh', 'Elagabalus introduces the cult of Elagabal to Rome', 'Rome', '埃拉伽巴路斯将叙利亚太阳神崇拜带入罗马，引发政治和宗教上的巨大反弹。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-222-assassination-of-elagabalus-alexander-severus-becomes-emperor', 'zh', 'Assassination of Elagabalus; Alexander Severus becomes emperor', 'Rome', '222 年埃拉伽巴路斯被弑，亚历山大·塞维鲁即位，皇权回归正常轨道。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-222-reign-of-alexander-severus-stability-under-maternal-regency', 'zh', 'Reign of Alexander Severus: stability under maternal regency', 'Rome', '亚历山大·塞维鲁的 13 年统治是塞维鲁王朝最后一段相对稳定期，但母后干政、军事软弱为接下来的危机埋下伏笔。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-222-regency-of-julia-mamaea-and-the-role-of-ulpian', 'zh', 'Regency of Julia Mamaea and the role of Ulpian', 'Rome', '尤利娅·玛迈亚通过元老院顾问委员会和法学家乌尔比安统治帝国，但母权的过度干涉埋下了灭亡的种子。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-224-ardashir-i-overthrows-the-parthians-and-founds-the-sassanid-empire', 'zh', 'Ardashir I overthrows the Parthians and founds the Sassanid Empire', 'Persia', '224 年阿尔达希尔一世推翻帕提亚建立萨珊波斯，罗马东部边境面临前所未有的挑战。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-230-the-collapse-of-roman-coinage-and-hyperinflation', 'zh', 'The collapse of Roman coinage and hyperinflation', 'Rome', '三世纪危机时期罗马银币的含银量暴跌至不足 5%，导致帝国财政和军队薪酬体系崩溃。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-235-assassination-of-alexander-severus-beginning-of-the-third-century-crisis', 'zh', 'Assassination of Alexander Severus; beginning of the Third Century Crisis', 'Moguntiacum', '235 年亚历山大·塞维鲁被弑，塞维鲁王朝终结，三世纪危机正式开始。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-235-reign-of-maximinus-thrax-first-soldier-emperor-from-the-ranks', 'zh', 'Reign of Maximinus Thrax: first soldier-emperor from the ranks', 'Germania', '马克西米努斯·色雷克斯是第一位从普通士兵逐级晋升至皇帝的军人，他的统治完全以军队为核心。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-235-the-third-century-crisis-overview', 'zh', 'The Third Century Crisis: overview', 'Rome', '三世纪危机（235-284）是罗马帝国历史上最严重的系统性危机，军事、经济、政治同时崩溃。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-235-maximinus-thraxs-rhine-and-danube-campaigns', 'zh', 'Maximinus Thrax''s Rhine and Danube campaigns', 'Germania', '马克西米努斯在位三年间持续在前线作战（日耳曼-萨尔马提亚），从未踏足罗马。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-238-year-of-the-six-emperors', 'zh', 'Year of the Six Emperors', 'Carthage', '公元 238 年出现了六位皇帝——戈尔迪安一世、戈尔迪安二世、马克西米努斯、普皮恩努斯、巴尔比努斯和戈尔迪安三世——帝国政治陷入空前混乱。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-238-fall-of-maximinus-thrax-at-aquileia', 'zh', 'Fall of Maximinus Thrax at Aquileia', 'Aquileia', '238 年马克西米努斯围攻阿奎莱亚失败，被自己的士兵杀死。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-244-death-of-gordian-iii-philip-the-arab-becomes-emperor', 'zh', 'Death of Gordian III; Philip the Arab becomes emperor', 'Mesopotamia', '244 年戈尔迪安三世在对萨珊波斯的远征中死亡，腓力·阿拉伯即位。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-244-shapur-is-account-of-gordian-iiis-death-battle-or-murder', 'zh', 'Shapur I''s account of Gordian III''s death: battle or murder?', 'Misiche', '沙普尔一世声称戈尔迪安三世在 Misiche 会战中阵亡——罗马史料则暗示他被腓力谋杀——双方叙事直接矛盾。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-248-fall-of-philip-the-arab-decius-becomes-emperor', 'zh', 'Fall of Philip the Arab; Decius becomes emperor', 'Verona', '249 年腓力·阿拉伯被德西乌斯击败身亡，帝国陷入新一轮军事动荡。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-249-decian-persecution-of-christians', 'zh', 'Decian persecution of Christians', 'Rome', '德西乌斯于 250 年发动了第一次帝国范围的系统性基督教迫害。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-251-battle-of-abrittus-decius-killed-by-goths', 'zh', 'Battle of Abrittus: Decius killed by Goths', 'Abrittus', '251 年德西乌斯在阿布里图斯战役中被哥特人击杀，成为首位死于蛮族的罗马皇帝。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-252-shapur-is-three-invasions-of-the-roman-east-252-260', 'zh', 'Shapur I''s three invasions of the Roman East (252-260)', 'Mesopotamia', '沙普尔一世在 252-260 年间三次大规模入侵罗马帝国东部，最终俘虏了皇帝瓦勒良。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-252-the-plague-of-cyprian-249-262', 'zh', 'The Plague of Cyprian (249-262)', 'Carthage', '西普里安瘟疫（249-262）在帝国面临军事和政治危机的同时对人口造成了毁灭性的打击。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-253-valerian-and-gallienus-the-first-systematic-division-of-the-empire', 'zh', 'Valerian and Gallienus: the first systematic division of the empire', 'Rome', '253 年瓦勒良与加里恩努斯父子共治，开创了三世纪东西分治帝国的先例。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-260-capture-of-valerian-by-shapur-i', 'zh', 'Capture of Valerian by Shapur I', 'Edessa', '260 年罗马皇帝瓦勒良被萨珊波斯国王沙普尔一世俘虏——罗马史上首次皇帝被外敌生擒。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-260-gallienus-sole-reign-gallic-empire-secedes', 'zh', 'Gallienus sole reign; Gallic Empire secedes', 'Gaul', '加里恩努斯在父亲被俘后独自统治帝国，面对高卢帝国的分离和多方入侵，艰难支撑。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-260-the-gallic-empire-260-274', 'zh', 'The Gallic Empire (260-274)', 'Gaul', '260 年高卢、不列颠和西班牙在波斯特穆斯领导下脱离中央帝国，形成了持续 14 年的高卢帝国。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-260-gallienus-faces-the-empires-darkest-hour', 'zh', 'Gallienus faces the empire''s darkest hour', 'Rome', '瓦勒良被俘后，加里恩努斯独自面对帝国在最黑暗时期的全面崩溃。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-260-postumus-founds-the-gallic-empire', 'zh', 'Postumus founds the Gallic Empire', 'Colonia Agrippina', '260 年波斯特穆斯被莱茵河军团拥立，杀害加里恩努斯之子后建立了独立的高卢帝国。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-260-gallienus-creation-of-a-mobile-cavalry-army', 'zh', 'Gallienus'' creation of a mobile cavalry army', 'Milan', '加里恩努斯创建了独立的骑兵预备队，为后来奥勒良和戴克里先的纵深防御奠定了基础。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-267-odaenathus-romes-eastern-defender-and-the-origin-of-palmyrene-power', 'zh', 'Odaenathus: Rome''s eastern defender and the origin of Palmyrene power', 'Palmyra', '奥登纳图斯在瓦勒良被俘后击退萨珊波斯，成为实际上的东方最高统帅——为帕尔米拉帝国的崛起创造了条件。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-268-reign-of-claudius-gothicus-victory-at-naissus', 'zh', 'Reign of Claudius Gothicus: victory at Naissus', 'Naissus', '克劳狄二世（268-270）在纳伊苏斯大破哥特入侵军，但统治仅一年零八个月即因瘟疫而死。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-268-claudius-gothicus-and-the-constantinian-connection', 'zh', 'Claudius Gothicus and the Constantinian connection', 'Naissus', 'HA 将克劳狄二世神话化为君士坦丁的祖先，但在君士坦丁时代的宣传中这一虚构被广泛接受。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-269-eutropius-on-zenobias-regency', 'zh', 'Eutropius on Zenobia''s regency', 'Palmyra', 'Eutropius 对芝诺比娅统治的描述相对中性，强调了它作为合法代理而非纯粹叛乱的方面。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-270-aurelian-becomes-emperor', 'zh', 'Aurelian becomes emperor', 'Sirmium', '270 年奥勒良即位，迅速稳定了多瑙河前线并开始收复失地。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-270-zenobia-and-the-palmyrene-empire-267-272', 'zh', 'Zenobia and the Palmyrene Empire (267-272)', 'Palmyra', '芝诺比娅在丈夫死后将帕尔米拉扩展为一个实际上脱离罗马的东方帝国。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-271-aurelians-reforms-walls-coinage-and-sol-invictus', 'zh', 'Aurelian''s reforms: walls, coinage, and Sol Invictus', 'Rome', '奥勒良在统一帝国的同时进行了防御、币制、宗教等方面的系统性改革。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-271-construction-of-the-aurelian-walls-rome-is-no-longer-safe', 'zh', 'Construction of the Aurelian Walls: Rome is no longer safe', 'Rome', '奥勒良城墙的修建标志着帝国心脏地带自共和国以来首次暴露于蛮族威胁之下。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-272-aurelian-defeats-zenobia-and-recovers-the-east', 'zh', 'Aurelian defeats Zenobia and recovers the East', 'Palmyra', '272 年奥勒良击败帕尔米拉的芝诺比娅女王，收复帝国东部行省。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-274-aurelian-defeats-tetricus-and-reunifies-the-roman-empire', 'zh', 'Aurelian defeats Tetricus and reunifies the Roman Empire', 'Châlons', '274 年奥勒良收复高卢帝国，完成了罗马帝国的再统一。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-275-assassination-of-aurelian', 'zh', 'Assassination of Aurelian', 'Caenophrurium', '275 年奥勒良被其秘书官伪造名单引发的阴谋杀害，帝国再次陷入空位期。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-275-reign-and-death-of-tacitus', 'zh', 'Reign and death of Tacitus', 'Rome', '塔西佗被元老院选举为帝但仅在位数月即去世。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-276-military-campaigns-and-public-works-of-probus', 'zh', 'Military campaigns and public works of Probus', 'Gaul', '普罗布斯通过一系列成功的军事行动巩固了帝国，其让士兵参与公共工程的政策虽高效但引发军队不满。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-277-reign-of-probus-military-recovery', 'zh', 'Reign of Probus: military recovery', 'Gaul', '普罗布斯（276-282）在莱茵河和多瑙河取得了连续的军事胜利，巩固了奥勒良重新统一的帝国。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-280-the-transition-from-soldier-emperors-to-diocletians-system', 'zh', 'The transition from soldier-emperors to Diocletian''s system', 'Rome', '卡鲁斯短命王朝（282-284）是三世纪危机模式的最后一次重复，此后戴克里先带来了系统性变革。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-282-reign-of-carus-persian-victory-and-mysterious-death', 'zh', 'Reign of Carus: Persian victory and mysterious death', 'Mesopotamia', '卡鲁斯（282-283）成功攻陷泰西封但随即神秘死亡，其子努梅里安的死亡直接触发了戴克里先的崛起。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-284-diocletian-becomes-emperor', 'zh', 'Diocletian becomes emperor', 'Nicomedia', '284 年戴克里先即位，终结了三世纪危机，开启帝国制度性改革的新时代。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-284-battle-of-the-margus-diocletian-defeats-carinus', 'zh', 'Battle of the Margus: Diocletian defeats Carinus', 'Margus River', '285 年戴克里先在马尔古斯河战役中击败卡里努斯，成为帝国唯一的皇帝。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-284-diocletians-elevation-from-freedmans-son-to-dominus', 'zh', 'Diocletian''s elevation: from freedman''s son to dominus', 'Nicomedia', '戴克里先将皇帝的公众形象从奥古斯都的第一公民转变为波斯式的神圣君主。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-284-284-ce-as-the-end-of-the-third-century-crisis-and-the-beginning-of-late-', 'zh', '284 CE as the end of the Third Century Crisis and the beginning of Late Antiquity', 'Nicomedia', '284 年戴克里先的即位被现代学者视为从三世纪危机向古典晚期转型的转折点。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-285-career-of-maximian-the-loyal-colleague', 'zh', 'Career of Maximian: the loyal colleague', 'Milan', '马克西米安是戴克里先长达二十年的西部共治者，虽军事才能卓著但缺乏政治自信。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-285-aurelius-victor-on-diocletians-reign', 'zh', 'Aurelius Victor on Diocletian''s reign', 'Nicomedia', 'Aurelius Victor 提供了对戴克里先统治的最早拉丁文评价——称赞其成就但也批评其傲慢。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-293-establishment-of-the-tetrarchy', 'zh', 'Establishment of the Tetrarchy', 'Nicomedia', '戴克里先建立了四帝共治制度（Tetrarchy），以四人分工治理的方式取代一人独治。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-286-carausius-and-the-secessionist-british-empire-286-296', 'zh', 'Carausius and the secessionist British Empire (286-296)', 'Britannia', '海军指挥官卡劳修斯于 286-293 年割据不列颠，建立了独特的海洋帝国。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-293-career-of-constantius-chlorus-the-quiet-caesar', 'zh', 'Career of Constantius Chlorus: the quiet Caesar', 'Trier', '君士坦提乌斯一世是四帝共治中最不引人注目但最为可靠的凯撒——他收复了不列颠，并在宗教迫害中采取了温和政策。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-301-diocletians-administrative-and-economic-reforms', 'zh', 'Diocletian''s administrative and economic reforms', 'Empire-wide', '戴克里先进行了罗马帝国史上最大规模的行政、军事和财政制度改革。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-301-diocletians-edict-on-maximum-prices-301-ce', 'zh', 'Diocletian''s Edict on Maximum Prices (301 CE)', 'Empire-wide', '301 年的《最高价格敕令》是古代世界最著名的经济政策失败案例之一。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-303-the-great-persecution-begins', 'zh', 'The Great Persecution begins', 'Nicomedia', '303 年大迫害开始了——戴克里先统治下对基督教最系统性的打击。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-303-the-great-persecution-regional-variation-and-political-context', 'zh', 'The Great Persecution: regional variation and political context', 'Nicomedia', '大迫害的执行力度在帝国不同地区差异极大，反映了四帝之间的政治分歧。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-305-abdication-of-diocletian-and-maximian', 'zh', 'Abdication of Diocletian and Maximian', 'Nicomedia', '305 年戴克里先与马克西米安同日退位，君士坦提乌斯一世和伽列里乌斯成为奥古斯都。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-306-death-of-constantius-chlorus-constantine-proclaimed-emperor', 'zh', 'Death of Constantius Chlorus; Constantine proclaimed emperor', 'Eboracum', '306 年君士坦提乌斯一世在约克病逝，君士坦丁被不列颠军团拥立为帝——开启了君士坦丁时代。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-308-council-of-carnuntum-diocletians-last-attempt-to-save-the-tetrarchy', 'zh', 'Council of Carnuntum: Diocletian''s last attempt to save the Tetrarchy', 'Carnuntum', '308 年卡农图姆会议是戴克里先为挽救四帝共治的最后一次努力，但制度已不可逆转地瓦解。', '{}');
INSERT INTO "historical_event_i18n" ("event_id", "locale", "title", "location_name", "summary", "raw_json") VALUES ('rome-311-death-of-galerius-and-the-edict-of-toleration', 'zh', 'Death of Galerius and the Edict of Toleration', 'Nicomedia', '311 年伽列里乌斯在临终前颁布宽容敕令，承认迫害基督教失败并允许基督教的存在。', '{}');

