INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-200-guandu', 'sanguozhi-wei-wudi', '建安五年', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安五年","quote":"袁绍运谷车数千乘至，公用荀攸计，遣徐晃、史涣邀击，大破之，尽烧其车。公乃留曹洪守，自将步骑五千人夜往，会明至。"}');
INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-200-guandu', 'sanguozhi-wei-yuan-shao', '袁绍传官渡相关记载', '{"sourceId":"sanguozhi-wei-yuan-shao","locator":"袁绍传官渡相关记载","quote":"沮授又曰：“北兵数衆而果劲不及南，南谷虚少而货财不及北；南利在于急战，北利在于缓搏。宜徐持乆，旷以日月。”绍不从。"}');
INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-200-guandu', 'sanguozhi-wei-zhang-he', '张郃传官渡相关记载', '{"sourceId":"sanguozhi-wei-zhang-he","locator":"张郃传官渡相关记载","quote":"合说绍曰：“曹公兵精，往必破琼等；琼等破，则将军事去矣，宜急引兵救之。”"}');
INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-200-guandu', 'sanguozhi-wei-xun-yu-jia-xu', '荀彧、荀攸传官渡相关记载', '{"sourceId":"sanguozhi-wei-xun-yu-jia-xu","locator":"荀彧、荀攸传官渡相关记载","quote":"太祖保官渡，绍围之。太祖军粮方尽，书与彧，议欲还许以引绍。彧曰：“今军食虽少，未若楚、汉在荥阳、成皐间也。”"}');
INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-200-guandu', 'sanguozhi-shu-guan-yu', '关羽传白马斩颜良', '{"sourceId":"sanguozhi-shu-guan-yu","locator":"关羽传白马斩颜良","quote":"羽望见良麾盖，策马刺良于万衆之中，斩其首还，绍诸将莫能当者，遂解白马围。"}');
