INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-220-cao-pi-founds-wei', 'houhanshu-xiandi', '延康元年', '{"sourceId":"houhanshu-xiandi","locator":"延康元年"}');
INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-220-cao-pi-founds-wei', 'zizhi-tongjian-69', '黄初元年', '{"sourceId":"zizhi-tongjian-69","locator":"黄初元年","quote":"冬十月乙卯，汉帝告祠高庙，使行御史大夫张音持节奉玺绶诏册，禅位于魏。辛未，升坛受玺绶，即皇帝位。"}');
INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-221-liu-bei-founds-shu', 'sanguozhi-shu-xianzhu', '章武元年', '{"sourceId":"sanguozhi-shu-xianzhu","locator":"章武元年","quote":"章武元年夏四月，大赦，改年。以诸葛亮为丞相，许靖为司徒。置百官，立宗庙。"}');
INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-221-liu-bei-founds-shu', 'zizhi-tongjian-69', '章武元年', '{"sourceId":"zizhi-tongjian-69","locator":"章武元年","quote":"夏四月丙午，汉中王即皇帝位于武担之南。大赦，改元章武。以诸葛亮为丞相，许靖为司徒。"}');
INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-222-yiling', 'sanguozhi-shu-xianzhu', '章武二年', '{"sourceId":"sanguozhi-shu-xianzhu","locator":"章武二年","quote":"陆议大破先主军于猇亭，将军冯习、张南等皆没。先主自猇亭还秭归，收合离散兵。"}');
INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-222-yiling', 'sanguozhi-wu-lu-xun', '陆逊传夷陵相关记载', '{"sourceId":"sanguozhi-wu-lu-xun","locator":"陆逊传夷陵相关记载","quote":"逊曰：“吾已晓破之之术。”乃敕各持一把茅，以火攻拔之。通率诸军同时俱攻，斩张南、冯习及胡王沙摩柯等首，破其四十馀营。"}');
INSERT INTO "historical_event_sources" ("event_id", "source_id", "locator", "raw_json") VALUES ('china-222-yiling', 'zizhi-tongjian-70', '章武二年 / 黄武元年', '{"sourceId":"zizhi-tongjian-70","locator":"章武二年 / 黄武元年","quote":"陆逊督诸军大破先主军于猇亭，将军冯习、张南等皆没。"}');
