INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-shu-xianzhu-liu-bei-death', 'sanguozhi-shu-xianzhu', NULL, '三国志', '蜀书', '先主传', '章武三年', 223, '先主病笃，托孤于丞相亮，尚书令李严为副。夏四月癸巳，先主殂于永安宫，时年六十三。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-shu-xianzhu-liu-bei-death","sourceId":"sanguozhi-shu-xianzhu","workTitle":"三国志","bookTitle":"蜀书","chapterTitle":"先主传","locator":"章武三年","year":223,"text":"先主病笃，托孤于丞相亮，尚书令李严为副。夏四月癸巳，先主殂于永安宫，时年六十三。","translation":null,"mentionedPersonIds":["liu-bei","zhuge-liang"],"mentionedEventIds":["china-222-yiling"],"mentionedPlaceIds":["yongan"],"tags":["死亡","白帝城","托孤"],"confidence":"high","reviewStatus":"reviewed"}');
