INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-wudi-cao-cao-coalition', 'sanguozhi-wei-wudi', NULL, '三国志', '魏书', '武帝纪', '初平元年春正月', 190, '初平元年春正月，后将军袁术、冀州牧韩馥、豫州刺史孔伷、兖州刺史刘岱、河内太守王匡、勃海太守袁绍、陈留太守张邈、东郡太守桥瑁、山阳太守袁遗、济北相鲍信同时俱起兵，众各数万，推绍为盟主。太祖行奋武将军。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-wudi-cao-cao-coalition","sourceId":"sanguozhi-wei-wudi","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"武帝纪","locator":"初平元年春正月","year":190,"text":"初平元年春正月，后将军袁术、冀州牧韩馥、豫州刺史孔伷、兖州刺史刘岱、河内太守王匡、勃海太守袁绍、陈留太守张邈、东郡太守桥瑁、山阳太守袁遗、济北相鲍信同时俱起兵，众各数万，推绍为盟主。太祖行奋武将军。","translation":null,"mentionedPersonIds":["cao-cao","yuan-shao","yuan-shu"],"mentionedEventIds":["china-190-coalition-against-dong-zhuo"],"mentionedPlaceIds":["chenliu","suanzao"],"tags":["讨董","关东联军","奋武将军"],"confidence":"high","reviewStatus":"reviewed"}');
