INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-shu-xianzhu-liu-bei-hanzhong-king', 'sanguozhi-shu-xianzhu', NULL, '三国志', '蜀书', '先主传', '建安二十四年秋', 219, '先主遂有汉中。秋，群下上先主为汉中王，表于汉帝。遂于沔阳设坛场，陈兵列众，群臣陪位，读奏讫，御王冠于先主。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-shu-xianzhu-liu-bei-hanzhong-king","sourceId":"sanguozhi-shu-xianzhu","workTitle":"三国志","bookTitle":"蜀书","chapterTitle":"先主传","locator":"建安二十四年秋","year":219,"text":"先主遂有汉中。秋，群下上先主为汉中王，表于汉帝。遂于沔阳设坛场，陈兵列众，群臣陪位，读奏讫，御王冠于先主。","translation":null,"mentionedPersonIds":["liu-bei","zhuge-liang","guan-yu","zhang-fei","ma-chao","huang-zhong","wei-yan"],"mentionedEventIds":["china-219-hanzhong-and-jingzhou-crisis"],"mentionedPlaceIds":["hanzhong","mianyang"],"tags":["汉中王","汉中","称王"],"confidence":"high","reviewStatus":"reviewed"}');
