INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-cao-zhang-death', 'sanguozhi-wei-cao-zhang', NULL, '三国志', '魏书', '任城威王彰传', '黄初四年', 223, '三年，立为任城王。四年，朝京都，疾薨于邸，谥曰威。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-cao-zhang-death","sourceId":"sanguozhi-wei-cao-zhang","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"任城威王彰传","locator":"黄初四年","year":223,"text":"三年，立为任城王。四年，朝京都，疾薨于邸，谥曰威。","translation":null,"mentionedPersonIds":["cao-zhang","cao-pi"],"mentionedEventIds":[],"mentionedPlaceIds":["luoyang"],"tags":["任城王","死亡","谥号"],"confidence":"high","reviewStatus":"reviewed"}');
