INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-cao-zhi-copper-terrace', 'sanguozhi-wei-cao-zhi', NULL, '三国志', '魏书', '陈思王植传', '邺铜雀台', 210, '时邺铜爵台新城，太祖悉将诸子登台，使各为赋。植援笔立成，可观，太祖甚异之。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-cao-zhi-copper-terrace","sourceId":"sanguozhi-wei-cao-zhi","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"陈思王植传","locator":"邺铜雀台","year":210,"text":"时邺铜爵台新城，太祖悉将诸子登台，使各为赋。植援笔立成，可观，太祖甚异之。","translation":null,"mentionedPersonIds":["cao-zhi","cao-cao"],"mentionedEventIds":[],"mentionedPlaceIds":["ye"],"tags":["铜雀台","赋","曹操赏识"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-cao-zhi-succession', 'sanguozhi-wei-cao-zhi', NULL, '三国志', '魏书', '陈思王植传', '建安二十二年前后', 217, '植旣以才见异，而丁仪、丁廙、杨修等为之羽翼。太祖狐疑，几为太子者数矣。而植任性而行，不自雕励，饮酒不节。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-cao-zhi-succession","sourceId":"sanguozhi-wei-cao-zhi","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"陈思王植传","locator":"建安二十二年前后","year":217,"text":"植旣以才见异，而丁仪、丁廙、杨修等为之羽翼。太祖狐疑，几为太子者数矣。而植任性而行，不自雕励，饮酒不节。","translation":null,"mentionedPersonIds":["cao-zhi","cao-cao","cao-pi"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["继承竞争","曹丕","曹植"],"confidence":"high","reviewStatus":"reviewed"}');
