INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-cao-zhi-death', 'sanguozhi-wei-cao-zhi', NULL, '三国志', '魏书', '陈思王植传', '太和六年', 232, '其二月，以陈四县封植为陈王，邑三千五百户。植每欲求别见独谈，论及时政，幸兾试用，终不能得。旣还，怅然绝望。遂发疾薨，时年四十一。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-cao-zhi-death","sourceId":"sanguozhi-wei-cao-zhi","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"陈思王植传","locator":"太和六年","year":232,"text":"其二月，以陈四县封植为陈王，邑三千五百户。植每欲求别见独谈，论及时政，幸兾试用，终不能得。旣还，怅然绝望。遂发疾薨，时年四十一。","translation":null,"mentionedPersonIds":["cao-zhi","cao-rui"],"mentionedEventIds":[],"mentionedPlaceIds":["chen"],"tags":["陈王","死亡","宗室处境"],"confidence":"high","reviewStatus":"reviewed"}');
