INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-qi-wang-235-qi-wang', 'sanguozhi-wei-qi-wang', NULL, '三国志', '魏书', '齐王纪', '青龙三年', 235, '青龙三年，立为齐王。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-qi-wang-235-qi-wang","sourceId":"sanguozhi-wei-qi-wang","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"齐王纪","locator":"青龙三年","year":235,"text":"青龙三年，立为齐王。","translation":null,"mentionedPersonIds":["cao-fang"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["齐王","宗室继嗣"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-qi-wang-239-enthroned', 'sanguozhi-wei-qi-wang', NULL, '三国志', '魏书', '齐王纪', '景初三年正月', 239, '景初三年正月丁亥朔，帝甚病，乃立为皇太子。是日，即皇帝位，大赦。尊皇后曰皇太后。大将军曹爽、太尉司马宣王辅政。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-qi-wang-239-enthroned","sourceId":"sanguozhi-wei-qi-wang","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"齐王纪","locator":"景初三年正月","year":239,"text":"景初三年正月丁亥朔，帝甚病，乃立为皇太子。是日，即皇帝位，大赦。尊皇后曰皇太后。大将军曹爽、太尉司马宣王辅政。","translation":null,"mentionedPersonIds":["cao-fang","cao-rui","cao-shuang","sima-yi"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["即位","辅政","曹爽","司马懿"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-qi-wang-249-gaopingling', 'sanguozhi-wei-qi-wang', NULL, '三国志', '魏书', '齐王纪', '嘉平元年春正月', 249, '嘉平元年春正月甲午，车驾谒高平陵。太傅司马宣王奏免大将军曹爽、爽弟中领军羲、武卫将军训、散骑常侍彦官，以侯就第。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-qi-wang-249-gaopingling","sourceId":"sanguozhi-wei-qi-wang","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"齐王纪","locator":"嘉平元年春正月","year":249,"text":"嘉平元年春正月甲午，车驾谒高平陵。太傅司马宣王奏免大将军曹爽、爽弟中领军羲、武卫将军训、散骑常侍彦官，以侯就第。","translation":null,"mentionedPersonIds":["cao-fang","cao-shuang","sima-yi"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["高平陵","司马氏","曹爽"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-qi-wang-254-deposed', 'sanguozhi-wei-qi-wang', NULL, '三国志', '魏书', '齐王纪', '嘉平六年九月', 254, '秋九月，大将军司马景王将谋废帝，以闻皇太后。甲戌，太后令曰：皇帝芳春秋已长，不亲万机……遣芳归藩于齐，以避皇位。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-qi-wang-254-deposed","sourceId":"sanguozhi-wei-qi-wang","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"齐王纪","locator":"嘉平六年九月","year":254,"text":"秋九月，大将军司马景王将谋废帝，以闻皇太后。甲戌，太后令曰：皇帝芳春秋已长，不亲万机……遣芳归藩于齐，以避皇位。","translation":null,"mentionedPersonIds":["cao-fang","cao-mao","empress-guo-mingyuan"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["废立","司马师","齐王"],"confidence":"high","reviewStatus":"reviewed"}');
