INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-gaogui-xianggong-254-enthroned', 'sanguozhi-wei-gaogui-xianggong', NULL, '三国志', '魏书', '高贵乡公纪', '正元元年十月', 254, '齐王废，公卿议迎立公。十月己丑，公至于玄武馆……其日即皇帝位于太极前殿。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-gaogui-xianggong-254-enthroned","sourceId":"sanguozhi-wei-gaogui-xianggong","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"高贵乡公纪","locator":"正元元年十月","year":254,"text":"齐王废，公卿议迎立公。十月己丑，公至于玄武馆……其日即皇帝位于太极前殿。","translation":null,"mentionedPersonIds":["cao-mao","cao-fang"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["即位","废立","洛阳"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-gaogui-xianggong-260-sima-zhao', 'sanguozhi-wei-gaogui-xianggong', NULL, '三国志', '魏书', '高贵乡公纪', '甘露五年五月', 260, '帝见威权日去，不胜其忿。乃召侍中王沈、尚书王经、散骑常侍王业，谓曰：“司马昭之心，路人所知也。吾不能坐受废辱，今日当与卿等自出讨之。”', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-gaogui-xianggong-260-sima-zhao","sourceId":"sanguozhi-wei-gaogui-xianggong","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"高贵乡公纪","locator":"甘露五年五月","year":260,"text":"帝见威权日去，不胜其忿。乃召侍中王沈、尚书王经、散骑常侍王业，谓曰：“司马昭之心，路人所知也。吾不能坐受废辱，今日当与卿等自出讨之。”","translation":null,"mentionedPersonIds":["cao-mao","sima-zhao"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["司马昭","王经","反抗"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-gaogui-xianggong-260-death', 'sanguozhi-wei-gaogui-xianggong', NULL, '三国志', '魏书', '高贵乡公纪', '甘露五年五月', 260, '中护军贾充又逆帝战于南阙下，帝自用剑。众欲退，太子舍人成济问充曰：“事急矣。当云何？”充曰：“畜养汝等，正谓今日。今日之事，无所问也。”济即前刺帝，刃出于背。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-gaogui-xianggong-260-death","sourceId":"sanguozhi-wei-gaogui-xianggong","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"高贵乡公纪","locator":"甘露五年五月","year":260,"text":"中护军贾充又逆帝战于南阙下，帝自用剑。众欲退，太子舍人成济问充曰：“事急矣。当云何？”充曰：“畜养汝等，正谓今日。今日之事，无所问也。”济即前刺帝，刃出于背。","translation":null,"mentionedPersonIds":["cao-mao","sima-zhao"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["被弑","贾充","成济"],"confidence":"high","reviewStatus":"reviewed"}');
