INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-cao-ren-219-fancheng', 'sanguozhi-wei-cao-ren', NULL, '三国志', '魏书', '曹仁传', '关羽攻樊', 219, '关羽攻樊，时汉水暴溢，于禁等七军皆没，禁降羽。仁人马数千人守城，城不没者数板……徐晃救至，水亦稍减，晃从外击羽，仁得溃围出，羽退走。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-cao-ren-219-fancheng","sourceId":"sanguozhi-wei-cao-ren","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"曹仁传","locator":"关羽攻樊","year":219,"text":"关羽攻樊，时汉水暴溢，于禁等七军皆没，禁降羽。仁人马数千人守城，城不没者数板……徐晃救至，水亦稍减，晃从外击羽，仁得溃围出，羽退走。","translation":null,"mentionedPersonIds":["cao-ren","guan-yu","yu-jin","xu-huang"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["襄樊","关羽","徐晃"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-cao-ren-222-grand-marshal', 'sanguozhi-wei-cao-ren', NULL, '三国志', '魏书', '曹仁传', '文帝时期', 222, '文帝遣使即拜仁大将军。又诏仁移屯临颍，迁大司马，复督诸军据乌江，还屯合肥。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-cao-ren-222-grand-marshal","sourceId":"sanguozhi-wei-cao-ren","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"曹仁传","locator":"文帝时期","year":222,"text":"文帝遣使即拜仁大将军。又诏仁移屯临颍，迁大司马，复督诸军据乌江，还屯合肥。","translation":null,"mentionedPersonIds":["cao-ren","cao-pi"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["大将军","大司马"],"confidence":"high","reviewStatus":"reviewed"}');
