INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-sgz-wei-cao-lin-donghai-record', 'sanguozhi-wei-cao-lin-donghai', NULL, '三国志', '魏书', '东海定王霖传', '本传', 222, '东海定王霖，黄初三年立为河东王。六年，改封馆陶县。明帝即位，以先帝遗意，爱宠霖异于诸国。而霖性粗暴，闺门之内，婢妾之间，多所残害。太和六年，改封东海。嘉平元年薨……高贵乡公髦，霖之子也，入继大宗。', NULL, 'high', 'reviewed', '{"id":"mention-sgz-wei-cao-lin-donghai-record","sourceId":"sanguozhi-wei-cao-lin-donghai","workTitle":"三国志","bookTitle":"魏书","chapterTitle":"东海定王霖传","locator":"本传","year":222,"text":"东海定王霖，黄初三年立为河东王。六年，改封馆陶县。明帝即位，以先帝遗意，爱宠霖异于诸国。而霖性粗暴，闺门之内，婢妾之间，多所残害。太和六年，改封东海。嘉平元年薨……高贵乡公髦，霖之子也，入继大宗。","translation":null,"mentionedPersonIds":["cao-lin-donghai","cao-cao"],"mentionedEventIds":[],"mentionedPlaceIds":[],"tags":["宗室","封国","武文世王公传"],"confidence":"high","reviewStatus":"reviewed"}');
