INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-zztj-75-249-gaopingling', 'zizhi-tongjian-75', NULL, '资治通鉴', '魏纪七', '邵陵厉公中', '嘉平元年春正月甲午', 249, '春，正月，甲午，帝谒高平陵，大将军爽与弟中领军羲、武卫将军训、散骑常侍彦皆从。太傅懿以皇太后令，闭诸城门，勒兵据武库。', NULL, 'high', 'reviewed', '{"id":"mention-zztj-75-249-gaopingling","sourceId":"zizhi-tongjian-75","workTitle":"资治通鉴","bookTitle":"魏纪七","chapterTitle":"邵陵厉公中","locator":"嘉平元年春正月甲午","year":249,"text":"春，正月，甲午，帝谒高平陵，大将军爽与弟中领军羲、武卫将军训、散骑常侍彦皆从。太傅懿以皇太后令，闭诸城门，勒兵据武库。","personIds":["cao-fang","cao-shuang","sima-yi"],"placeIds":["gaopingling","luoyang"],"tags":["高平陵","曹爽","司马懿"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-zztj-75-249-cao-shuang-death', 'zizhi-tongjian-75', NULL, '资治通鉴', '魏纪七', '邵陵厉公中', '嘉平元年正月戊戌', 249, '于是收爽、羲、训、晏、颺、谧、轨、胜并桓范皆下狱，劾以大逆不道，与张当俱夷三族。', NULL, 'high', 'reviewed', '{"id":"mention-zztj-75-249-cao-shuang-death","sourceId":"zizhi-tongjian-75","workTitle":"资治通鉴","bookTitle":"魏纪七","chapterTitle":"邵陵厉公中","locator":"嘉平元年正月戊戌","year":249,"text":"于是收爽、羲、训、晏、颺、谧、轨、胜并桓范皆下狱，劾以大逆不道，与张当俱夷三族。","personIds":["cao-shuang","sima-yi"],"placeIds":["luoyang"],"tags":["高平陵","伏诛","司马氏"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-zztj-75-249-wang-ling-cao-biao-plot', 'zizhi-tongjian-75', NULL, '资治通鉴', '魏纪七', '邵陵厉公中', '嘉平元年秋九月', 249, '凌与愚阴谋，以帝暗弱，制于强臣，闻楚王彪有智勇，欲共立之，迎都许昌。', NULL, 'high', 'reviewed', '{"id":"mention-zztj-75-249-wang-ling-cao-biao-plot","sourceId":"zizhi-tongjian-75","workTitle":"资治通鉴","bookTitle":"魏纪七","chapterTitle":"邵陵厉公中","locator":"嘉平元年秋九月","year":249,"text":"凌与愚阴谋，以帝暗弱，制于强臣，闻楚王彪有智勇，欲共立之，迎都许昌。","personIds":["wang-ling","cao-biao","cao-fang","sima-yi"],"placeIds":["xuchang"],"tags":["王凌案","曹彪","废立"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-zztj-75-251-wang-ling-death', 'zizhi-tongjian-75', NULL, '资治通鉴', '魏纪七', '邵陵厉公中', '嘉平三年五月甲寅', 251, '凌试索棺钉以观懿意，懿命给之。五月，甲寅，凌行到项，遂饮药死。', NULL, 'high', 'reviewed', '{"id":"mention-zztj-75-251-wang-ling-death","sourceId":"zizhi-tongjian-75","workTitle":"资治通鉴","bookTitle":"魏纪七","chapterTitle":"邵陵厉公中","locator":"嘉平三年五月甲寅","year":251,"text":"凌试索棺钉以观懿意，懿命给之。五月，甲寅，凌行到项，遂饮药死。","personIds":["wang-ling","sima-yi"],"placeIds":["shouchun"],"tags":["王凌案","淮南","死亡"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-zztj-75-251-cao-biao-death', 'zizhi-tongjian-75', NULL, '资治通鉴', '魏纪七', '邵陵厉公中', '嘉平三年六月', 251, '六月，赐楚王彪死。尽录诸王公置邺，使有司察之，不得与人交关。', NULL, 'high', 'reviewed', '{"id":"mention-zztj-75-251-cao-biao-death","sourceId":"zizhi-tongjian-75","workTitle":"资治通鉴","bookTitle":"魏纪七","chapterTitle":"邵陵厉公中","locator":"嘉平三年六月","year":251,"text":"六月，赐楚王彪死。尽录诸王公置邺，使有司察之，不得与人交关。","personIds":["cao-biao","wang-ling"],"placeIds":["ye"],"tags":["王凌案","曹彪","宗室管控"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-zztj-76-254-cao-fang-deposed', 'zizhi-tongjian-76', NULL, '资治通鉴', '魏纪八', '高贵乡公上', '正元元年九月甲戌', 254, '昭引兵入城，大将军师乃谋废帝。甲戌，师以皇太后令召群臣会议，以帝荒淫无度，亵近倡优，不可以承天绪。', NULL, 'high', 'reviewed', '{"id":"mention-zztj-76-254-cao-fang-deposed","sourceId":"zizhi-tongjian-76","workTitle":"资治通鉴","bookTitle":"魏纪八","chapterTitle":"高贵乡公上","locator":"正元元年九月甲戌","year":254,"text":"昭引兵入城，大将军师乃谋废帝。甲戌，师以皇太后令召群臣会议，以帝荒淫无度，亵近倡优，不可以承天绪。","personIds":["cao-fang","cao-mao"],"placeIds":["luoyang"],"tags":["废立","司马师","曹芳"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-zztj-77-260-cao-mao-sima-zhao', 'zizhi-tongjian-77', NULL, '资治通鉴', '魏纪九', '高贵乡公下', '景元元年五月己丑', 260, '帝见威权日去，不胜其忿。五月，己丑，召侍中王沈、尚书王经、散骑常侍王业，谓曰：“司马昭之心，路人所知也。”', NULL, 'high', 'reviewed', '{"id":"mention-zztj-77-260-cao-mao-sima-zhao","sourceId":"zizhi-tongjian-77","workTitle":"资治通鉴","bookTitle":"魏纪九","chapterTitle":"高贵乡公下","locator":"景元元年五月己丑","year":260,"text":"帝见威权日去，不胜其忿。五月，己丑，召侍中王沈、尚书王经、散骑常侍王业，谓曰：“司马昭之心，路人所知也。”","personIds":["cao-mao","sima-zhao"],"placeIds":["luoyang"],"tags":["司马昭","曹髦","反抗"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-zztj-77-260-cao-mao-death', 'zizhi-tongjian-77', NULL, '资治通鉴', '魏纪九', '高贵乡公下', '景元元年五月己丑', 260, '中护军贾充自外入，逆与帝战于南阙下。济即抽戈前刺帝，殒于车下。', NULL, 'high', 'reviewed', '{"id":"mention-zztj-77-260-cao-mao-death","sourceId":"zizhi-tongjian-77","workTitle":"资治通鉴","bookTitle":"魏纪九","chapterTitle":"高贵乡公下","locator":"景元元年五月己丑","year":260,"text":"中护军贾充自外入，逆与帝战于南阙下。济即抽戈前刺帝，殒于车下。","personIds":["cao-mao","sima-zhao"],"placeIds":["luoyang"],"tags":["曹髦被弑","贾充","成济"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-zztj-78-263-shu-surrender', 'zizhi-tongjian-78', NULL, '资治通鉴', '魏纪十', '元皇帝下', '景元四年冬十月', 263, '汉主乃遣侍中张绍等奉玺绶以降于艾。艾至成都城北，汉主率太子诸王及群臣六十余人，面缚舆榇诣军门。', NULL, 'high', 'reviewed', '{"id":"mention-zztj-78-263-shu-surrender","sourceId":"zizhi-tongjian-78","workTitle":"资治通鉴","bookTitle":"魏纪十","chapterTitle":"元皇帝下","locator":"景元四年冬十月","year":263,"text":"汉主乃遣侍中张绍等奉玺绶以降于艾。艾至成都城北，汉主率太子诸王及群臣六十余人，面缚舆榇诣军门。","personIds":["liu-shan","deng-ai","zhong-hui","cao-huan"],"eventIds":["china-263-shu-han-conquered"],"placeIds":["chengdu"],"tags":["灭蜀","邓艾","刘禅"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('mention-zztj-78-264-zhong-hui-deng-ai', 'zizhi-tongjian-78', NULL, '资治通鉴', '魏纪十', '元皇帝下', '咸熙元年正月', 264, '争前杀会。会将士死者数百人。邓艾本营将士追出艾于槛车，迎还。卫瓘乃遣护军田续等将兵袭艾，遇于绵竹西，斩艾父子。', NULL, 'high', 'reviewed', '{"id":"mention-zztj-78-264-zhong-hui-deng-ai","sourceId":"zizhi-tongjian-78","workTitle":"资治通鉴","bookTitle":"魏纪十","chapterTitle":"元皇帝下","locator":"咸熙元年正月","year":264,"text":"争前杀会。会将士死者数百人。邓艾本营将士追出艾于槛车，迎还。卫瓘乃遣护军田续等将兵袭艾，遇于绵竹西，斩艾父子。","personIds":["zhong-hui","deng-ai","jiang-wei"],"eventIds":["china-263-shu-han-conquered"],"placeIds":["chengdu","mianzhu"],"tags":["钟会之乱","邓艾","成都"],"confidence":"high","reviewStatus":"reviewed"}');
INSERT INTO "source_mentions" ("id", "source_id", "passage_id", "work_title", "book_title", "chapter_title", "locator", "year", "text", "translation", "confidence", "review_status", "raw_json") VALUES ('sasanian-ancient:shkz-royal-genealogy', 'deepseek-sasanian-source-s-kz-res-gestae-divi-saporis-shapur-i-kaba-ye-zardosht-trilingual-inscri', NULL, 'ŠKZ / Res Gestae Divi Saporis', '', 'royal genealogy and titulature', 'opening genealogy', 240, 'Shapur identifies himself through Ardashir and Papak and frames the dynasty with royal titulature.', '沙普尔一世铭文开篇以阿尔达希尔、帕帕克等谱系和王号说明王权来源，这是早期萨珊王朝自我合法化的核心材料。', 'high', 'reviewed', '{"id":"sasanian-ancient:shkz-royal-genealogy","cardId":"shkz-royal-genealogy","importedFromBatch":"manual-sasanian-ancient-knowledge-190-310","regionId":"sasanian-persia","periodId":"sasanian-persia-224-310","topicId":"political_structure","peopleCore":["sasanian-ardashir-i","sasanian-shapur-i"],"eventIds":[],"tags":["inscription","royal-legitimacy","genealogy"],"interpretation":"这不是传记，而是王权声明。它能支撑阿尔达希尔一世、沙普尔一世的继承关系和萨珊王号变化。","disputeNote":"铭文是王室自我叙述，合法化意图很强；具体继承细节仍需钱币和后期叙事互证。"}');
