INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-190-coalition', 'cao-cao', 190, NULL, '190', 'campaign', '参加关东讨董', '曹操参与关东诸军讨董，虽兵力不大，却在汉末群雄政治舞台上开始形成独立军事声望。', 'high', 0, '{"id":"cao-cao-190-coalition","personId":"cao-cao","year":190,"displayYear":"190","type":"campaign","title":"参加关东讨董","summary":"曹操参与关东诸军讨董，虽兵力不大，却在汉末群雄政治舞台上开始形成独立军事声望。","relatedEventIds":["china-190-coalition-against-dong-zhuo"],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-coalition"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"初平元年","quote":"初平元年春正月，后将军袁术、冀州牧韩馥等同时俱起兵，众各数万，推绍为盟主。太祖行奋武将军。"},{"sourceId":"zizhi-tongjian-59","locator":"初平元年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-194-yanzhou-crisis', 'cao-cao', 194, NULL, '194-195', 'campaign', '兖州根据地危机', '吕布、陈宫等袭取兖州多地，曹操一度只保有少数城邑，早期根据地几近崩溃。', 'high', 0, '{"id":"cao-cao-194-yanzhou-crisis","personId":"cao-cao","year":194,"displayYear":"194-195","type":"campaign","title":"兖州根据地危机","summary":"吕布、陈宫等袭取兖州多地，曹操一度只保有少数城邑，早期根据地几近崩溃。","relatedEventIds":["china-194-lu-bu-seizes-yan"],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-yanzhou-crisis"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"兴平元年至二年","quote":"会张邈与陈宫叛迎吕布，郡县皆应。荀彧、程昱保鄄城，范、东阿二县固守，太祖乃引军还。"},{"sourceId":"sanguozhi-wei-lubu","locator":"吕布传"}]}');
