INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-200-guandu', 'cao-cao', 200, NULL, '200', 'campaign', '官渡击败袁绍', '曹操在兵力劣势下守官渡、袭乌巢，扭转北方格局。', 'high', 0, '{"id":"cao-cao-200-guandu","personId":"cao-cao","year":200,"displayYear":"200","type":"campaign","title":"官渡击败袁绍","summary":"曹操在兵力劣势下守官渡、袭乌巢，扭转北方格局。","relatedEventIds":["china-200-guandu"],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-guandu"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安五年","quote":"公乃留曹洪守，自将步骑五千人夜往，会明至。公急击之，琼退保营，遂攻之。"},{"sourceId":"zizhi-tongjian-63","locator":"建安五年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-204-hebei', 'cao-cao', 204, NULL, '204-207', 'campaign', '平定袁氏河北余部', '官渡之后，曹操继续北攻袁谭、袁尚等袁氏残余，并向乌桓方向推进，北方统一格局逐渐完成。', 'medium', 0, '{"id":"cao-cao-204-hebei","personId":"cao-cao","year":204,"displayYear":"204-207","type":"campaign","title":"平定袁氏河北余部","summary":"官渡之后，曹操继续北攻袁谭、袁尚等袁氏残余，并向乌桓方向推进，北方统一格局逐渐完成。","relatedEventIds":["china-200-guandu"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安九年至十二年","quote":"八月，审配兄子荣夜开所守城东门内兵。配逆战，败，生禽配，斩之，邺定。"},{"sourceId":"zizhi-tongjian-63","locator":"河北战事延续"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-208-red-cliffs', 'cao-cao', 208, NULL, '208', 'campaign', '赤壁失利', '曹操南下荆州后在长江中游受挫，迅速统一南方的计划失败。', 'high', 0, '{"id":"cao-cao-208-red-cliffs","personId":"cao-cao","year":208,"displayYear":"208","type":"campaign","title":"赤壁失利","summary":"曹操南下荆州后在长江中游受挫，迅速统一南方的计划失败。","relatedEventIds":["china-208-red-cliffs"],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-red-cliffs"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安十三年","quote":"公至赤壁，与备战，不利。于是大疫，吏士多死者，乃引军还。"},{"sourceId":"zizhi-tongjian-65","locator":"建安十三年"}]}');
