INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-215-hanzhong', 'cao-cao', 215, NULL, '215', 'campaign', '取汉中，张鲁归降', '曹操西征汉中，张鲁归降，汉中一度纳入曹操控制，也让曹刘争夺益州北部门户的矛盾激化。', 'high', 0, '{"id":"cao-cao-215-hanzhong","personId":"cao-cao","year":215,"displayYear":"215","type":"campaign","title":"取汉中，张鲁归降","summary":"曹操西征汉中，张鲁归降，汉中一度纳入曹操控制，也让曹刘争夺益州北部门户的矛盾激化。","relatedEventIds":["china-215-cao-cao-takes-hanzhong"],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-hanzhong"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安二十年","quote":"公军入南郑，尽得鲁府库珍宝。巴、汉皆降。复汉宁郡为汉中。"},{"sourceId":"sanguozhi-wei-zhang-lu","locator":"张鲁传"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-216-king-wei', 'cao-cao', 216, NULL, '216', 'office', '进爵魏王', '曹操由魏公进爵魏王，曹氏政权制度化程度进一步提高，为曹丕代汉奠定政治结构。', 'high', 0, '{"id":"cao-cao-216-king-wei","personId":"cao-cao","year":216,"displayYear":"216","type":"office","title":"进爵魏王","summary":"曹操由魏公进爵魏王，曹氏政权制度化程度进一步提高，为曹丕代汉奠定政治结构。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-king-wei"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安二十一年","quote":"夏五月，天子进公爵为魏王。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-219-hanzhong-retreat', 'cao-cao', 219, NULL, '219', 'campaign', '汉中退兵与荆州压力', '刘备夺取汉中后称汉中王，关羽又在荆州北伐襄樊，曹操集团同时承受西线和南线压力。', 'high', 0, '{"id":"cao-cao-219-hanzhong-retreat","personId":"cao-cao","year":219,"displayYear":"219","type":"campaign","title":"汉中退兵与荆州压力","summary":"刘备夺取汉中后称汉中王，关羽又在荆州北伐襄樊，曹操集团同时承受西线和南线压力。","relatedEventIds":["china-219-hanzhong-and-jingzhou-crisis"],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-hanzhong-retreat"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安二十四年","quote":"秋七月，以夫人卞氏为王后。遣于禁助曹仁击关羽。八月，汉水溢，灌禁军，军没，羽获禁，遂围仁。"},{"sourceId":"zizhi-tongjian-67","locator":"建安二十四年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-220-death', 'cao-cao', 220, NULL, '220', 'death', '曹操去世', '曹操去世后，曹丕继承魏王位并在同年完成代汉。', 'high', 0, '{"id":"cao-cao-220-death","personId":"cao-cao","year":220,"displayYear":"220","type":"death","title":"曹操去世","summary":"曹操去世后，曹丕继承魏王位并在同年完成代汉。","relatedEventIds":["china-220-cao-pi-founds-wei"],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安二十五年","quote":"庚子，王崩于洛阳，年六十六。遗令曰：“天下尚未安定，未得遵古也。”"}]}');
