INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('liu-bei-194-xuzhou', 'liu-bei', 194, NULL, '194-196', 'turning-point', '入徐州并接掌州事', '陶谦迎刘备入徐州，陶谦死后刘备一度接掌徐州，这是他第一次拥有较完整的州级政治基础。', 'high', 0, '{"id":"liu-bei-194-xuzhou","personId":"liu-bei","year":194,"displayYear":"194-196","type":"turning-point","title":"入徐州并接掌州事","summary":"陶谦迎刘备入徐州，陶谦死后刘备一度接掌徐州，这是他第一次拥有较完整的州级政治基础。","relatedEventIds":["china-194-tao-qian-yields-xuzhou"],"sourceMentionIds":["mention-sgz-shu-xianzhu-liu-bei-xuzhou"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-shu-xianzhu","locator":"陶谦迎先主入徐州","quote":"孔融谓先主曰：“袁公路岂忧国忘家者邪？冢中枯骨，何足介意。”先主遂领徐州。"},{"sourceId":"zizhi-tongjian-59","locator":"兴平元年至建安元年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('liu-bei-199-xiapi', 'liu-bei', 199, NULL, '199', 'campaign', '协曹攻吕布后失徐州基础', '刘备与曹操共同击败吕布，但徐州格局很快转向曹操主导，刘备再次进入流动依附和再起阶段。', 'high', 0, '{"id":"liu-bei-199-xiapi","personId":"liu-bei","year":199,"displayYear":"199","type":"campaign","title":"协曹攻吕布后失徐州基础","summary":"刘备与曹操共同击败吕布，但徐州格局很快转向曹操主导，刘备再次进入流动依附和再起阶段。","relatedEventIds":["china-199-lu-bu-defeated"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-shu-xianzhu","locator":"建安三年至四年","quote":"先主复得妻子，从曹公还许。表先主为左将军，礼之愈重，出则同舆，坐则同席。"},{"sourceId":"sanguozhi-wei-lubu","locator":"吕布传下邳败亡"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('liu-bei-201-jingzhou', 'liu-bei', 201, NULL, '201-207', 'service', '依附刘表，屯驻荆州北部', '官渡后刘备转入荆州，依附刘表并屯驻新野等地，为后来联吴抗曹和取荆益二州留下空间。', 'high', 0, '{"id":"liu-bei-201-jingzhou","personId":"liu-bei","year":201,"displayYear":"201-207","type":"service","title":"依附刘表，屯驻荆州北部","summary":"官渡后刘备转入荆州，依附刘表并屯驻新野等地，为后来联吴抗曹和取荆益二州留下空间。","relatedEventIds":["china-207-longzhong-plan"],"sourceMentionIds":["mention-sgz-shu-xianzhu-liu-bei-jingzhou"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-shu-xianzhu","locator":"依刘表居新野","quote":"先主遣麋竺、孙乾与刘表相闻，表自郊迎，以上宾礼待之，益其兵，使屯新野。"},{"sourceId":"zizhi-tongjian-65","locator":"建安十三年前荆州形势"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('liu-bei-207-longzhong', 'liu-bei', 207, NULL, '207', 'strategy', '三顾诸葛亮，隆中对成形', '刘备拜访诸葛亮并获得跨荆、益二州的战略规划，集团路线由此清晰化。', 'high', 0, '{"id":"liu-bei-207-longzhong","personId":"liu-bei","year":207,"displayYear":"207","type":"strategy","title":"三顾诸葛亮，隆中对成形","summary":"刘备拜访诸葛亮并获得跨荆、益二州的战略规划，集团路线由此清晰化。","relatedEventIds":["china-207-longzhong-plan"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-shu-xianzhu","locator":"三顾与隆中相关记载"},{"sourceId":"sanguozhi-shu-zhuge-liang","locator":"诸葛亮传","quote":"徐庶曰：“此人可就见，不可屈致也。将军宜枉驾顾之。”由是先主遂诣亮，凡三往，乃见。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('liu-bei-208-red-cliffs', 'liu-bei', 208, NULL, '208', 'campaign', '参与孙刘联盟抗曹', '刘备在长坂后南撤，并与孙权集团联合抗曹，赤壁后获得重新立足的机会。', 'high', 0, '{"id":"liu-bei-208-red-cliffs","personId":"liu-bei","year":208,"displayYear":"208","type":"campaign","title":"参与孙刘联盟抗曹","summary":"刘备在长坂后南撤，并与孙权集团联合抗曹，赤壁后获得重新立足的机会。","relatedEventIds":["china-208-red-cliffs"],"sourceMentionIds":["mention-sgz-shu-xianzhu-liu-bei-red-cliffs"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-shu-xianzhu","locator":"建安十三年","quote":"与曹公战于赤壁，大破之，焚其舟船。先主与吴军水陆并进，追到南郡。"},{"sourceId":"sanguozhi-wu-zhou-yu","locator":"周瑜、鲁肃传赤壁相关记载"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('liu-bei-214-yi', 'liu-bei', 214, NULL, '214', 'turning-point', '入主益州', '刘备击败刘璋并占据益州，获得建立蜀汉的根本根据地。', 'high', 0, '{"id":"liu-bei-214-yi","personId":"liu-bei","year":214,"displayYear":"214","type":"turning-point","title":"入主益州","summary":"刘备击败刘璋并占据益州，获得建立蜀汉的根本根据地。","relatedEventIds":["china-214-liu-bei-takes-yi"],"sourceMentionIds":["mention-sgz-shu-xianzhu-liu-bei-yizhou"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-shu-xianzhu","locator":"取益州相关记载","quote":"先主遣人迎超，超将兵径到城下。城中震怖，璋即稽服。"},{"sourceId":"zizhi-tongjian-67","locator":"建安十九年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('liu-bei-219-hanzhong-king', 'liu-bei', 219, NULL, '219', 'politics', '夺汉中后称汉中王', '汉中战事获胜后，刘备称汉中王，蜀汉建国前的政治形态基本成形。', 'high', 0, '{"id":"liu-bei-219-hanzhong-king","personId":"liu-bei","year":219,"displayYear":"219","type":"politics","title":"夺汉中后称汉中王","summary":"汉中战事获胜后，刘备称汉中王，蜀汉建国前的政治形态基本成形。","relatedEventIds":["china-219-hanzhong-and-jingzhou-crisis"],"sourceMentionIds":["mention-sgz-shu-xianzhu-liu-bei-hanzhong-king"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-shu-xianzhu","locator":"建安二十四年称汉中王","quote":"秋，群下上先主为汉中王，表于汉帝。"},{"sourceId":"zizhi-tongjian-67","locator":"建安二十四年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('liu-bei-221-emperor', 'liu-bei', 221, NULL, '221', 'politics', '称帝建立蜀汉', '曹魏代汉后，刘备在成都称帝，以延续汉统为政治号召。', 'high', 0, '{"id":"liu-bei-221-emperor","personId":"liu-bei","year":221,"displayYear":"221","type":"politics","title":"称帝建立蜀汉","summary":"曹魏代汉后，刘备在成都称帝，以延续汉统为政治号召。","relatedEventIds":["china-221-liu-bei-founds-shu"],"sourceMentionIds":["mention-sgz-shu-xianzhu-liu-bei-emperor"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-shu-xianzhu","locator":"章武元年","quote":"章武元年夏四月，大赦，改年。以诸葛亮为丞相，许靖为司徒。置百官，立宗庙。"},{"sourceId":"zizhi-tongjian-69","locator":"章武元年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('liu-bei-222-yiling', 'liu-bei', 222, NULL, '222', 'campaign', '夷陵败退', '刘备东征孙吴以争夺荆州旧地，被陆逊在夷陵一线击败，蜀汉外向扩张能力受到沉重打击。', 'high', 0, '{"id":"liu-bei-222-yiling","personId":"liu-bei","year":222,"displayYear":"222","type":"campaign","title":"夷陵败退","summary":"刘备东征孙吴以争夺荆州旧地，被陆逊在夷陵一线击败，蜀汉外向扩张能力受到沉重打击。","relatedEventIds":["china-222-yiling"],"sourceMentionIds":["mention-sgz-shu-xianzhu-liu-bei-yiling"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-shu-xianzhu","locator":"章武二年夷陵败绩","quote":"陆议大破先主军于猇亭，将军冯习、张南等皆没。先主自猇亭还秭归，收合离散兵。"},{"sourceId":"zizhi-tongjian-70","locator":"黄武元年 / 章武二年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('liu-bei-223-death', 'liu-bei', 223, NULL, '223', 'death', '白帝城托孤后去世', '夷陵失败后，刘备退至永安，临终托孤诸葛亮，蜀汉进入刘禅与诸葛亮辅政阶段。', 'high', 0, '{"id":"liu-bei-223-death","personId":"liu-bei","year":223,"displayYear":"223","type":"death","title":"白帝城托孤后去世","summary":"夷陵失败后，刘备退至永安，临终托孤诸葛亮，蜀汉进入刘禅与诸葛亮辅政阶段。","relatedEventIds":["china-222-yiling"],"sourceMentionIds":["mention-sgz-shu-xianzhu-liu-bei-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-shu-xianzhu","locator":"章武三年","quote":"先主病笃，托孤于丞相亮，尚书令李严为副。夏四月癸巳，先主殂于永安宫，时年六十三。"}]}');
