INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('sun-quan-182-born', 'sun-quan', 182, NULL, '182', 'birth', '孙权出生', '孙权为孙坚之子、孙策之弟，后继承江东基业。', 'high', 0, '{"id":"sun-quan-182-born","personId":"sun-quan","year":182,"displayYear":"182","type":"birth","title":"孙权出生","summary":"孙权为孙坚之子、孙策之弟，后继承江东基业。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wu-wuzhu-sun-quan-origin"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wu-wuzhu","locator":"吴主传","quote":"孙权字仲谋。兄策既定诸郡，时权年十五，以为阳羡长。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('sun-quan-200-succeeds-jiangdong', 'sun-quan', 200, NULL, '200', 'turning-point', '继承江东基业', '孙策遇刺后，孙权继承江东，依托张昭、周瑜等旧臣稳定内部，完成从继承者到统治者的过渡。', 'high', 0, '{"id":"sun-quan-200-succeeds-jiangdong","personId":"sun-quan","year":200,"displayYear":"200","type":"turning-point","title":"继承江东基业","summary":"孙策遇刺后，孙权继承江东，依托张昭、周瑜等旧臣稳定内部，完成从继承者到统治者的过渡。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wu-wuzhu-sun-quan-succeeds"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wu-wuzhu","locator":"建安五年孙策卒后","quote":"五年，策薨，以事授权，权哭未及息。张昭谓权曰：“此宁哭时邪？”乃改易权服，扶令上马，使出巡军。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('sun-quan-208-red-cliffs', 'sun-quan', 208, NULL, '208', 'politics', '决策抗曹并形成孙刘联盟', '曹操南下时，孙权接受周瑜、鲁肃等抗曹意见，与刘备集团联合。', 'high', 0, '{"id":"sun-quan-208-red-cliffs","personId":"sun-quan","year":208,"displayYear":"208","type":"politics","title":"决策抗曹并形成孙刘联盟","summary":"曹操南下时，孙权接受周瑜、鲁肃等抗曹意见，与刘备集团联合。","relatedEventIds":["china-208-red-cliffs"],"sourceMentionIds":["mention-sgz-wu-wuzhu-sun-quan-red-cliffs"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wu-wuzhu","locator":"建安十三年","quote":"惟瑜、肃执拒之议，意与权同。瑜、普为左右督，各领万人，与备俱进，遇于赤壁，大破曹公军。"},{"sourceId":"sanguozhi-wu-zhou-yu","locator":"周瑜、鲁肃传赤壁相关记载"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('sun-quan-215-hefei', 'sun-quan', 215, NULL, '215', 'campaign', '合肥受挫', '孙权北攻合肥未能突破曹魏江淮防线，显示江东虽能守长江，却很难稳定向淮北推进。', 'high', 0, '{"id":"sun-quan-215-hefei","personId":"sun-quan","year":215,"displayYear":"215","type":"campaign","title":"合肥受挫","summary":"孙权北攻合肥未能突破曹魏江淮防线，显示江东虽能守长江，却很难稳定向淮北推进。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wu-wuzhu-sun-quan-hefei"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wu-wuzhu","locator":"建安二十年合肥相关记载","quote":"合肥未下，彻军还。兵皆就路，权与凌统、甘宁等在津北为魏将张辽所袭，统等以死捍权，权乘骏马越津桥得去。"},{"sourceId":"zizhi-tongjian-67","locator":"建安二十年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('sun-quan-219-jingzhou', 'sun-quan', 219, NULL, '219', 'campaign', '袭取荆州，孙刘关系破裂', '孙权命吕蒙等袭取关羽后方，夺回荆州要地，赤壁以来的孙刘联盟由合作转为公开对抗。', 'high', 0, '{"id":"sun-quan-219-jingzhou","personId":"sun-quan","year":219,"displayYear":"219","type":"campaign","title":"袭取荆州，孙刘关系破裂","summary":"孙权命吕蒙等袭取关羽后方，夺回荆州要地，赤壁以来的孙刘联盟由合作转为公开对抗。","relatedEventIds":["china-219-hanzhong-and-jingzhou-crisis"],"sourceMentionIds":["mention-sgz-wu-wuzhu-sun-quan-jingzhou"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wu-wuzhu","locator":"建安二十四年","quote":"闰月，权征羽，先遣吕蒙袭公安，获将军士仁。蒙到南郡，南郡太守麋芳以城降。"},{"sourceId":"sanguozhi-wu-zhou-yu","locator":"吕蒙传荆州相关记载"},{"sourceId":"zizhi-tongjian-67","locator":"建安二十四年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('sun-quan-222-king-wu', 'sun-quan', 222, NULL, '222', 'politics', '受封吴王并稳住荆州', '夷陵战后孙权在吴、蜀、魏之间调整外交位置，一面接受魏封吴王，一面巩固荆州与江东防线。', 'high', 0, '{"id":"sun-quan-222-king-wu","personId":"sun-quan","year":222,"displayYear":"222","type":"politics","title":"受封吴王并稳住荆州","summary":"夷陵战后孙权在吴、蜀、魏之间调整外交位置，一面接受魏封吴王，一面巩固荆州与江东防线。","relatedEventIds":["china-222-yiling"],"sourceMentionIds":["mention-sgz-wu-wuzhu-sun-quan-king-wu"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wu-wuzhu","locator":"黄武元年","quote":"黄武元年春正月，陆逊部将军宋谦等攻蜀五屯，皆破之，斩其将。"},{"sourceId":"zizhi-tongjian-70","locator":"黄武元年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('sun-quan-226-jiaozhou', 'sun-quan', 226, NULL, '226', 'politics', '交州士氏独立地位削弱', '士燮去世后，孙吴加强对交州的任命和军事处置，岭南从士氏名义臣属转向更直接的孙吴经营。', 'medium', 0, '{"id":"sun-quan-226-jiaozhou","personId":"sun-quan","year":226,"displayYear":"226","type":"politics","title":"交州士氏独立地位削弱","summary":"士燮去世后，孙吴加强对交州的任命和军事处置，岭南从士氏名义臣属转向更直接的孙吴经营。","relatedEventIds":["china-226-jiaozhou-incorporated-by-wu"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wu-shi-xie","locator":"士燮传黄武五年"},{"sourceId":"sanguozhi-wu-lu-dai","locator":"吕岱传交州相关记载"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('sun-quan-229-emperor', 'sun-quan', 229, NULL, '229', 'politics', '称帝建立孙吴', '孙权称帝，孙吴正式与曹魏、蜀汉并列为三国政权。', 'high', 0, '{"id":"sun-quan-229-emperor","personId":"sun-quan","year":229,"displayYear":"229","type":"politics","title":"称帝建立孙吴","summary":"孙权称帝，孙吴正式与曹魏、蜀汉并列为三国政权。","relatedEventIds":["china-229-sun-quan-emperor"],"sourceMentionIds":["mention-sgz-wu-wuzhu-sun-quan-emperor"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wu-wuzhu","locator":"黄龙元年","quote":"黄龙元年春，公卿百司皆劝权正尊号。夏四月，夏口、武昌并言黄龙、凤凰见。丙申，南郊即皇帝位。"},{"sourceId":"zizhi-tongjian-69","locator":"黄龙元年"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('sun-quan-252-death', 'sun-quan', 252, NULL, '252', 'death', '吴大帝去世', '孙权去世后，孙吴进入宗室与权臣政治更替频繁的阶段。', 'high', 0, '{"id":"sun-quan-252-death","personId":"sun-quan","year":252,"displayYear":"252","type":"death","title":"吴大帝去世","summary":"孙权去世后，孙吴进入宗室与权臣政治更替频繁的阶段。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wu-wuzhu-sun-quan-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wu-wuzhu","locator":"吴主传","quote":"夏四月，权薨，时年七十一，谥曰大皇帝。秋七月，葬蒋陵。"}]}');
