INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('shi-xie-210-submits-wu', 'shi-xie', 210, NULL, '210', 'politics', '向孙权奉承节度', '孙权遣步骘为交州刺史，士燮率兄弟接受节度，并以贡纳、子弟入质维持与江东的名义关系。', 'high', 0, '{"id":"shi-xie-210-submits-wu","personId":"shi-xie","year":210,"displayYear":"210","type":"politics","title":"向孙权奉承节度","summary":"孙权遣步骘为交州刺史，士燮率兄弟接受节度，并以贡纳、子弟入质维持与江东的名义关系。","relatedEventIds":[],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wu-shi-xie","locator":"建安十五年前后","quote":"建安十五年，孙权遣步隲为交州刺史。隲到，燮率兄弟奉承节度。"}]}');
