INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-174-xiaolian', 'cao-cao', 174, NULL, '约174', 'office', '举孝廉，任洛阳北部尉', '曹操二十岁左右举孝廉入仕，历任郎、洛阳北部尉、顿丘令，进入东汉官僚体系。', 'medium', 0, '{"id":"cao-cao-174-xiaolian","personId":"cao-cao","year":174,"displayYear":"约174","type":"office","title":"举孝廉，任洛阳北部尉","summary":"曹操二十岁左右举孝廉入仕，历任郎、洛阳北部尉、顿丘令，进入东汉官僚体系。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-xiaolian"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"年二十","quote":"年二十，举孝廉为郎，除洛阳北部尉，迁顿丘令。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-184-yellow-turban', 'cao-cao', 184, NULL, '184', 'campaign', '讨黄巾，转任济南相', '黄巾起义爆发后，曹操以骑都尉讨颍川黄巾，随后出任济南相，开始积累地方治理声望。', 'high', 0, '{"id":"cao-cao-184-yellow-turban","personId":"cao-cao","year":184,"displayYear":"184","type":"campaign","title":"讨黄巾，转任济南相","summary":"黄巾起义爆发后，曹操以骑都尉讨颍川黄巾，随后出任济南相，开始积累地方治理声望。","relatedEventIds":["china-184-yellow-turban-rebellion"],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-yellow-turban"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"光和末","quote":"光和末，黄巾起。拜骑都尉，讨颍川贼。迁为济南相。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-189-dong-zhuo-east', 'cao-cao', 189, NULL, '189', 'politics', '拒董卓任命，变姓名东归', '董卓控制洛阳后表曹操为骁骑校尉，曹操没有接受，而是改名潜行东归，为之后起兵讨董铺垫。', 'high', 0, '{"id":"cao-cao-189-dong-zhuo-east","personId":"cao-cao","year":189,"displayYear":"189","type":"politics","title":"拒董卓任命，变姓名东归","summary":"董卓控制洛阳后表曹操为骁骑校尉，曹操没有接受，而是改名潜行东归，为之后起兵讨董铺垫。","relatedEventIds":["china-189-dong-zhuo-enters-luoyang"],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-dong-zhuo-east"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"中平六年","quote":"卓表太祖为骁骑校尉，欲与计事。太祖乃变易姓名，间行东归。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-192-yanzhou-qingzhou', 'cao-cao', 192, NULL, '192', 'turning-point', '领兖州牧，收青州兵', '刘岱死后，鲍信等迎曹操领兖州牧；同年收降青州黄巾，形成后来曹操军力中的重要兵源。', 'high', 0, '{"id":"cao-cao-192-yanzhou-qingzhou","personId":"cao-cao","year":192,"displayYear":"192","type":"turning-point","title":"领兖州牧，收青州兵","summary":"刘岱死后，鲍信等迎曹操领兖州牧；同年收降青州黄巾，形成后来曹操军力中的重要兵源。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-yanzhou-qingzhou"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"初平三年","quote":"信乃与州吏万潜等至东郡迎太祖领兖州牧。冬，受降卒三十馀万，男女百馀万口，收其精锐者，号为青州兵。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-197-wan-defeat', 'cao-cao', 197, NULL, '197', 'campaign', '宛城败于张绣', '张绣先降后叛，曹操在宛城失利，长子曹昂与侄曹安民遇害，是曹操早期扩张中的重大挫折。', 'high', 0, '{"id":"cao-cao-197-wan-defeat","personId":"cao-cao","year":197,"displayYear":"197","type":"campaign","title":"宛城败于张绣","summary":"张绣先降后叛，曹操在宛城失利，长子曹昂与侄曹安民遇害，是曹操早期扩张中的重大挫折。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-wan-defeat"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安二年","quote":"二年春正月，公到宛。张绣降，旣而悔之，复反。公与战，军败，为流矢所中，长子昂、弟子安民遇害。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-207-white-wolf', 'cao-cao', 207, NULL, '207', 'campaign', '白狼山破乌桓', '曹操北征乌桓，出卢龙塞，白狼山遇敌后以张辽为先锋击破蹋顿，袁氏余部北方依托被切断。', 'high', 0, '{"id":"cao-cao-207-white-wolf","personId":"cao-cao","year":207,"displayYear":"207","type":"campaign","title":"白狼山破乌桓","summary":"曹操北征乌桓，出卢龙塞，白狼山遇敌后以张辽为先锋击破蹋顿，袁氏余部北方依托被切断。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-white-wolf"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安十二年八月","quote":"八月，登白狼山，卒与虏遇，衆甚盛。公登高，望虏陈不整，乃纵兵击之，使张辽为先锋，虏衆大崩。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-211-tongguan', 'cao-cao', 211, NULL, '211', 'campaign', '潼关西征马超韩遂', '关中诸将疑惧反叛后，曹操西征马超、韩遂等，先令诸将坚壁不战，再渡河展开关中战事。', 'high', 0, '{"id":"cao-cao-211-tongguan","personId":"cao-cao","year":211,"displayYear":"211","type":"campaign","title":"潼关西征马超韩遂","summary":"关中诸将疑惧反叛后，曹操西征马超、韩遂等，先令诸将坚壁不战，再渡河展开关中战事。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wudi-cao-cao-tongguan"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安十六年","quote":"超等屯潼关，公勑诸将：“关西兵精悍，坚壁勿与战。”秋七月，公西征。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-cao-217-cao-pi-heir', 'cao-cao', 217, NULL, '217', 'politics', '立曹丕为魏太子', '曹操晚年确立曹丕为魏太子，完成魏王集团继承次序安排。', 'high', 0, '{"id":"cao-cao-217-cao-pi-heir","personId":"cao-cao","year":217,"displayYear":"217","type":"politics","title":"立曹丕为魏太子","summary":"曹操晚年确立曹丕为魏太子，完成魏王集团继承次序安排。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wendi-cao-pi-heir"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wendi","locator":"建安二十二年","quote":"建安十六年，为五官中郎将、副丞相。二十二年，立为魏太子。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-pi-211-wuguan', 'cao-pi', 211, NULL, '211', 'office', '任五官中郎将、副丞相', '曹丕在建安十六年任五官中郎将、副丞相，开始进入曹操集团最高层的制度化继承序列。', 'high', 0, '{"id":"cao-pi-211-wuguan","personId":"cao-pi","year":211,"displayYear":"211","type":"office","title":"任五官中郎将、副丞相","summary":"曹丕在建安十六年任五官中郎将、副丞相，开始进入曹操集团最高层的制度化继承序列。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wendi-cao-pi-heir"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wendi","locator":"建安十六年","quote":"建安十六年，为五官中郎将、副丞相。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-pi-217-heir', 'cao-pi', 217, NULL, '217', 'politics', '立为魏太子', '曹丕被立为魏太子，正式压过曹植等竞争者，成为曹操政治遗产的继承人。', 'high', 0, '{"id":"cao-pi-217-heir","personId":"cao-pi","year":217,"displayYear":"217","type":"politics","title":"立为魏太子","summary":"曹丕被立为魏太子，正式压过曹植等竞争者，成为曹操政治遗产的继承人。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wendi-cao-pi-heir"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wendi","locator":"建安二十二年","quote":"二十二年，立为魏太子。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-pi-221-sun-quan-vassal', 'cao-pi', 221, NULL, '221', 'diplomacy', '册封孙权为吴王', '孙权向魏遣使奉章并归还于禁等，曹丕册拜孙权为大将军、吴王，魏吴关系短暂转入名义臣属状态。', 'high', 0, '{"id":"cao-pi-221-sun-quan-vassal","personId":"cao-pi","year":221,"displayYear":"221","type":"diplomacy","title":"册封孙权为吴王","summary":"孙权向魏遣使奉章并归还于禁等，曹丕册拜孙权为大将军、吴王，魏吴关系短暂转入名义臣属状态。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wendi-cao-pi-sun-quan"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wendi","locator":"黄初二年八月","quote":"秋八月，孙权遣使奉章，并遣于禁等还。丁巳，使太常邢贞持节拜权为大将军，封吴王，加九锡。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-pi-222-south-campaign', 'cao-pi', 222, NULL, '222', 'campaign', '治兵南征', '夷陵战后魏吴关系重新紧张，曹丕在东郊治兵后南征，试图利用吴蜀战后格局压迫孙吴。', 'high', 0, '{"id":"cao-pi-222-south-campaign","personId":"cao-pi","year":222,"displayYear":"222","type":"campaign","title":"治兵南征","summary":"夷陵战后魏吴关系重新紧张，曹丕在东郊治兵后南征，试图利用吴蜀战后格局压迫孙吴。","relatedEventIds":["china-222-yiling"],"sourceMentionIds":["mention-sgz-wei-wendi-cao-pi-south-campaign"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wendi","locator":"黄初三年","quote":"六月辛亥，治兵于东郊。庚午，遂南征。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-pi-225-guangling', 'cao-pi', 225, NULL, '225', 'campaign', '广陵临江观兵', '曹丕东巡至广陵故城，临江陈兵十余万，展示对孙吴方向的军事压力。', 'high', 0, '{"id":"cao-pi-225-guangling","personId":"cao-pi","year":225,"displayYear":"225","type":"campaign","title":"广陵临江观兵","summary":"曹丕东巡至广陵故城，临江陈兵十余万，展示对孙吴方向的军事压力。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-wendi-cao-pi-guangling"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-wendi","locator":"黄初六年","quote":"冬十月，行幸广陵故城，临江观兵，戎卒十馀万，旌旗数百里。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-rui-204-born', 'cao-rui', 204, NULL, '204', 'birth', '曹叡出生', '曹叡为曹丕之子，字元仲；《明帝纪》称其幼年受曹操喜爱，常在左右。', 'medium', 0, '{"id":"cao-rui-204-born","personId":"cao-rui","year":204,"displayYear":"204","type":"birth","title":"曹叡出生","summary":"曹叡为曹丕之子，字元仲；《明帝纪》称其幼年受曹操喜爱，常在左右。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-mingdi-cao-rui-origin"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wei-mingdi","locator":"明帝纪开篇","quote":"明皇帝讳睿，字元仲，文帝太子也。生而太祖爱之，常令在左右。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-rui-220-enfeoffment', 'cao-rui', 220, 222, '220-222', 'office', '封武德侯、齐公、平原王', '曹叡黄初年间先封武德侯，后为齐公、平原王；因甄后之事，起初未被立即确定为继嗣。', 'high', 0, '{"id":"cao-rui-220-enfeoffment","personId":"cao-rui","year":220,"endYear":222,"displayYear":"220-222","type":"office","title":"封武德侯、齐公、平原王","summary":"曹叡黄初年间先封武德侯，后为齐公、平原王；因甄后之事，起初未被立即确定为继嗣。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-mingdi-cao-rui-enfeoffment"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-mingdi","locator":"黄初年间","quote":"年十五，封武德侯，黄初二年为齐公，三年为平原王。以其母诛，故未建为嗣。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-rui-226-accession', 'cao-rui', 226, NULL, '226', 'politics', '立为皇太子并即位', '曹丕病重时立曹叡为皇太子；同日曹叡即皇帝位，曹魏进入明帝时期。', 'high', 0, '{"id":"cao-rui-226-accession","personId":"cao-rui","year":226,"displayYear":"226","type":"politics","title":"立为皇太子并即位","summary":"曹丕病重时立曹叡为皇太子；同日曹叡即皇帝位，曹魏进入明帝时期。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-mingdi-cao-rui-accession"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-mingdi","locator":"黄初七年五月","quote":"七年夏五月，帝病笃，乃立为皇太子。丁巳，即皇帝位，大赦。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-rui-228-zhuge-liang-first-northern-expedition', 'cao-rui', 228, NULL, '228', 'campaign', '应对诸葛亮第一次北伐', '诸葛亮攻边，天水、南安、安定响应；曹叡调度曹真、张郃等关右兵力应对，魏蜀战争进入明帝时期主轴。', 'high', 0, '{"id":"cao-rui-228-zhuge-liang-first-northern-expedition","personId":"cao-rui","year":228,"displayYear":"228","type":"campaign","title":"应对诸葛亮第一次北伐","summary":"诸葛亮攻边，天水、南安、安定响应；曹叡调度曹真、张郃等关右兵力应对，魏蜀战争进入明帝时期主轴。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-mingdi-cao-rui-zhuge-228"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-mingdi","locator":"太和二年","quote":"蜀大将诸葛亮寇边，天水、南安、安定三郡吏民叛应亮。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-rui-234-wuzhang', 'cao-rui', 234, NULL, '234', 'campaign', '五丈原相持，诸葛亮卒', '诸葛亮出斜谷屯渭南，司马懿率魏军拒守；诸葛亮去世后蜀军撤退，曹魏西线压力暂缓。', 'high', 0, '{"id":"cao-rui-234-wuzhang","personId":"cao-rui","year":234,"displayYear":"234","type":"campaign","title":"五丈原相持，诸葛亮卒","summary":"诸葛亮出斜谷屯渭南，司马懿率魏军拒守；诸葛亮去世后蜀军撤退，曹魏西线压力暂缓。","relatedEventIds":["china-234-wuzhang-plains"],"sourceMentionIds":["mention-sgz-wei-mingdi-cao-rui-wuzhang"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-mingdi","locator":"青龙二年","quote":"是月，诸葛亮出斜谷，屯渭南，司马宣王率诸军拒之。会亮卒，其军退还。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-rui-238-liaodong', 'cao-rui', 238, NULL, '238', 'campaign', '遣司马懿平辽东', '曹叡决意以大兵讨公孙渊，司马懿围襄平并斩送公孙渊首级，辽东公孙氏政权灭亡。', 'high', 0, '{"id":"cao-rui-238-liaodong","personId":"cao-rui","year":238,"displayYear":"238","type":"campaign","title":"遣司马懿平辽东","summary":"曹叡决意以大兵讨公孙渊，司马懿围襄平并斩送公孙渊首级，辽东公孙氏政权灭亡。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-mingdi-cao-rui-liaodong"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-mingdi","locator":"景初二年","quote":"丙寅，司马宣王围公孙渊于襄平，大破之，传渊首于京都，海东诸郡平。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-rui-239-death', 'cao-rui', 239, NULL, '239', 'death', '魏明帝去世', '曹叡临终托付曹芳、曹爽、司马懿等，随后崩于嘉福殿，曹魏进入少帝与辅政格局。', 'high', 0, '{"id":"cao-rui-239-death","personId":"cao-rui","year":239,"displayYear":"239","type":"death","title":"魏明帝去世","summary":"曹叡临终托付曹芳、曹爽、司马懿等，随后崩于嘉福殿，曹魏进入少帝与辅政格局。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-mingdi-cao-rui-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-mingdi","locator":"景初三年正月","quote":"即日，帝崩于嘉福殿，魏书曰：殡于九龙前殿。时年三十六。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhang-early-martial', 'cao-zhang', NULL, NULL, '早年', 'service', '以武勇见称', '曹彰字子文，少善射御、膂力过人，自陈志在为卫青、霍去病式的骑将。', 'high', 0, '{"id":"cao-zhang-early-martial","personId":"cao-zhang","year":null,"displayYear":"早年","type":"service","title":"以武勇见称","summary":"曹彰字子文，少善射御、膂力过人，自陈志在为卫青、霍去病式的骑将。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhang-early"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhang","locator":"本传开篇","quote":"任城威王彰，字子文。少善射御，膂力过人，手格猛兽，不避险阻。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhang-218-daijun', 'cao-zhang', 218, NULL, '218', 'campaign', '北征代郡乌丸', '代郡乌丸反叛时，曹彰为北中郎将、行骁骑将军，率军北征并以武勇立功。', 'high', 0, '{"id":"cao-zhang-218-daijun","personId":"cao-zhang","year":218,"displayYear":"218","type":"campaign","title":"北征代郡乌丸","summary":"代郡乌丸反叛时，曹彰为北中郎将、行骁骑将军，率军北征并以武勇立功。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhang-daijun"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhang","locator":"建安二十三年","quote":"二十三年，代郡乌丸反，以彰为北中郎将，行骁骑将军。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhang-222-rencheng', 'cao-zhang', 222, NULL, '222', 'office', '立为任城王', '曹丕黄初三年立曹彰为任城王，宗室诸王分封体系进一步成形。', 'high', 0, '{"id":"cao-zhang-222-rencheng","personId":"cao-zhang","year":222,"displayYear":"222","type":"office","title":"立为任城王","summary":"曹丕黄初三年立曹彰为任城王，宗室诸王分封体系进一步成形。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhang-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhang","locator":"黄初三年","quote":"三年，立为任城王。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhang-223-death', 'cao-zhang', 223, NULL, '223', 'death', '朝京都，疾薨于邸', '曹彰入朝京都后病逝于邸舍，谥为威，后世围绕其入朝与暴薨有不同说法。', 'high', 0, '{"id":"cao-zhang-223-death","personId":"cao-zhang","year":223,"displayYear":"223","type":"death","title":"朝京都，疾薨于邸","summary":"曹彰入朝京都后病逝于邸舍，谥为威，后世围绕其入朝与暴薨有不同说法。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhang-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhang","locator":"黄初四年","quote":"四年，朝京都，疾薨于邸，谥曰威。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhi-192-birth', 'cao-zhi', 192, NULL, '约192', 'birth', '曹植出生', '曹植字子建，卒年四十一，据《陈思王植传》卒年反推约生于初平三年前后。', 'medium', 0, '{"id":"cao-zhi-192-birth","personId":"cao-zhi","year":192,"displayYear":"约192","type":"birth","title":"曹植出生","summary":"曹植字子建，卒年四十一，据《陈思王植传》卒年反推约生于初平三年前后。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhi-death"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhi","locator":"太和六年","quote":"遂发疾薨，时年四十一。","note":"生年据卒年和享年反推。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhi-early-literary-talent', 'cao-zhi', 203, NULL, '约203', 'service', '少有文才', '曹植十余岁已能诵读大量诗论辞赋，善于属文，是建安文学中最重要的曹氏宗室人物。', 'medium', 1, '{"id":"cao-zhi-early-literary-talent","personId":"cao-zhi","year":203,"displayYear":"约203","type":"service","title":"少有文才","summary":"曹植十余岁已能诵读大量诗论辞赋，善于属文，是建安文学中最重要的曹氏宗室人物。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhi-talent"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhi","locator":"本传开篇","quote":"陈思王植字子建。年十岁馀，诵读诗、论及辞赋数十万言，善属文。","note":"年份据曹植生年和“年十岁馀”约推。"}],"approximate":true}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhi-210-copper-terrace', 'cao-zhi', 210, NULL, '约210', 'service', '铜雀台援笔立成', '曹操带诸子登邺城铜雀台命作赋，曹植援笔立成，受到曹操特别赏识。', 'medium', 0, '{"id":"cao-zhi-210-copper-terrace","personId":"cao-zhi","year":210,"displayYear":"约210","type":"service","title":"铜雀台援笔立成","summary":"曹操带诸子登邺城铜雀台命作赋，曹植援笔立成，受到曹操特别赏识。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhi-copper-terrace"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhi","locator":"邺铜雀台","quote":"植援笔立成，可观，太祖甚异之。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhi-217-succession-rivalry', 'cao-zhi', 217, NULL, '217 前后', 'politics', '参与继承竞争并失势', '曹植因才学被曹操看重，一度几乎成为太子候选；但其任性饮酒，与曹丕的自饰经营形成反差，最终曹丕被立为魏太子。', 'high', 0, '{"id":"cao-zhi-217-succession-rivalry","personId":"cao-zhi","year":217,"displayYear":"217 前后","type":"politics","title":"参与继承竞争并失势","summary":"曹植因才学被曹操看重，一度几乎成为太子候选；但其任性饮酒，与曹丕的自饰经营形成反差，最终曹丕被立为魏太子。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhi-succession"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhi","locator":"建安二十二年前后","quote":"太祖狐疑，几为太子者数矣。而植任性而行，不自雕励，饮酒不节。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhi-221-demotion', 'cao-zhi', 221, NULL, '221', 'politics', '贬爵安乡侯', '曹丕即位后，曹植被奏称醉酒悖慢、胁迫使者，有司请罪；曹丕因卞太后缘故不杀，贬其爵。', 'high', 0, '{"id":"cao-zhi-221-demotion","personId":"cao-zhi","year":221,"displayYear":"221","type":"politics","title":"贬爵安乡侯","summary":"曹丕即位后，曹植被奏称醉酒悖慢、胁迫使者，有司请罪；曹丕因卞太后缘故不杀，贬其爵。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhi-demotion"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhi","locator":"黄初二年","quote":"黄初二年，监国谒者灌均希指，奏“植醉酒悖慢，劫胁使者”。有司请治罪，帝以太后故，贬爵安乡侯。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhi-232-death', 'cao-zhi', 232, NULL, '232', 'death', '封陈王后病逝', '曹叡太和六年，以陈四县封曹植为陈王；曹植多次求试用不得，忧郁发病而卒，年四十一。', 'high', 0, '{"id":"cao-zhi-232-death","personId":"cao-zhi","year":232,"displayYear":"232","type":"death","title":"封陈王后病逝","summary":"曹叡太和六年，以陈四县封曹植为陈王；曹植多次求试用不得，忧郁发病而卒，年四十一。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhi-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhi","locator":"太和六年","quote":"其二月，以陈四县封植为陈王，邑三千五百户。植每欲求别见独谈，论及时政，幸兾试用，终不能得。旣还，怅然绝望。遂发疾薨，时年四十一。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-chong-196-birth', 'cao-chong', 196, NULL, '约196', 'birth', '曹冲出生', '曹冲字仓舒，建安十三年卒时年十三，据此约生于建安元年前后。', 'medium', 0, '{"id":"cao-chong-196-birth","personId":"cao-chong","year":196,"displayYear":"约196","type":"birth","title":"曹冲出生","summary":"曹冲字仓舒，建安十三年卒时年十三，据此约生于建安元年前后。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-chong-death"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-chong","locator":"建安十三年","quote":"年十三，建安十三年疾病。","note":"生年据卒年和享年反推。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-chong-early-talent', 'cao-chong', 201, 202, '约201-202', 'service', '幼年聪察早慧', '曹冲五六岁时已被称有成人之智，是曹操诸子中最具早慧形象的人物之一。', 'medium', 1, '{"id":"cao-chong-early-talent","personId":"cao-chong","year":201,"displayYear":"约201-202","type":"service","title":"幼年聪察早慧","summary":"曹冲五六岁时已被称有成人之智，是曹操诸子中最具早慧形象的人物之一。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-chong-talent"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-chong","locator":"本传开篇","quote":"少聦察岐嶷，生五六岁，智意所及，有若成人之智。","note":"年份据曹冲约生年和“五六岁”约推。"}],"endYear":202,"approximate":true}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-chong-elephant', 'cao-chong', 201, 202, '约201-202', 'service', '曹冲称象', '孙权进献巨象，群臣无法测重，曹冲提出以船载象、刻水痕、再称物相校的方法。', 'medium', 1, '{"id":"cao-chong-elephant","personId":"cao-chong","year":201,"displayYear":"约201-202","type":"service","title":"曹冲称象","summary":"孙权进献巨象，群臣无法测重，曹冲提出以船载象、刻水痕、再称物相校的方法。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-chong-elephant"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-chong","locator":"称象","quote":"冲曰：“置象大船之上，而刻其水痕所至，称物以载之，则校可知矣。”","note":"本传未明纪年，置于曹冲五六岁早慧阶段。"}],"endYear":202,"approximate":true}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-chong-mercy', 'cao-chong', 206, NULL, '约206', 'politics', '为库吏解鼠啮马鞍之罪', '曹冲利用衣物被鼠啮的说法，替因曹操马鞍被鼠啮而恐惧受死的库吏开解，传记借此突出其仁爱与机智。', 'medium', 1, '{"id":"cao-chong-mercy","personId":"cao-chong","year":206,"displayYear":"约206","type":"politics","title":"为库吏解鼠啮马鞍之罪","summary":"曹冲利用衣物被鼠啮的说法，替因曹操马鞍被鼠啮而恐惧受死的库吏开解，传记借此突出其仁爱与机智。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-chong-mercy"],"confidence":"medium","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-chong","locator":"马鞍鼠啮","quote":"太祖马鞌在库，而为鼠所啮，库吏惧必死。冲谓曰：“待三日中，然后自归。”","note":"本传未明纪年，暂置于曹冲去世前数年。"}],"approximate":true}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-chong-208-death', 'cao-chong', 208, NULL, '208', 'death', '十三岁病逝', '曹冲建安十三年病逝，曹操哀甚，并对曹丕说这是自己的不幸、诸子的幸运，反映曹冲曾被寄予很高期待。', 'high', 0, '{"id":"cao-chong-208-death","personId":"cao-chong","year":208,"displayYear":"208","type":"death","title":"十三岁病逝","summary":"曹冲建安十三年病逝，曹操哀甚，并对曹丕说这是自己的不幸、诸子的幸运，反映曹冲曾被寄予很高期待。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-chong-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-chong","locator":"建安十三年","quote":"年十三，建安十三年疾病，太祖亲为请命。及亡，哀甚。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-ang-early-xiaolian', 'cao-ang', NULL, NULL, '弱冠', 'office', '弱冠举孝廉', '曹昂字子修，弱冠时举孝廉，是曹操早年成年的长子。', 'high', 0, '{"id":"cao-ang-early-xiaolian","personId":"cao-ang","year":null,"displayYear":"弱冠","type":"office","title":"弱冠举孝廉","summary":"曹昂字子修，弱冠时举孝廉，是曹操早年成年的长子。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-ang-life-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-ang","locator":"本传","quote":"丰愍王昂字子修。弱冠举孝廉。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-ang-197-death', 'cao-ang', 197, NULL, '197', 'death', '随曹操南征，为张绣所害', '曹昂随曹操南征宛城，张绣复叛后遇害；《武帝纪》还记其与曹安民同死于宛城败局。', 'high', 0, '{"id":"cao-ang-197-death","personId":"cao-ang","year":197,"displayYear":"197","type":"death","title":"随曹操南征，为张绣所害","summary":"曹昂随曹操南征宛城，张绣复叛后遇害；《武帝纪》还记其与曹安民同死于宛城败局。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-ang-life-death","mention-sgz-wei-wudi-cao-cao-wan-defeat"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-ang","locator":"本传","quote":"随太祖南征，为张绣所害。"},{"sourceId":"sanguozhi-wei-wudi","locator":"建安二年","quote":"公与战，军败，为流矢所中，长子昂、弟子安民遇害。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-shuang-239-regency', 'cao-shuang', 239, NULL, '239', 'politics', '受明帝遗诏辅少主', '曹叡病重时拜曹爽为大将军，假节钺、都督中外诸军事、录尚书事，与司马懿共同辅佐曹芳。', 'high', 0, '{"id":"cao-shuang-239-regency","personId":"cao-shuang","year":239,"displayYear":"239","type":"politics","title":"受明帝遗诏辅少主","summary":"曹叡病重时拜曹爽为大将军，假节钺、都督中外诸军事、录尚书事，与司马懿共同辅佐曹芳。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-shuang-early-regency","mention-sgz-wei-mingdi-cao-rui-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-shuang","locator":"明帝末年","quote":"帝寝疾，乃引爽入卧内，拜大将军，假节钺，都督中外诸军事，录尚书事，与太尉司马宣王并受遗诏辅少主。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-shuang-240-power-network', 'cao-shuang', 240, NULL, '正始初', 'politics', '曹氏兄弟出入禁闼，权势转盛', '曹爽辅政后，曹羲、曹训、曹彦等兄弟分居禁军和侍从要职，何晏、邓飏、李胜、丁谧等成为腹心。', 'high', 0, '{"id":"cao-shuang-240-power-network","personId":"cao-shuang","year":240,"displayYear":"正始初","type":"politics","title":"曹氏兄弟出入禁闼，权势转盛","summary":"曹爽辅政后，曹羲、曹训、曹彦等兄弟分居禁军和侍从要职，何晏、邓飏、李胜、丁谧等成为腹心。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-shuang-power"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-shuang","locator":"正始初","quote":"爽弟羲为中领军，训武衞将军，彦散骑常侍侍讲，其馀诸弟皆以列侯侍从，出入禁闼，贵宠莫盛焉。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-shuang-244-shu-campaign', 'cao-shuang', 244, NULL, '244', 'campaign', '骆谷伐蜀失利', '曹爽为立威名发动伐蜀，自长安发卒六七万人入骆谷，因转输困难和蜀军据险，最终无功而返。', 'high', 0, '{"id":"cao-shuang-244-shu-campaign","personId":"cao-shuang","year":244,"displayYear":"244","type":"campaign","title":"骆谷伐蜀失利","summary":"曹爽为立威名发动伐蜀，自长安发卒六七万人入骆谷，因转输困难和蜀军据险，最终无功而返。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-shuang-shu-campaign"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-shuang","locator":"正始五年","quote":"正始五年，爽乃西至长安，大发卒六七万人，从骆谷入。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-shuang-249-gaopingling', 'cao-shuang', 249, NULL, '249', 'turning-point', '高平陵政变中失势', '曹芳谒高平陵时曹爽兄弟随行出城，司马懿据武库、屯洛水浮桥，曹爽失去洛阳中枢控制。', 'high', 0, '{"id":"cao-shuang-249-gaopingling","personId":"cao-shuang","year":249,"displayYear":"249","type":"turning-point","title":"高平陵政变中失势","summary":"曹芳谒高平陵时曹爽兄弟随行出城，司马懿据武库、屯洛水浮桥，曹爽失去洛阳中枢控制。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-shuang-gaoping"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-shuang","locator":"正始十年正月","quote":"十年正月，车驾朝高平陵，爽兄弟皆从。宣王部勒兵马，先据武库，遂出屯洛水浮桥。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-shuang-249-death', 'cao-shuang', 249, NULL, '249', 'death', '曹爽及党羽伏诛', '高平陵之后，曹爽、曹羲、曹训、何晏、邓飏、丁谧等被诛并夷三族，司马氏掌握曹魏政局。', 'high', 0, '{"id":"cao-shuang-249-death","personId":"cao-shuang","year":249,"displayYear":"249","type":"death","title":"曹爽及党羽伏诛","summary":"高平陵之后，曹爽、曹羲、曹训、何晏、邓飏、丁谧等被诛并夷三族，司马氏掌握曹魏政局。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-shuang-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-shuang","locator":"正始十年","quote":"于是收爽、羲、训、晏、扬、谧、轨、胜、范、当等，皆伏诛，夷三族。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-fang-235-qi-wang', 'cao-fang', 235, NULL, '235', 'office', '立为齐王', '曹芳幼年入魏明帝后嗣体系，青龙三年被立为齐王，是其入继皇位前的身份基础。', 'high', 0, '{"id":"cao-fang-235-qi-wang","personId":"cao-fang","year":235,"displayYear":"235","type":"office","title":"立为齐王","summary":"曹芳幼年入魏明帝后嗣体系，青龙三年被立为齐王，是其入继皇位前的身份基础。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-qi-wang-235-qi-wang"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-qi-wang","locator":"青龙三年","quote":"青龙三年，立为齐王。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-fang-239-enthroned', 'cao-fang', 239, NULL, '239', 'politics', '明帝病重，曹芳即位', '魏明帝病重时立曹芳为皇太子，当日即皇帝位；曹爽与司马懿同受托辅政，曹魏进入少帝政治。', 'high', 0, '{"id":"cao-fang-239-enthroned","personId":"cao-fang","year":239,"displayYear":"239","type":"politics","title":"明帝病重，曹芳即位","summary":"魏明帝病重时立曹芳为皇太子，当日即皇帝位；曹爽与司马懿同受托辅政，曹魏进入少帝政治。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-qi-wang-239-enthroned"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-qi-wang","locator":"景初三年正月","quote":"景初三年正月丁亥朔，帝甚病，乃立为皇太子。是日，即皇帝位，大赦。尊皇后曰皇太后。大将军曹爽、太尉司马宣王辅政。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-fang-249-gaopingling', 'cao-fang', 249, NULL, '249', 'turning-point', '高平陵政变中失去曹爽辅政体系', '曹芳谒高平陵时，司马懿在洛阳发动政变，奏免曹爽兄弟官职；此后曹魏中枢权力转入司马氏。', 'high', 0, '{"id":"cao-fang-249-gaopingling","personId":"cao-fang","year":249,"displayYear":"249","type":"turning-point","title":"高平陵政变中失去曹爽辅政体系","summary":"曹芳谒高平陵时，司马懿在洛阳发动政变，奏免曹爽兄弟官职；此后曹魏中枢权力转入司马氏。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-qi-wang-249-gaopingling"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-qi-wang","locator":"嘉平元年春正月","quote":"嘉平元年春正月甲午，车驾谒高平陵。太傅司马宣王奏免大将军曹爽、爽弟中领军羲、武卫将军训、散骑常侍彦官，以侯就第。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-fang-254-deposed', 'cao-fang', 254, NULL, '254', 'politics', '司马师谋废，曹芳归藩于齐', '司马师以郭太后令废曹芳帝位，遣其归藩为齐王；曹魏皇位转由高贵乡公曹髦继承。', 'high', 0, '{"id":"cao-fang-254-deposed","personId":"cao-fang","year":254,"displayYear":"254","type":"politics","title":"司马师谋废，曹芳归藩于齐","summary":"司马师以郭太后令废曹芳帝位，遣其归藩为齐王；曹魏皇位转由高贵乡公曹髦继承。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-qi-wang-254-deposed"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-qi-wang","locator":"嘉平六年九月","quote":"秋九月，大将军司马景王将谋废帝，以闻皇太后。甲戌，太后令曰：皇帝芳春秋已长，不亲万机……遣芳归藩于齐，以避皇位。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-mao-244-gaogui', 'cao-mao', 244, NULL, '244', 'office', '封高贵乡公', '曹髦为曹丕之孙、东海定王曹霖之子，正始五年被封为高贵乡公，传称少好学、夙成。', 'high', 0, '{"id":"cao-mao-244-gaogui","personId":"cao-mao","year":244,"displayYear":"244","type":"office","title":"封高贵乡公","summary":"曹髦为曹丕之孙、东海定王曹霖之子，正始五年被封为高贵乡公，传称少好学、夙成。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-gaogui-xianggong-244-gaogui"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-gaogui-xianggong","locator":"正始五年","quote":"高贵乡公讳髦，字彦士，文帝孙，东海定王霖子也。正始五年，封歘县高贵乡公。少好学，夙成。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-mao-254-enthroned', 'cao-mao', 254, NULL, '254', 'politics', '齐王废后被迎立', '曹芳被废后，公卿迎立曹髦；曹髦入洛阳时仍以人臣自处，随后在太极前殿即皇帝位。', 'high', 0, '{"id":"cao-mao-254-enthroned","personId":"cao-mao","year":254,"displayYear":"254","type":"politics","title":"齐王废后被迎立","summary":"曹芳被废后，公卿迎立曹髦；曹髦入洛阳时仍以人臣自处，随后在太极前殿即皇帝位。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-gaogui-xianggong-254-enthroned"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-gaogui-xianggong","locator":"正元元年十月","quote":"齐王废，公卿议迎立公。十月己丑，公至于玄武馆……其日即皇帝位于太极前殿。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-mao-260-sima-zhao', 'cao-mao', 260, NULL, '260', 'turning-point', '称“司马昭之心，路人所知”', '曹髦面对司马昭权势日盛，召王沈、王经、王业等言明不愿坐受废辱，决定亲自讨伐司马昭。', 'high', 0, '{"id":"cao-mao-260-sima-zhao","personId":"cao-mao","year":260,"displayYear":"260","type":"turning-point","title":"称“司马昭之心，路人所知”","summary":"曹髦面对司马昭权势日盛，召王沈、王经、王业等言明不愿坐受废辱，决定亲自讨伐司马昭。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-gaogui-xianggong-260-sima-zhao"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-gaogui-xianggong","locator":"甘露五年五月","quote":"帝见威权日去，不胜其忿。乃召侍中王沈、尚书王经、散骑常侍王业，谓曰：“司马昭之心，路人所知也。吾不能坐受废辱，今日当与卿等自出讨之。”"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-mao-260-death', 'cao-mao', 260, NULL, '260', 'death', '南阙下被弑', '曹髦率僮仆宿卫出宫，被贾充所部阻击；太子舍人成济刺杀曹髦，曹魏皇权与司马氏矛盾公开化。', 'high', 0, '{"id":"cao-mao-260-death","personId":"cao-mao","year":260,"displayYear":"260","type":"death","title":"南阙下被弑","summary":"曹髦率僮仆宿卫出宫，被贾充所部阻击；太子舍人成济刺杀曹髦，曹魏皇权与司马氏矛盾公开化。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-gaogui-xianggong-260-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-gaogui-xianggong","locator":"甘露五年五月","quote":"中护军贾充又逆帝战于南阙下，帝自用剑。众欲退，太子舍人成济问充曰：“事急矣。当云何？”充曰：“畜养汝等，正谓今日。今日之事，无所问也。”济即前刺帝，刃出于背。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-huan-258-changdao', 'cao-huan', 258, NULL, '258', 'office', '封常道乡公', '曹奂为曹操之孙、燕王曹宇之子，甘露三年被封为安次县常道乡公。', 'high', 0, '{"id":"cao-huan-258-changdao","personId":"cao-huan","year":258,"displayYear":"258","type":"office","title":"封常道乡公","summary":"曹奂为曹操之孙、燕王曹宇之子，甘露三年被封为安次县常道乡公。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-chenliu-wang-258-changdao"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-chenliu-wang","locator":"甘露三年","quote":"陈留王讳奂，字景明，武帝孙，燕王宇子也。甘露三年，封安次县常道乡公。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-huan-260-enthroned', 'cao-huan', 260, NULL, '260', 'politics', '曹髦死后被迎立', '高贵乡公曹髦被弑后，公卿迎立曹奂；他入洛阳见皇太后，当日在太极前殿即位。', 'high', 0, '{"id":"cao-huan-260-enthroned","personId":"cao-huan","year":260,"displayYear":"260","type":"politics","title":"曹髦死后被迎立","summary":"高贵乡公曹髦被弑后，公卿迎立曹奂；他入洛阳见皇太后，当日在太极前殿即位。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-chenliu-wang-260-enthroned"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-chenliu-wang","locator":"甘露五年六月","quote":"高贵乡公卒，公卿议迎立公。六月甲寅，入于洛阳，见皇太后，是日即皇帝位于太极前殿，大赦，改年。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-huan-263-shu-surrender', 'cao-huan', 263, NULL, '263', 'campaign', '魏灭蜀汉', '曹奂在位时，邓艾、钟会伐蜀，刘禅向邓艾投降，蜀汉灭亡；这是曹魏后期最重大的军事成果。', 'high', 0, '{"id":"cao-huan-263-shu-surrender","personId":"cao-huan","year":263,"displayYear":"263","type":"campaign","title":"魏灭蜀汉","summary":"曹奂在位时，邓艾、钟会伐蜀，刘禅向邓艾投降，蜀汉灭亡；这是曹魏后期最重大的军事成果。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-chenliu-wang-263-shu-surrender"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-chenliu-wang","locator":"景元四年十一月","quote":"自邓艾、锺会率众伐蜀，所至辄克。是月，蜀主刘禅诣艾降，巴蜀皆平。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-huan-265-abdication', 'cao-huan', 265, NULL, '265', 'abdication', '禅位于晋', '咸熙二年，曹奂下诏禅位于晋王司马炎，曹魏政权结束；曹奂随后被封为陈留王。', 'high', 0, '{"id":"cao-huan-265-abdication","personId":"cao-huan","year":265,"displayYear":"265","type":"abdication","title":"禅位于晋","summary":"咸熙二年，曹奂下诏禅位于晋王司马炎，曹魏政权结束；曹奂随后被封为陈留王。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-chenliu-wang-265-abdication"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-chenliu-wang","locator":"咸熙二年十二月","quote":"十二月壬戌，天禄永终，历数在晋。诏群公卿士具仪设坛于南郊，使使者奉皇帝玺绶册，禅位于晋嗣王，如汉魏故事。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-ren-early', 'cao-ren', NULL, NULL, '早年', 'service', '少好弓马，从曹操起兵', '曹仁是曹操从弟，少好弓马，汉末豪杰并起时聚众千余人，随后从曹操起兵。', 'high', 0, '{"id":"cao-ren-early","personId":"cao-ren","year":null,"displayYear":"早年","type":"service","title":"少好弓马，从曹操起兵","summary":"曹仁是曹操从弟，少好弓马，汉末豪杰并起时聚众千余人，随后从曹操起兵。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-ren-early"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-ren","locator":"本传开篇","quote":"曹仁字子孝，太祖从弟也。少好弓马弋猎……遂从太祖，为别部司马，行厉锋校尉。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-ren-208-jiangling', 'cao-ren', 208, NULL, '208 后', 'campaign', '留屯江陵，拒周瑜', '曹操平荆州后，曹仁以行征南将军留守江陵，对抗周瑜，是赤壁后曹魏南线防御核心。', 'high', 0, '{"id":"cao-ren-208-jiangling","personId":"cao-ren","year":208,"displayYear":"208 后","type":"campaign","title":"留屯江陵，拒周瑜","summary":"曹操平荆州后，曹仁以行征南将军留守江陵，对抗周瑜，是赤壁后曹魏南线防御核心。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-ren-208-jiangling"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-ren","locator":"平荆州后","quote":"从平荆州，以仁行征南将军，留屯江陵，拒吴将周瑜。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-ren-219-fancheng', 'cao-ren', 219, NULL, '219', 'campaign', '襄樊危机中坚守樊城', '关羽围樊城、水淹七军后，曹仁在粮尽援绝中坚守，直至徐晃救援而解围。', 'high', 0, '{"id":"cao-ren-219-fancheng","personId":"cao-ren","year":219,"displayYear":"219","type":"campaign","title":"襄樊危机中坚守樊城","summary":"关羽围樊城、水淹七军后，曹仁在粮尽援绝中坚守，直至徐晃救援而解围。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-ren-219-fancheng"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-ren","locator":"关羽攻樊","quote":"关羽攻樊，时汉水暴溢，于禁等七军皆没，禁降羽。仁人马数千人守城，城不没者数板……徐晃救至，水亦稍减，晃从外击羽，仁得溃围出，羽退走。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-ren-222-grand-marshal', 'cao-ren', 222, NULL, '222 前后', 'office', '拜大将军，迁大司马', '曹丕时期，曹仁拜大将军、迁大司马，仍负责南线、东线军事调度。', 'high', 0, '{"id":"cao-ren-222-grand-marshal","personId":"cao-ren","year":222,"displayYear":"222 前后","type":"office","title":"拜大将军，迁大司马","summary":"曹丕时期，曹仁拜大将军、迁大司马，仍负责南线、东线军事调度。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-ren-222-grand-marshal"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-ren","locator":"文帝时期","quote":"文帝遣使即拜仁大将军。又诏仁移屯临颍，迁大司马，复督诸军据乌江，还屯合肥。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-hong-190-save-cao-cao', 'cao-hong', 190, NULL, '190', 'campaign', '荥阳败后让马救曹操', '曹操讨董卓至荥阳败于徐荣，曹洪下马授曹操，并称天下可无洪不可无君，是其传中最著名事迹。', 'high', 0, '{"id":"cao-hong-190-save-cao-cao","personId":"cao-hong","year":190,"displayYear":"190","type":"campaign","title":"荥阳败后让马救曹操","summary":"曹操讨董卓至荥阳败于徐荣，曹洪下马授曹操，并称天下可无洪不可无君，是其传中最著名事迹。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-hong-190-save-cao-cao"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-hong","locator":"讨董卓荥阳败后","quote":"太祖失马，贼追甚急，洪下，以马授太祖，太祖辞让，洪曰：“天下可无洪，不可无君。”遂步从到汴水。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-hong-194-yan-zhou', 'cao-hong', 194, NULL, '194', 'campaign', '兖州危机中聚粮继军', '张邈迎吕布、兖州危机爆发时，曹洪先据东平、范，聚粮接济曹操军队。', 'high', 0, '{"id":"cao-hong-194-yan-zhou","personId":"cao-hong","year":194,"displayYear":"194","type":"campaign","title":"兖州危机中聚粮继军","summary":"张邈迎吕布、兖州危机爆发时，曹洪先据东平、范，聚粮接济曹操军队。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-hong-194-yan-zhou"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-hong","locator":"张邈迎吕布","quote":"太祖征徐州，张邈举兖州叛迎吕布。时大饥荒，洪将兵在前，先据东平、范，聚粮谷以继军。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-hong-226-later-office', 'cao-hong', 226, NULL, '226 后', 'office', '明帝即位后复任后将军、骠骑将军', '曹洪在曹丕时期曾几乎获罪，魏明帝即位后再受任用，拜后将军、特进、骠骑将军。', 'high', 0, '{"id":"cao-hong-226-later-office","personId":"cao-hong","year":226,"displayYear":"226 后","type":"office","title":"明帝即位后复任后将军、骠骑将军","summary":"曹洪在曹丕时期曾几乎获罪，魏明帝即位后再受任用，拜后将军、特进、骠骑将军。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-hong-226-later-office"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-hong","locator":"明帝即位后","quote":"明帝即位，拜后将军，更封乐城侯，邑千户，位特进，复拜骠骑将军。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-hong-232-death', 'cao-hong', 232, NULL, '232', 'death', '薨，谥恭侯', '曹洪太和六年去世，谥恭侯，其子曹馥嗣爵。', 'high', 0, '{"id":"cao-hong-232-death","personId":"cao-hong","year":232,"displayYear":"232","type":"death","title":"薨，谥恭侯","summary":"曹洪太和六年去世，谥恭侯，其子曹馥嗣爵。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-hong-232-death"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-hong","locator":"太和六年","quote":"太和六年薨，谥曰恭侯。子馥，嗣侯。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-xiu-early-qianliju', 'cao-xiu', NULL, NULL, '早年', 'service', '归曹操，被称“千里驹”', '曹休少孤避乱至吴地，后北归曹操，被称为“吾家千里驹”，与曹丕同处并领虎豹骑。', 'high', 0, '{"id":"cao-xiu-early-qianliju","personId":"cao-xiu","year":null,"displayYear":"早年","type":"service","title":"归曹操，被称“千里驹”","summary":"曹休少孤避乱至吴地，后北归曹操，被称为“吾家千里驹”，与曹丕同处并领虎豹骑。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-xiu-early-qianliju"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-xiu","locator":"早年归曹操","quote":"太祖谓左右曰：“此吾家千里驹也。”使与文帝同止，见待如子。常从征伐，使领虎豹骑宿卫。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-xiu-218-xiabian', 'cao-xiu', 218, NULL, '218', 'campaign', '下辩战事中参曹洪军事', '刘备遣吴兰屯下辩时，曹休为骑都尉参曹洪军事，曹操实际将指挥责任寄予曹休。', 'high', 0, '{"id":"cao-xiu-218-xiabian","personId":"cao-xiu","year":218,"displayYear":"218","type":"campaign","title":"下辩战事中参曹洪军事","summary":"刘备遣吴兰屯下辩时，曹休为骑都尉参曹洪军事，曹操实际将指挥责任寄予曹休。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-xiu-218-xiabian"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-xiu","locator":"刘备遣吴兰屯下辩","quote":"刘备遣将吴兰屯下辩，太祖遣曹洪征之，以休为骑都尉，参洪军事。太祖谓休曰：“汝虽参军，其实帅也。”"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhen-early-adopted', 'cao-zhen', NULL, NULL, '早年', 'service', '少孤，被曹操收养', '曹真少孤后被曹操收养，与曹丕同处；因勇猛被曹操任为虎豹骑将领。', 'high', 0, '{"id":"cao-zhen-early-adopted","personId":"cao-zhen","year":null,"displayYear":"早年","type":"service","title":"少孤，被曹操收养","summary":"曹真少孤后被曹操收养，与曹丕同处；因勇猛被曹操任为虎豹骑将领。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhen-early-adopted"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhen","locator":"本传开篇","quote":"太祖哀真少孤，收养与诸子同，使与文帝共止……太祖壮其鸷勇，使将虎豹骑。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhen-228-qishan', 'cao-zhen', 228, NULL, '228', 'campaign', '督诸军应对诸葛亮祁山之围', '诸葛亮第一次北伐时，曹真督诸军屯郿，张郃击破马谡，魏军平定响应蜀汉的三郡。', 'high', 0, '{"id":"cao-zhen-228-qishan","personId":"cao-zhen","year":228,"displayYear":"228","type":"campaign","title":"督诸军应对诸葛亮祁山之围","summary":"诸葛亮第一次北伐时，曹真督诸军屯郿，张郃击破马谡，魏军平定响应蜀汉的三郡。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhen-228-qishan"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhen","locator":"诸葛亮围祁山","quote":"诸葛亮围祁山，南安、天水、安定三郡反应亮。帝遣真督诸军军郿，遣张合击亮将马谡，大破之。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-zhen-230-southern-campaign', 'cao-zhen', 230, NULL, '230', 'campaign', '多路伐蜀遇雨撤军', '曹真建议多路伐蜀，曹叡采纳；曹真自长安从子午道南入，但连日大雨、栈道断绝，魏军奉诏撤还。', 'high', 0, '{"id":"cao-zhen-230-southern-campaign","personId":"cao-zhen","year":230,"displayYear":"230","type":"campaign","title":"多路伐蜀遇雨撤军","summary":"曹真建议多路伐蜀，曹叡采纳；曹真自长安从子午道南入，但连日大雨、栈道断绝，魏军奉诏撤还。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-zhen-230-southern-campaign"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhen","locator":"太和四年","quote":"真以“蜀连出侵边境，宜遂伐之。数道并入，可大克也”。帝从其计……真以八月发长安，从子午道南入……会大霖雨三十馀日，或栈道断绝，诏真还军。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-xiong-royal-house-record', 'cao-xiong', 221, NULL, '221-229', 'office', '追封萧怀公，后进王爵', '曹熊早逝，黄初二年追封萧怀公，太和三年又追进为萧怀王。', 'high', 0, '{"id":"cao-xiong-royal-house-record","personId":"cao-xiong","year":221,"displayYear":"221-229","type":"office","title":"追封萧怀公，后进王爵","summary":"曹熊早逝，黄初二年追封萧怀公，太和三年又追进为萧怀王。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-xiong-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-xiong","locator":"本传","quote":"萧怀王熊，早薨。黄初二年追封谥萧怀公。太和三年，又追封爵为王。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-shuo-royal-house-record', 'cao-shuo', 229, NULL, '229', 'office', '追封谥相殇王', '曹铄早逝，太和三年追封谥；其后嗣曹潜、曹偃相继承袭，又皆早卒。', 'high', 0, '{"id":"cao-shuo-royal-house-record","personId":"cao-shuo","year":229,"displayYear":"229","type":"office","title":"追封谥相殇王","summary":"曹铄早逝，太和三年追封谥；其后嗣曹潜、曹偃相继承袭，又皆早卒。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-shuo-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-shuo","locator":"本传","quote":"相殇王铄，早薨，太和三年追封谥。青龙元年，子愍王潜嗣，其年薨。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-ju-royal-house-record', 'cao-ju', 211, 232, '211-232', 'office', '由范阳侯屡徙至彭城王', '曹据建安十六年封范阳侯，此后历宛侯、章陵王、义阳、彭城、济阴、定陶等封号，太和六年复封彭城。', 'high', 0, '{"id":"cao-ju-royal-house-record","personId":"cao-ju","year":211,"displayYear":"211-232","type":"office","title":"由范阳侯屡徙至彭城王","summary":"曹据建安十六年封范阳侯，此后历宛侯、章陵王、义阳、彭城、济阴、定陶等封号，太和六年复封彭城。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-ju-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-ju","locator":"本传","quote":"彭城王据，建安十六年封范阳侯。二十二年，徙封宛侯。黄初二年，进爵为公。三年，为章陵王……太和六年，改封诸王，皆以郡为国，据复封彭城。"}],"endYear":232}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-yu-royal-house-record', 'cao-yu', 211, 239, '211-239', 'office', '由都乡侯至燕王，明帝末年短暂受托', '曹宇字彭祖，建安十六年封都乡侯，太和六年改封燕王；曹叡病重时曾拜其为大将军托以后事，旋因固让和帝意改变而免官。', 'high', 0, '{"id":"cao-yu-royal-house-record","personId":"cao-yu","year":211,"displayYear":"211-239","type":"office","title":"由都乡侯至燕王，明帝末年短暂受托","summary":"曹宇字彭祖，建安十六年封都乡侯，太和六年改封燕王；曹叡病重时曾拜其为大将军托以后事，旋因固让和帝意改变而免官。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-yu-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-yu","locator":"本传","quote":"燕王宇字彭祖。建安十六年，封都乡侯……太和六年，改封燕王。明帝少与宇同止，常爱异之……冬十二月，明帝疾笃，拜宇为大将军，属以后事。受署四日，宇深固让；帝意亦变，遂免宇官。"}],"endYear":239}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-lin-royal-house-record', 'cao-lin', 211, 232, '211-232', 'office', '由饶阳侯历封至沛王', '曹林建安十六年封饶阳侯，后历谯王、鄄城等封号，太和六年改封沛王。', 'high', 0, '{"id":"cao-lin-royal-house-record","personId":"cao-lin","year":211,"displayYear":"211-232","type":"office","title":"由饶阳侯历封至沛王","summary":"曹林建安十六年封饶阳侯，后历谯王、鄄城等封号，太和六年改封沛王。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-lin-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-lin","locator":"本传","quote":"沛穆王林，建安十六年封饶阳侯……太和六年，改封沛。景初、正元、景元中，累增邑，并前四千七百户。林薨，子纬嗣。"}],"endYear":232}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-gun-royal-house-record', 'cao-gun', 216, 232, '216-232', 'office', '由平乡侯至中山王，以好学谨慎见称', '曹衮建安二十一年封平乡侯，少好学能属文；兄弟游娱时，他常研读经典，传中形象较为正面。', 'high', 0, '{"id":"cao-gun-royal-house-record","personId":"cao-gun","year":216,"displayYear":"216-232","type":"office","title":"由平乡侯至中山王，以好学谨慎见称","summary":"曹衮建安二十一年封平乡侯，少好学能属文；兄弟游娱时，他常研读经典，传中形象较为正面。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-gun-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-gun","locator":"本传","quote":"中山恭王衮，建安二十一年封平乡侯。少好学，年十余岁能属文……每兄弟游娱，衮独谭思经典。"}],"endYear":232}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-xuan-royal-house-record', 'cao-xuan', 211, NULL, '211 后', 'office', '封西乡侯后早薨', '曹玹建安十六年封西乡侯，早逝无子，后由曹林子曹赞、曹壹等奉其后。', 'high', 0, '{"id":"cao-xuan-royal-house-record","personId":"cao-xuan","year":211,"displayYear":"211 后","type":"office","title":"封西乡侯后早薨","summary":"曹玹建安十六年封西乡侯，早逝无子，后由曹林子曹赞、曹壹等奉其后。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-xuan-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-xuan","locator":"本传","quote":"济阳怀王玹，建安十六年封西乡侯。早薨，无子。二十年，以沛王林子赞袭玹爵邑，早薨，无子。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-jun-royal-house-record', 'cao-jun', 216, 259, '216-259', 'office', '由郿侯至陈留王，甘露四年薨', '曹峻字子安，建安二十一年封郿侯，后为陈留王，甘露四年去世。', 'high', 0, '{"id":"cao-jun-royal-house-record","personId":"cao-jun","year":216,"displayYear":"216-259","type":"office","title":"由郿侯至陈留王，甘露四年薨","summary":"曹峻字子安，建安二十一年封郿侯，后为陈留王，甘露四年去世。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-jun-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-jun","locator":"本传","quote":"陈留恭王峻字子安，建安二十一年封郿侯。二十二年，徙封襄邑。黄初二年，进爵为公。三年，为陈留王……甘露四年薨。"}],"endYear":259}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-ju-fanyang-royal-house-record', 'cao-ju-fanyang', 217, NULL, '217 后', 'office', '早薨无子，曹敏奉后', '曹矩早逝无子，建安二十二年以樊安公曹均之子曹敏奉其后，后追进为范阳闵王。', 'high', 0, '{"id":"cao-ju-fanyang-royal-house-record","personId":"cao-ju-fanyang","year":217,"displayYear":"217 后","type":"office","title":"早薨无子，曹敏奉后","summary":"曹矩早逝无子，建安二十二年以樊安公曹均之子曹敏奉其后，后追进为范阳闵王。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-ju-fanyang-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-ju-fanyang","locator":"本传","quote":"范阳闵王矩，早薨，无子。建安二十二年，以樊安公均子敏奉矩后，封临晋侯。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-gan-royal-house-record', 'cao-gan', 215, 232, '215-232', 'office', '由高平亭侯至赵王', '曹干建安二十年封高平亭侯，后历赖亭、弘农、燕公、河间王、钜鹿等封号，太和六年改封赵王；因曹丕遗诏，明帝常加恩意。', 'high', 0, '{"id":"cao-gan-royal-house-record","personId":"cao-gan","year":215,"displayYear":"215-232","type":"office","title":"由高平亭侯至赵王","summary":"曹干建安二十年封高平亭侯，后历赖亭、弘农、燕公、河间王、钜鹿等封号，太和六年改封赵王；因曹丕遗诏，明帝常加恩意。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-gan-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-gan","locator":"本传","quote":"赵王干，建安二十年封高平亭侯……太和六年，改封赵王。干母有宠于太祖。及文帝为嗣，干母有力。文帝临崩，有遗诏，是以明帝常加恩意。"}],"endYear":232}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-shang-royal-house-record', 'cao-shang', 231, NULL, '231', 'office', '太和五年追封谥', '曹上早逝，太和五年追封谥，传称无后。', 'high', 0, '{"id":"cao-shang-royal-house-record","personId":"cao-shang","year":231,"displayYear":"231","type":"office","title":"太和五年追封谥","summary":"曹上早逝，太和五年追封谥，传称无后。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-shang-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-shang","locator":"本传","quote":"临邑殇公子上，早薨。太和五年，追封谥。无后。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-biao-royal-house-record', 'cao-biao', 216, 251, '216-251', 'office', '由寿春侯至楚王，后卷入王凌案', '曹彪字朱虎，建安二十一年封寿春侯，太和六年改封楚；嘉平年间王凌、令狐愚谋迎曹彪都许昌，案发后曹彪被迫自尽。', 'high', 0, '{"id":"cao-biao-royal-house-record","personId":"cao-biao","year":216,"displayYear":"216-251","type":"office","title":"由寿春侯至楚王，后卷入王凌案","summary":"曹彪字朱虎，建安二十一年封寿春侯，太和六年改封楚；嘉平年间王凌、令狐愚谋迎曹彪都许昌，案发后曹彪被迫自尽。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-biao-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-biao","locator":"本传","quote":"楚王彪字朱虎。建安二十一年，封寿春侯……嘉平元年，兖州刺史令狐愚与太尉王凌谋迎彪都许昌。语在凌传。乃遣傅及侍御史就国案验……使自图焉。"}],"endYear":251}');
