INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-hui-royal-house-record', 'cao-hui', 217, 242, '217-242', 'office', '由历城侯至东平王', '曹徽奉叔公朗陵哀侯后，建安二十二年封历城侯，太和六年改封东平；青龙二年曾因属官殴县吏被削户，正始三年去世。', 'high', 0, '{"id":"cao-hui-royal-house-record","personId":"cao-hui","year":217,"displayYear":"217-242","type":"office","title":"由历城侯至东平王","summary":"曹徽奉叔公朗陵哀侯后，建安二十二年封历城侯，太和六年改封东平；青龙二年曾因属官殴县吏被削户，正始三年去世。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-hui-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-hui","locator":"本传","quote":"东平灵王徽，奉叔公朗陵哀侯王后。建安二十二年，封历城侯……太和六年，改封东平。青龙二年，徽使官属檛寿张县吏，为有司所奏。诏削县一，户五百。其年复所削县。正始三年薨。"}],"endYear":242}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-mao-prince-royal-house-record', 'cao-mao-prince', 217, 244, '217-244', 'office', '由万岁亭侯至乐陵王', '曹茂建安二十二年封万岁亭侯，因性情骄很、少无宠于曹操，文帝时独不王；太和元年封聊城王，正始五年徙封乐陵。', 'high', 0, '{"id":"cao-mao-prince-royal-house-record","personId":"cao-mao-prince","year":217,"displayYear":"217-244","type":"office","title":"由万岁亭侯至乐陵王","summary":"曹茂建安二十二年封万岁亭侯，因性情骄很、少无宠于曹操，文帝时独不王；太和元年封聊城王，正始五年徙封乐陵。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-mao-prince-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-mao-prince","locator":"本传","quote":"乐陵王茂，建安二十二年封万岁亭侯……茂性慠佷，少无宠于太祖。及文帝世，又独不王。太和元年，徙封聊城公，其年为王。"}],"endYear":244}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-xie-royal-house-record', 'cao-xie', 231, 235, '231-235', 'office', '追封经殇公，后改赞哀王', '曹协早逝，太和五年追封谥经殇公，青龙二年更追改号谥，青龙三年由其子曹寻嗣。', 'high', 0, '{"id":"cao-xie-royal-house-record","personId":"cao-xie","year":231,"displayYear":"231-235","type":"office","title":"追封经殇公，后改赞哀王","summary":"曹协早逝，太和五年追封谥经殇公，青龙二年更追改号谥，青龙三年由其子曹寻嗣。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-xie-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-xie","locator":"本传","quote":"赞哀王协，早薨。太和五年追封谥曰经殇公。青龙二年，更追改号谥。三年，子殇王寻嗣。"}],"endYear":235}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-rui-prince-royal-house-record', 'cao-rui-prince', 226, 233, '226-233', 'office', '封阳平县王，后改北海王', '曹蕤在魏明帝即位后被立为阳平县王，太和六年改封北海，青龙元年去世。', 'high', 0, '{"id":"cao-rui-prince-royal-house-record","personId":"cao-rui-prince","year":226,"displayYear":"226-233","type":"office","title":"封阳平县王，后改北海王","summary":"曹蕤在魏明帝即位后被立为阳平县王，太和六年改封北海，青龙元年去世。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-rui-prince-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-rui-prince","locator":"本传","quote":"北海悼王蕤，黄初七年，明帝即位，立为阳平县王。太和六年，改封北海。青龙元年薨。"}],"endYear":233}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-jian-royal-house-record', 'cao-jian', 225, NULL, '225', 'office', '立为东武阳王，当年薨', '曹鉴黄初六年立为东武阳王，当年去世，青龙三年赐谥，无子国除。', 'high', 0, '{"id":"cao-jian-royal-house-record","personId":"cao-jian","year":225,"displayYear":"225","type":"office","title":"立为东武阳王，当年薨","summary":"曹鉴黄初六年立为东武阳王，当年去世，青龙三年赐谥，无子国除。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-jian-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-jian","locator":"本传","quote":"东武阳怀王鉴，黄初六年立。其年薨。青龙三年赐谥。无子。国除。"}]}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-lin-donghai-royal-house-record', 'cao-lin-donghai', 222, 249, '222-249', 'office', '由河东王改封东海，子曹髦入继大宗', '曹霖黄初三年立为河东王，太和六年改封东海；传称其粗暴，嘉平元年去世，其子曹髦后来入继帝位。', 'high', 0, '{"id":"cao-lin-donghai-royal-house-record","personId":"cao-lin-donghai","year":222,"displayYear":"222-249","type":"office","title":"由河东王改封东海，子曹髦入继大宗","summary":"曹霖黄初三年立为河东王，太和六年改封东海；传称其粗暴，嘉平元年去世，其子曹髦后来入继帝位。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-lin-donghai-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-lin-donghai","locator":"本传","quote":"东海定王霖，黄初三年立为河东王。六年，改封馆陶县。明帝即位，以先帝遗意，爱宠霖异于诸国。而霖性粗暴，闺门之内，婢妾之间，多所残害。太和六年，改封东海。嘉平元年薨……高贵乡公髦，霖之子也，入继大宗。"}],"endYear":249}');
INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('cao-li-royal-house-record', 'cao-li', 221, 229, '221-229', 'office', '封秦公，后改元城王', '曹礼黄初二年封秦公，以京兆郡为国，后改京兆王、元城王，太和三年去世。', 'high', 0, '{"id":"cao-li-royal-house-record","personId":"cao-li","year":221,"displayYear":"221-229","type":"office","title":"封秦公，后改元城王","summary":"曹礼黄初二年封秦公，以京兆郡为国，后改京兆王、元城王，太和三年去世。","relatedEventIds":[],"sourceMentionIds":["mention-sgz-wei-cao-li-record"],"confidence":"high","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-li","locator":"本传","quote":"元城哀王礼，黄初二年封秦公，以京兆郡为国。三年，改为京兆王。六年，改封元城王。太和三年薨。"}],"endYear":229}');
