INSERT INTO "person_life_events" ("id", "person_id", "year", "end_year", "display_year", "type", "title", "summary", "confidence", "approximate", "raw_json") VALUES ('wang-ling-249-251-cao-biao-plot', 'wang-ling', 249, 251, '249-251', 'politics', '谋迎楚王曹彪', '王凌与外甥令狐愚据淮南重兵，因少帝暗弱、受制强臣，谋迎楚王曹彪都许昌；嘉平三年事败，王凌被迫西诣京师途中饮药而死。', 'high', 0, '{"id":"wang-ling-249-251-cao-biao-plot","personId":"wang-ling","year":249,"endYear":251,"displayYear":"249-251","type":"politics","title":"谋迎楚王曹彪","summary":"王凌与外甥令狐愚据淮南重兵，因少帝暗弱、受制强臣，谋迎楚王曹彪都许昌；嘉平三年事败，王凌被迫西诣京师途中饮药而死。","confidence":"high"}');
