INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('zhang-jiao-unknown-birth', 'zh', '生年不详', '生年不详', '张角的早年经历与出生年份缺乏可靠纪年，本项目暂以黄巾起义前的太平道活动作为可追踪起点。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('zhang-jiao-184-yellow-turban', 'zh', '184', '黄巾起义爆发并病死', '张角以太平道组织起义，起义当年即病死；黄巾起义仍成为东汉地方军事化的开端。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('dong-zhuo-unknown-birth', 'zh', '生年不详', '陇西豪强与边地军功出身', '董卓早年活动主要见于边地交游、讨羌胡和凉州军功记载，缺少明确生年。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('dong-zhuo-189-court', 'zh', '189', '入洛阳控制朝廷', '何进被杀后，董卓率兵进入洛阳，控制少帝与陈留王，随后废立皇帝。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('dong-zhuo-192-death', 'zh', '192', '被吕布诛杀', '王允与吕布合谋杀董卓，但其凉州部曲随后反攻长安，朝廷局势继续恶化。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('han-xiandi-181-born', 'zh', '181', '刘协出生', '刘协为汉灵帝子，董卓入洛阳后被立为皇帝。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('han-xiandi-189-enthroned', 'zh', '189', '即位为汉献帝', '董卓废少帝后立陈留王刘协为帝，东汉朝廷进入权臣挟持阶段。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('han-xiandi-196-xu', 'zh', '196', '迁至许都', '曹操迎汉献帝至许，以朝廷名义整合政治资源，汉帝成为曹操集团政治合法性的核心。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('han-xiandi-220-abdication', 'zh', '220', '禅位曹丕', '汉献帝禅位于曹丕，东汉灭亡，曹魏建立。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('han-xiandi-234-death', 'zh', '234', '山阳公刘协去世', '禅位后的刘协被封山阳公，234 年去世。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('yuan-shao-unknown-birth', 'zh', '生年不详', '汝南袁氏出身', '袁绍出自汝南袁氏，早年以名门和士人网络获得声望；明确生年不详。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('yuan-shao-190-coalition', 'zh', '190', '成为关东联军盟主', '关东诸军起兵讨董时，袁绍凭借家世与声望成为联军中心人物。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('yuan-shao-199-hebei', 'zh', '199', '击灭公孙瓒，河北优势成形', '公孙瓒败亡后，袁绍控制河北主要区域，成为官渡前曹操面对的最大北方对手。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('yuan-shao-200-guandu', 'zh', '200', '官渡失利', '袁绍南攻曹操，在官渡相持后因乌巢粮秣被袭、将领降曹等因素失败，北方优势急剧削弱。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('yuan-shao-202-death', 'zh', '202', '袁绍去世', '袁绍死后，袁谭、袁尚等继承纷争加速河北集团瓦解。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('yan-liang-unknown-birth', 'zh', '生年不详', '早年不详', '颜良的早年履历不详，史料主要集中在袁绍南攻曹操前后的军事活动。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('yan-liang-200-boma', 'zh', '200', '白马之战被关羽斩杀', '袁绍遣颜良攻白马，曹操派张辽、关羽为先锋，关羽斩颜良，白马之围遂解。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('yan-liang-hebei-tradition', 'zh', '后世称呼', '列入河北四庭柱传统', '颜良与文丑、张郃、高览并称“河北四庭柱”属于后世通俗叙事归类，本项目仅作传统标签。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('wen-chou-unknown-birth', 'zh', '生年不详', '早年不详', '文丑的早年履历不详，史料主要保存其作为袁绍名将参与官渡前哨战的片段。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('wen-chou-200-yanjin', 'zh', '200', '延津方向败亡', '颜良死后，文丑继续参与袁绍军前哨作战，在延津方向被曹军击败并败亡。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('wen-chou-hebei-tradition', 'zh', '后世称呼', '列入河北四庭柱传统', '文丑并入“河北四庭柱”是后世通俗归纳，反映其在袁绍武将叙事中的代表性。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('zhang-he-unknown-birth', 'zh', '生年不详', '河间鄚人', '张郃为河间鄚人，汉末应募讨黄巾，后从韩馥转入袁绍集团；生年不详。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('zhang-he-200-defection', 'zh', '200', '官渡归降曹操', '乌巢转折后，张郃归降曹操。张郃传与武帝纪、袁绍传对降曹先后有细节差异，项目保留为“官渡转折期归曹”。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('zhang-he-228-jieting', 'zh', '228', '街亭击破马谡', '诸葛亮第一次北伐时，张郃在街亭击破马谡，迫使蜀军退兵。', '{}');
