INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-cao-174-xiaolian', 'zh', '约174', '举孝廉，任洛阳北部尉', '曹操二十岁左右举孝廉入仕，历任郎、洛阳北部尉、顿丘令，进入东汉官僚体系。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-cao-184-yellow-turban', 'zh', '184', '讨黄巾，转任济南相', '黄巾起义爆发后，曹操以骑都尉讨颍川黄巾，随后出任济南相，开始积累地方治理声望。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-cao-189-dong-zhuo-east', 'zh', '189', '拒董卓任命，变姓名东归', '董卓控制洛阳后表曹操为骁骑校尉，曹操没有接受，而是改名潜行东归，为之后起兵讨董铺垫。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-cao-192-yanzhou-qingzhou', 'zh', '192', '领兖州牧，收青州兵', '刘岱死后，鲍信等迎曹操领兖州牧；同年收降青州黄巾，形成后来曹操军力中的重要兵源。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-cao-197-wan-defeat', 'zh', '197', '宛城败于张绣', '张绣先降后叛，曹操在宛城失利，长子曹昂与侄曹安民遇害，是曹操早期扩张中的重大挫折。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-cao-207-white-wolf', 'zh', '207', '白狼山破乌桓', '曹操北征乌桓，出卢龙塞，白狼山遇敌后以张辽为先锋击破蹋顿，袁氏余部北方依托被切断。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-cao-211-tongguan', 'zh', '211', '潼关西征马超韩遂', '关中诸将疑惧反叛后，曹操西征马超、韩遂等，先令诸将坚壁不战，再渡河展开关中战事。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-cao-217-cao-pi-heir', 'zh', '217', '立曹丕为魏太子', '曹操晚年确立曹丕为魏太子，完成魏王集团继承次序安排。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-pi-211-wuguan', 'zh', '211', '任五官中郎将、副丞相', '曹丕在建安十六年任五官中郎将、副丞相，开始进入曹操集团最高层的制度化继承序列。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-pi-217-heir', 'zh', '217', '立为魏太子', '曹丕被立为魏太子，正式压过曹植等竞争者，成为曹操政治遗产的继承人。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-pi-221-sun-quan-vassal', 'zh', '221', '册封孙权为吴王', '孙权向魏遣使奉章并归还于禁等，曹丕册拜孙权为大将军、吴王，魏吴关系短暂转入名义臣属状态。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-pi-222-south-campaign', 'zh', '222', '治兵南征', '夷陵战后魏吴关系重新紧张，曹丕在东郊治兵后南征，试图利用吴蜀战后格局压迫孙吴。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-pi-225-guangling', 'zh', '225', '广陵临江观兵', '曹丕东巡至广陵故城，临江陈兵十余万，展示对孙吴方向的军事压力。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-rui-204-born', 'zh', '204', '曹叡出生', '曹叡为曹丕之子，字元仲；《明帝纪》称其幼年受曹操喜爱，常在左右。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-rui-220-enfeoffment', 'zh', '220-222', '封武德侯、齐公、平原王', '曹叡黄初年间先封武德侯，后为齐公、平原王；因甄后之事，起初未被立即确定为继嗣。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-rui-226-accession', 'zh', '226', '立为皇太子并即位', '曹丕病重时立曹叡为皇太子；同日曹叡即皇帝位，曹魏进入明帝时期。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-rui-228-zhuge-liang-first-northern-expedition', 'zh', '228', '应对诸葛亮第一次北伐', '诸葛亮攻边，天水、南安、安定响应；曹叡调度曹真、张郃等关右兵力应对，魏蜀战争进入明帝时期主轴。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-rui-234-wuzhang', 'zh', '234', '五丈原相持，诸葛亮卒', '诸葛亮出斜谷屯渭南，司马懿率魏军拒守；诸葛亮去世后蜀军撤退，曹魏西线压力暂缓。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-rui-238-liaodong', 'zh', '238', '遣司马懿平辽东', '曹叡决意以大兵讨公孙渊，司马懿围襄平并斩送公孙渊首级，辽东公孙氏政权灭亡。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-rui-239-death', 'zh', '239', '魏明帝去世', '曹叡临终托付曹芳、曹爽、司马懿等，随后崩于嘉福殿，曹魏进入少帝与辅政格局。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhang-early-martial', 'zh', '早年', '以武勇见称', '曹彰字子文，少善射御、膂力过人，自陈志在为卫青、霍去病式的骑将。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhang-218-daijun', 'zh', '218', '北征代郡乌丸', '代郡乌丸反叛时，曹彰为北中郎将、行骁骑将军，率军北征并以武勇立功。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhang-222-rencheng', 'zh', '222', '立为任城王', '曹丕黄初三年立曹彰为任城王，宗室诸王分封体系进一步成形。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhang-223-death', 'zh', '223', '朝京都，疾薨于邸', '曹彰入朝京都后病逝于邸舍，谥为威，后世围绕其入朝与暴薨有不同说法。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhi-192-birth', 'zh', '约192', '曹植出生', '曹植字子建，卒年四十一，据《陈思王植传》卒年反推约生于初平三年前后。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhi-early-literary-talent', 'zh', '约203', '少有文才', '曹植十余岁已能诵读大量诗论辞赋，善于属文，是建安文学中最重要的曹氏宗室人物。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhi-210-copper-terrace', 'zh', '约210', '铜雀台援笔立成', '曹操带诸子登邺城铜雀台命作赋，曹植援笔立成，受到曹操特别赏识。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhi-217-succession-rivalry', 'zh', '217 前后', '参与继承竞争并失势', '曹植因才学被曹操看重，一度几乎成为太子候选；但其任性饮酒，与曹丕的自饰经营形成反差，最终曹丕被立为魏太子。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhi-221-demotion', 'zh', '221', '贬爵安乡侯', '曹丕即位后，曹植被奏称醉酒悖慢、胁迫使者，有司请罪；曹丕因卞太后缘故不杀，贬其爵。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhi-232-death', 'zh', '232', '封陈王后病逝', '曹叡太和六年，以陈四县封曹植为陈王；曹植多次求试用不得，忧郁发病而卒，年四十一。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-chong-196-birth', 'zh', '约196', '曹冲出生', '曹冲字仓舒，建安十三年卒时年十三，据此约生于建安元年前后。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-chong-early-talent', 'zh', '约201-202', '幼年聪察早慧', '曹冲五六岁时已被称有成人之智，是曹操诸子中最具早慧形象的人物之一。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-chong-elephant', 'zh', '约201-202', '曹冲称象', '孙权进献巨象，群臣无法测重，曹冲提出以船载象、刻水痕、再称物相校的方法。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-chong-mercy', 'zh', '约206', '为库吏解鼠啮马鞍之罪', '曹冲利用衣物被鼠啮的说法，替因曹操马鞍被鼠啮而恐惧受死的库吏开解，传记借此突出其仁爱与机智。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-chong-208-death', 'zh', '208', '十三岁病逝', '曹冲建安十三年病逝，曹操哀甚，并对曹丕说这是自己的不幸、诸子的幸运，反映曹冲曾被寄予很高期待。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-ang-early-xiaolian', 'zh', '弱冠', '弱冠举孝廉', '曹昂字子修，弱冠时举孝廉，是曹操早年成年的长子。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-ang-197-death', 'zh', '197', '随曹操南征，为张绣所害', '曹昂随曹操南征宛城，张绣复叛后遇害；《武帝纪》还记其与曹安民同死于宛城败局。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-shuang-239-regency', 'zh', '239', '受明帝遗诏辅少主', '曹叡病重时拜曹爽为大将军，假节钺、都督中外诸军事、录尚书事，与司马懿共同辅佐曹芳。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-shuang-240-power-network', 'zh', '正始初', '曹氏兄弟出入禁闼，权势转盛', '曹爽辅政后，曹羲、曹训、曹彦等兄弟分居禁军和侍从要职，何晏、邓飏、李胜、丁谧等成为腹心。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-shuang-244-shu-campaign', 'zh', '244', '骆谷伐蜀失利', '曹爽为立威名发动伐蜀，自长安发卒六七万人入骆谷，因转输困难和蜀军据险，最终无功而返。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-shuang-249-gaopingling', 'zh', '249', '高平陵政变中失势', '曹芳谒高平陵时曹爽兄弟随行出城，司马懿据武库、屯洛水浮桥，曹爽失去洛阳中枢控制。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-shuang-249-death', 'zh', '249', '曹爽及党羽伏诛', '高平陵之后，曹爽、曹羲、曹训、何晏、邓飏、丁谧等被诛并夷三族，司马氏掌握曹魏政局。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-fang-235-qi-wang', 'zh', '235', '立为齐王', '曹芳幼年入魏明帝后嗣体系，青龙三年被立为齐王，是其入继皇位前的身份基础。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-fang-239-enthroned', 'zh', '239', '明帝病重，曹芳即位', '魏明帝病重时立曹芳为皇太子，当日即皇帝位；曹爽与司马懿同受托辅政，曹魏进入少帝政治。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-fang-249-gaopingling', 'zh', '249', '高平陵政变中失去曹爽辅政体系', '曹芳谒高平陵时，司马懿在洛阳发动政变，奏免曹爽兄弟官职；此后曹魏中枢权力转入司马氏。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-fang-254-deposed', 'zh', '254', '司马师谋废，曹芳归藩于齐', '司马师以郭太后令废曹芳帝位，遣其归藩为齐王；曹魏皇位转由高贵乡公曹髦继承。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-mao-244-gaogui', 'zh', '244', '封高贵乡公', '曹髦为曹丕之孙、东海定王曹霖之子，正始五年被封为高贵乡公，传称少好学、夙成。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-mao-254-enthroned', 'zh', '254', '齐王废后被迎立', '曹芳被废后，公卿迎立曹髦；曹髦入洛阳时仍以人臣自处，随后在太极前殿即皇帝位。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-mao-260-sima-zhao', 'zh', '260', '称“司马昭之心，路人所知”', '曹髦面对司马昭权势日盛，召王沈、王经、王业等言明不愿坐受废辱，决定亲自讨伐司马昭。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-mao-260-death', 'zh', '260', '南阙下被弑', '曹髦率僮仆宿卫出宫，被贾充所部阻击；太子舍人成济刺杀曹髦，曹魏皇权与司马氏矛盾公开化。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-huan-258-changdao', 'zh', '258', '封常道乡公', '曹奂为曹操之孙、燕王曹宇之子，甘露三年被封为安次县常道乡公。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-huan-260-enthroned', 'zh', '260', '曹髦死后被迎立', '高贵乡公曹髦被弑后，公卿迎立曹奂；他入洛阳见皇太后，当日在太极前殿即位。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-huan-263-shu-surrender', 'zh', '263', '魏灭蜀汉', '曹奂在位时，邓艾、钟会伐蜀，刘禅向邓艾投降，蜀汉灭亡；这是曹魏后期最重大的军事成果。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-huan-265-abdication', 'zh', '265', '禅位于晋', '咸熙二年，曹奂下诏禅位于晋王司马炎，曹魏政权结束；曹奂随后被封为陈留王。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-ren-early', 'zh', '早年', '少好弓马，从曹操起兵', '曹仁是曹操从弟，少好弓马，汉末豪杰并起时聚众千余人，随后从曹操起兵。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-ren-208-jiangling', 'zh', '208 后', '留屯江陵，拒周瑜', '曹操平荆州后，曹仁以行征南将军留守江陵，对抗周瑜，是赤壁后曹魏南线防御核心。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-ren-219-fancheng', 'zh', '219', '襄樊危机中坚守樊城', '关羽围樊城、水淹七军后，曹仁在粮尽援绝中坚守，直至徐晃救援而解围。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-ren-222-grand-marshal', 'zh', '222 前后', '拜大将军，迁大司马', '曹丕时期，曹仁拜大将军、迁大司马，仍负责南线、东线军事调度。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-hong-190-save-cao-cao', 'zh', '190', '荥阳败后让马救曹操', '曹操讨董卓至荥阳败于徐荣，曹洪下马授曹操，并称天下可无洪不可无君，是其传中最著名事迹。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-hong-194-yan-zhou', 'zh', '194', '兖州危机中聚粮继军', '张邈迎吕布、兖州危机爆发时，曹洪先据东平、范，聚粮接济曹操军队。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-hong-226-later-office', 'zh', '226 后', '明帝即位后复任后将军、骠骑将军', '曹洪在曹丕时期曾几乎获罪，魏明帝即位后再受任用，拜后将军、特进、骠骑将军。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-hong-232-death', 'zh', '232', '薨，谥恭侯', '曹洪太和六年去世，谥恭侯，其子曹馥嗣爵。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-xiu-early-qianliju', 'zh', '早年', '归曹操，被称“千里驹”', '曹休少孤避乱至吴地，后北归曹操，被称为“吾家千里驹”，与曹丕同处并领虎豹骑。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-xiu-218-xiabian', 'zh', '218', '下辩战事中参曹洪军事', '刘备遣吴兰屯下辩时，曹休为骑都尉参曹洪军事，曹操实际将指挥责任寄予曹休。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhen-early-adopted', 'zh', '早年', '少孤，被曹操收养', '曹真少孤后被曹操收养，与曹丕同处；因勇猛被曹操任为虎豹骑将领。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhen-228-qishan', 'zh', '228', '督诸军应对诸葛亮祁山之围', '诸葛亮第一次北伐时，曹真督诸军屯郿，张郃击破马谡，魏军平定响应蜀汉的三郡。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zhen-230-southern-campaign', 'zh', '230', '多路伐蜀遇雨撤军', '曹真建议多路伐蜀，曹叡采纳；曹真自长安从子午道南入，但连日大雨、栈道断绝，魏军奉诏撤还。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-xiong-royal-house-record', 'zh', '221-229', '追封萧怀公，后进王爵', '曹熊早逝，黄初二年追封萧怀公，太和三年又追进为萧怀王。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-shuo-royal-house-record', 'zh', '229', '追封谥相殇王', '曹铄早逝，太和三年追封谥；其后嗣曹潜、曹偃相继承袭，又皆早卒。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-ju-royal-house-record', 'zh', '211-232', '由范阳侯屡徙至彭城王', '曹据建安十六年封范阳侯，此后历宛侯、章陵王、义阳、彭城、济阴、定陶等封号，太和六年复封彭城。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-yu-royal-house-record', 'zh', '211-239', '由都乡侯至燕王，明帝末年短暂受托', '曹宇字彭祖，建安十六年封都乡侯，太和六年改封燕王；曹叡病重时曾拜其为大将军托以后事，旋因固让和帝意改变而免官。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-lin-royal-house-record', 'zh', '211-232', '由饶阳侯历封至沛王', '曹林建安十六年封饶阳侯，后历谯王、鄄城等封号，太和六年改封沛王。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-gun-royal-house-record', 'zh', '216-232', '由平乡侯至中山王，以好学谨慎见称', '曹衮建安二十一年封平乡侯，少好学能属文；兄弟游娱时，他常研读经典，传中形象较为正面。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-xuan-royal-house-record', 'zh', '211 后', '封西乡侯后早薨', '曹玹建安十六年封西乡侯，早逝无子，后由曹林子曹赞、曹壹等奉其后。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-jun-royal-house-record', 'zh', '216-259', '由郿侯至陈留王，甘露四年薨', '曹峻字子安，建安二十一年封郿侯，后为陈留王，甘露四年去世。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-ju-fanyang-royal-house-record', 'zh', '217 后', '早薨无子，曹敏奉后', '曹矩早逝无子，建安二十二年以樊安公曹均之子曹敏奉其后，后追进为范阳闵王。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-gan-royal-house-record', 'zh', '215-232', '由高平亭侯至赵王', '曹干建安二十年封高平亭侯，后历赖亭、弘农、燕公、河间王、钜鹿等封号，太和六年改封赵王；因曹丕遗诏，明帝常加恩意。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-shang-royal-house-record', 'zh', '231', '太和五年追封谥', '曹上早逝，太和五年追封谥，传称无后。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-biao-royal-house-record', 'zh', '216-251', '由寿春侯至楚王，后卷入王凌案', '曹彪字朱虎，建安二十一年封寿春侯，太和六年改封楚；嘉平年间王凌、令狐愚谋迎曹彪都许昌，案发后曹彪被迫自尽。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-qin-royal-house-record', 'zh', '231', '太和五年追封谥', '曹勤早逝，太和五年追封谥，传称无后。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-cheng-royal-house-record', 'zh', '231', '太和五年追封谥', '曹乘早逝，太和五年追封谥，传称无后。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-zheng-royal-house-record', 'zh', '217-218', '封郿侯后次年薨', '曹整奉从叔父郎中曹绍后，建安二十二年封郿侯，次年去世无子，黄初二年追进爵并谥戴公。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-jing-royal-house-record', 'zh', '231', '太和五年追封谥', '曹京早逝，太和五年追封谥，传称无后。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-jun-fan-royal-house-record', 'zh', '217-219', '封樊侯，建安二十四年薨', '曹均奉叔父蓟恭公曹彬后，建安二十二年封樊侯，二十四年去世，其子曹抗嗣。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-ji-royal-house-record', 'zh', '231', '太和五年追封谥', '曹棘早逝，太和五年追封谥，传称无后。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-hui-royal-house-record', 'zh', '217-242', '由历城侯至东平王', '曹徽奉叔公朗陵哀侯后，建安二十二年封历城侯，太和六年改封东平；青龙二年曾因属官殴县吏被削户，正始三年去世。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-mao-prince-royal-house-record', 'zh', '217-244', '由万岁亭侯至乐陵王', '曹茂建安二十二年封万岁亭侯，因性情骄很、少无宠于曹操，文帝时独不王；太和元年封聊城王，正始五年徙封乐陵。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-xie-royal-house-record', 'zh', '231-235', '追封经殇公，后改赞哀王', '曹协早逝，太和五年追封谥经殇公，青龙二年更追改号谥，青龙三年由其子曹寻嗣。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-rui-prince-royal-house-record', 'zh', '226-233', '封阳平县王，后改北海王', '曹蕤在魏明帝即位后被立为阳平县王，太和六年改封北海，青龙元年去世。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-jian-royal-house-record', 'zh', '225', '立为东武阳王，当年薨', '曹鉴黄初六年立为东武阳王，当年去世，青龙三年赐谥，无子国除。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-lin-donghai-royal-house-record', 'zh', '222-249', '由河东王改封东海，子曹髦入继大宗', '曹霖黄初三年立为河东王，太和六年改封东海；传称其粗暴，嘉平元年去世，其子曹髦后来入继帝位。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-li-royal-house-record', 'zh', '221-229', '封秦公，后改元城王', '曹礼黄初二年封秦公，以京兆郡为国，后改京兆王、元城王，太和三年去世。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-yong-royal-house-record', 'zh', '221-229', '封淮南公，后改邯郸王', '曹邕黄初二年封淮南公，以九江郡为国，后改淮南王、陈王、邯郸王，太和三年去世。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-gong-royal-house-record', 'zh', '222-223', '封清河王，次年薨', '曹贡黄初三年受封，黄初四年去世，无子国除。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('cao-yan-royal-house-record', 'zh', '222-223', '封广平王，次年薨', '曹俨黄初三年受封，黄初四年去世，无子国除。', '{}');
INSERT INTO "person_life_event_i18n" ("life_event_id", "locale", "display_year", "title", "summary", "raw_json") VALUES ('wang-ling-249-251-cao-biao-plot', 'zh', '249-251', '谋迎楚王曹彪', '王凌与外甥令狐愚据淮南重兵，因少帝暗弱、受制强臣，谋迎楚王曹彪都许昌；嘉平三年事败，王凌被迫西诣京师途中饮药而死。', '{}');

