INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-155-born', 'sanguozhi-wei-wudi', '武帝纪', '太祖武皇帝，沛国谯人也，姓曹，讳操，字孟德，汉相国参之后。', '{"sourceId":"sanguozhi-wei-wudi","locator":"武帝纪","quote":"太祖武皇帝，沛国谯人也，姓曹，讳操，字孟德，汉相国参之后。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-196-xu', 'sanguozhi-wei-wudi', '建安元年', '太祖将迎天子，诸将或疑，荀彧、程昱劝之，乃遣曹洪将兵西迎。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安元年","quote":"太祖将迎天子，诸将或疑，荀彧、程昱劝之，乃遣曹洪将兵西迎。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-196-xu', 'houhanshu-xiandi', '建安元年', NULL, '{"sourceId":"houhanshu-xiandi","locator":"建安元年"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-190-coalition', 'sanguozhi-wei-wudi', '初平元年', '初平元年春正月，后将军袁术、冀州牧韩馥等同时俱起兵，众各数万，推绍为盟主。太祖行奋武将军。', '{"sourceId":"sanguozhi-wei-wudi","locator":"初平元年","quote":"初平元年春正月，后将军袁术、冀州牧韩馥等同时俱起兵，众各数万，推绍为盟主。太祖行奋武将军。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-190-coalition', 'zizhi-tongjian-59', '初平元年', NULL, '{"sourceId":"zizhi-tongjian-59","locator":"初平元年"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-194-yanzhou-crisis', 'sanguozhi-wei-wudi', '兴平元年至二年', '会张邈与陈宫叛迎吕布，郡县皆应。荀彧、程昱保鄄城，范、东阿二县固守，太祖乃引军还。', '{"sourceId":"sanguozhi-wei-wudi","locator":"兴平元年至二年","quote":"会张邈与陈宫叛迎吕布，郡县皆应。荀彧、程昱保鄄城，范、东阿二县固守，太祖乃引军还。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-194-yanzhou-crisis', 'sanguozhi-wei-lubu', '吕布传', NULL, '{"sourceId":"sanguozhi-wei-lubu","locator":"吕布传"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-199-xiapi', 'sanguozhi-wei-wudi', '建安三年至四年', '月馀，布将宋宪、魏续等执陈宫，举城降，生禽布、宫，皆杀之。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安三年至四年","quote":"月馀，布将宋宪、魏续等执陈宫，举城降，生禽布、宫，皆杀之。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-199-xiapi', 'sanguozhi-wei-lubu', '吕布传', NULL, '{"sourceId":"sanguozhi-wei-lubu","locator":"吕布传"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-200-guandu', 'sanguozhi-wei-wudi', '建安五年', '公乃留曹洪守，自将步骑五千人夜往，会明至。公急击之，琼退保营，遂攻之。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安五年","quote":"公乃留曹洪守，自将步骑五千人夜往，会明至。公急击之，琼退保营，遂攻之。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-200-guandu', 'zizhi-tongjian-63', '建安五年', NULL, '{"sourceId":"zizhi-tongjian-63","locator":"建安五年"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-204-hebei', 'sanguozhi-wei-wudi', '建安九年至十二年', '八月，审配兄子荣夜开所守城东门内兵。配逆战，败，生禽配，斩之，邺定。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安九年至十二年","quote":"八月，审配兄子荣夜开所守城东门内兵。配逆战，败，生禽配，斩之，邺定。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-204-hebei', 'zizhi-tongjian-63', '河北战事延续', NULL, '{"sourceId":"zizhi-tongjian-63","locator":"河北战事延续"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-208-red-cliffs', 'sanguozhi-wei-wudi', '建安十三年', '公至赤壁，与备战，不利。于是大疫，吏士多死者，乃引军还。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安十三年","quote":"公至赤壁，与备战，不利。于是大疫，吏士多死者，乃引军还。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-208-red-cliffs', 'zizhi-tongjian-65', '建安十三年', NULL, '{"sourceId":"zizhi-tongjian-65","locator":"建安十三年"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-213-duke-wei', 'sanguozhi-wei-wudi', '建安十八年', '五月丙申，天子使御史大夫郗虑持节策命公为魏公。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安十八年","quote":"五月丙申，天子使御史大夫郗虑持节策命公为魏公。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-215-hanzhong', 'sanguozhi-wei-wudi', '建安二十年', '公军入南郑，尽得鲁府库珍宝。巴、汉皆降。复汉宁郡为汉中。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安二十年","quote":"公军入南郑，尽得鲁府库珍宝。巴、汉皆降。复汉宁郡为汉中。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-215-hanzhong', 'sanguozhi-wei-zhang-lu', '张鲁传', NULL, '{"sourceId":"sanguozhi-wei-zhang-lu","locator":"张鲁传"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-216-king-wei', 'sanguozhi-wei-wudi', '建安二十一年', '夏五月，天子进公爵为魏王。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安二十一年","quote":"夏五月，天子进公爵为魏王。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-219-hanzhong-retreat', 'sanguozhi-wei-wudi', '建安二十四年', '秋七月，以夫人卞氏为王后。遣于禁助曹仁击关羽。八月，汉水溢，灌禁军，军没，羽获禁，遂围仁。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安二十四年","quote":"秋七月，以夫人卞氏为王后。遣于禁助曹仁击关羽。八月，汉水溢，灌禁军，军没，羽获禁，遂围仁。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-219-hanzhong-retreat', 'zizhi-tongjian-67', '建安二十四年', NULL, '{"sourceId":"zizhi-tongjian-67","locator":"建安二十四年"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-220-death', 'sanguozhi-wei-wudi', '建安二十五年', '庚子，王崩于洛阳，年六十六。遗令曰：“天下尚未安定，未得遵古也。”', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安二十五年","quote":"庚子，王崩于洛阳，年六十六。遗令曰：“天下尚未安定，未得遵古也。”"}');
