INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-pi-226-death', 'sanguozhi-wei-wendi', '黄初七年五月', '夏五月丙辰，帝疾笃，召中军大将军曹真、镇军大将军陈羣、征东大将军曹休、抚军大将军司马宣王，并受遗诏辅嗣主。丁巳，帝崩于嘉福殿，时年四十。', '{"sourceId":"sanguozhi-wei-wendi","locator":"黄初七年五月","quote":"夏五月丙辰，帝疾笃，召中军大将军曹真、镇军大将军陈羣、征东大将军曹休、抚军大将军司马宣王，并受遗诏辅嗣主。丁巳，帝崩于嘉福殿，时年四十。"}');
