INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('liu-bei-223-death', 'sanguozhi-shu-xianzhu', '章武三年', '先主病笃，托孤于丞相亮，尚书令李严为副。夏四月癸巳，先主殂于永安宫，时年六十三。', '{"sourceId":"sanguozhi-shu-xianzhu","locator":"章武三年","quote":"先主病笃，托孤于丞相亮，尚书令李严为副。夏四月癸巳，先主殂于永安宫，时年六十三。"}');
