INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('zhuge-liang-181-born', 'sanguozhi-shu-zhuge-liang', '诸葛亮传', '诸葛亮字孔明，琅邪阳都人也。汉司隶校尉诸葛丰后也。', '{"sourceId":"sanguozhi-shu-zhuge-liang","locator":"诸葛亮传","quote":"诸葛亮字孔明，琅邪阳都人也。汉司隶校尉诸葛丰后也。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('zhuge-liang-207-longzhong', 'sanguozhi-shu-zhuge-liang', '诸葛亮传', '亮答曰：“自董卓已来，豪杰并起，跨州连郡者不可胜数。”', '{"sourceId":"sanguozhi-shu-zhuge-liang","locator":"诸葛亮传","quote":"亮答曰：“自董卓已来，豪杰并起，跨州连郡者不可胜数。”"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('zhuge-liang-223-regency', 'sanguozhi-shu-zhuge-liang', '建兴元年', '建兴元年，封亮武乡侯，开府治事。顷之，又领益州牧。', '{"sourceId":"sanguozhi-shu-zhuge-liang","locator":"建兴元年","quote":"建兴元年，封亮武乡侯，开府治事。顷之，又领益州牧。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('zhuge-liang-234-death', 'sanguozhi-shu-zhuge-liang', '诸葛亮传', '相持百馀日。其年八月，亮疾病，卒于军，时年五十四。', '{"sourceId":"sanguozhi-shu-zhuge-liang","locator":"诸葛亮传","quote":"相持百馀日。其年八月，亮疾病，卒于军，时年五十四。"}');
