INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-182-born', 'sanguozhi-wu-wuzhu', '吴主传', '孙权字仲谋。兄策既定诸郡，时权年十五，以为阳羡长。', '{"sourceId":"sanguozhi-wu-wuzhu","locator":"吴主传","quote":"孙权字仲谋。兄策既定诸郡，时权年十五，以为阳羡长。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-200-succeeds-jiangdong', 'sanguozhi-wu-wuzhu', '建安五年孙策卒后', '五年，策薨，以事授权，权哭未及息。张昭谓权曰：“此宁哭时邪？”乃改易权服，扶令上马，使出巡军。', '{"sourceId":"sanguozhi-wu-wuzhu","locator":"建安五年孙策卒后","quote":"五年，策薨，以事授权，权哭未及息。张昭谓权曰：“此宁哭时邪？”乃改易权服，扶令上马，使出巡军。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-208-red-cliffs', 'sanguozhi-wu-wuzhu', '建安十三年', '惟瑜、肃执拒之议，意与权同。瑜、普为左右督，各领万人，与备俱进，遇于赤壁，大破曹公军。', '{"sourceId":"sanguozhi-wu-wuzhu","locator":"建安十三年","quote":"惟瑜、肃执拒之议，意与权同。瑜、普为左右督，各领万人，与备俱进，遇于赤壁，大破曹公军。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-208-red-cliffs', 'sanguozhi-wu-zhou-yu', '周瑜、鲁肃传赤壁相关记载', NULL, '{"sourceId":"sanguozhi-wu-zhou-yu","locator":"周瑜、鲁肃传赤壁相关记载"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-215-hefei', 'sanguozhi-wu-wuzhu', '建安二十年合肥相关记载', '合肥未下，彻军还。兵皆就路，权与凌统、甘宁等在津北为魏将张辽所袭，统等以死捍权，权乘骏马越津桥得去。', '{"sourceId":"sanguozhi-wu-wuzhu","locator":"建安二十年合肥相关记载","quote":"合肥未下，彻军还。兵皆就路，权与凌统、甘宁等在津北为魏将张辽所袭，统等以死捍权，权乘骏马越津桥得去。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-215-hefei', 'zizhi-tongjian-67', '建安二十年', NULL, '{"sourceId":"zizhi-tongjian-67","locator":"建安二十年"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-219-jingzhou', 'sanguozhi-wu-wuzhu', '建安二十四年', '闰月，权征羽，先遣吕蒙袭公安，获将军士仁。蒙到南郡，南郡太守麋芳以城降。', '{"sourceId":"sanguozhi-wu-wuzhu","locator":"建安二十四年","quote":"闰月，权征羽，先遣吕蒙袭公安，获将军士仁。蒙到南郡，南郡太守麋芳以城降。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-219-jingzhou', 'sanguozhi-wu-zhou-yu', '吕蒙传荆州相关记载', NULL, '{"sourceId":"sanguozhi-wu-zhou-yu","locator":"吕蒙传荆州相关记载"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-219-jingzhou', 'zizhi-tongjian-67', '建安二十四年', NULL, '{"sourceId":"zizhi-tongjian-67","locator":"建安二十四年"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-222-king-wu', 'sanguozhi-wu-wuzhu', '黄武元年', '黄武元年春正月，陆逊部将军宋谦等攻蜀五屯，皆破之，斩其将。', '{"sourceId":"sanguozhi-wu-wuzhu","locator":"黄武元年","quote":"黄武元年春正月，陆逊部将军宋谦等攻蜀五屯，皆破之，斩其将。"}');
