INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-229-emperor', 'sanguozhi-wu-wuzhu', '黄龙元年', '黄龙元年春，公卿百司皆劝权正尊号。夏四月，夏口、武昌并言黄龙、凤凰见。丙申，南郊即皇帝位。', '{"sourceId":"sanguozhi-wu-wuzhu","locator":"黄龙元年","quote":"黄龙元年春，公卿百司皆劝权正尊号。夏四月，夏口、武昌并言黄龙、凤凰见。丙申，南郊即皇帝位。"}');
