INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('sun-quan-252-death', 'sanguozhi-wu-wuzhu', '吴主传', '夏四月，权薨，时年七十一，谥曰大皇帝。秋七月，葬蒋陵。', '{"sourceId":"sanguozhi-wu-wuzhu","locator":"吴主传","quote":"夏四月，权薨，时年七十一，谥曰大皇帝。秋七月，葬蒋陵。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('shi-xie-137-born', 'sanguozhi-wu-shi-xie', '士燮传', '士燮字威彦，苍梧广信人也。', '{"sourceId":"sanguozhi-wu-shi-xie","locator":"士燮传","quote":"士燮字威彦，苍梧广信人也。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('shi-xie-210-submits-wu', 'sanguozhi-wu-shi-xie', '建安十五年前后', '建安十五年，孙权遣步隲为交州刺史。隲到，燮率兄弟奉承节度。', '{"sourceId":"sanguozhi-wu-shi-xie","locator":"建安十五年前后","quote":"建安十五年，孙权遣步隲为交州刺史。隲到，燮率兄弟奉承节度。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('shi-xie-226-death', 'sanguozhi-wu-shi-xie', '黄武五年', '燮在郡四十馀岁，黄武五年，年九十卒。', '{"sourceId":"sanguozhi-wu-shi-xie","locator":"黄武五年","quote":"燮在郡四十馀岁，黄武五年，年九十卒。"}');
