INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('zhou-yu-175-born', 'sanguozhi-wu-zhou-yu', '周瑜传', '周瑜字公瑾，庐江舒人也。从祖父景，景子忠，皆为汉太尉。', '{"sourceId":"sanguozhi-wu-zhou-yu","locator":"周瑜传","quote":"周瑜字公瑾，庐江舒人也。从祖父景，景子忠，皆为汉太尉。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('zhou-yu-208-red-cliffs', 'sanguozhi-wu-zhou-yu', '周瑜传赤壁相关记载', '权遂遣瑜及程普等与备并力逆曹公，遇于赤壁。时曹公军众已有疾病，初一交战，公军败退。', '{"sourceId":"sanguozhi-wu-zhou-yu","locator":"周瑜传赤壁相关记载","quote":"权遂遣瑜及程普等与备并力逆曹公，遇于赤壁。时曹公军众已有疾病，初一交战，公军败退。"}');
