INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('lu-xun-183-born', 'sanguozhi-wu-lu-xun', '陆逊传', '陆逊字伯言，吴郡吴人也。本名议，世江东大族。', '{"sourceId":"sanguozhi-wu-lu-xun","locator":"陆逊传","quote":"陆逊字伯言，吴郡吴人也。本名议，世江东大族。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('lu-xun-219-jingzhou', 'sanguozhi-wu-lu-xun', '陆逊传', '逊具启形状，陈其可禽之要。权乃潜军而上，使逊与吕蒙为前部，至即克公安、南郡。', '{"sourceId":"sanguozhi-wu-lu-xun","locator":"陆逊传","quote":"逊具启形状，陈其可禽之要。权乃潜军而上，使逊与吕蒙为前部，至即克公安、南郡。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('lu-xun-219-jingzhou', 'zizhi-tongjian-67', '建安二十四年', NULL, '{"sourceId":"zizhi-tongjian-67","locator":"建安二十四年"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('lu-xun-222-yiling', 'sanguozhi-wu-lu-xun', '陆逊传', '逊曰：“吾已晓破之之术。”乃敕各持一把茅，以火攻拔之。通率诸军同时俱攻，斩张南、冯习等，破其四十馀营。', '{"sourceId":"sanguozhi-wu-lu-xun","locator":"陆逊传","quote":"逊曰：“吾已晓破之之术。”乃敕各持一把茅，以火攻拔之。通率诸军同时俱攻，斩张南、冯习等，破其四十馀营。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('lu-xun-222-yiling', 'zizhi-tongjian-70', '黄武元年 / 章武二年', NULL, '{"sourceId":"zizhi-tongjian-70","locator":"黄武元年 / 章武二年"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('lu-xun-245-death', 'sanguozhi-wu-lu-xun', '陆逊传', '权累遣中使责让逊，逊愤恚致卒，时年六十三，家无馀财。', '{"sourceId":"sanguozhi-wu-lu-xun","locator":"陆逊传","quote":"权累遣中使责让逊，逊愤恚致卒，时年六十三，家无馀财。"}');
