INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-xiu-220-east-command', 'sanguozhi-wei-cao-xiu', '文帝即王位后', '文帝即王位，为领军将军，录前后功，封东阳亭侯。夏侯敦薨，以休为镇南将军，假节都督诸军事。', '{"sourceId":"sanguozhi-wei-cao-xiu","locator":"文帝即王位后","quote":"文帝即王位，为领军将军，录前后功，封东阳亭侯。夏侯敦薨，以休为镇南将军，假节都督诸军事。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-xiu-222-wu-front', 'sanguozhi-wei-cao-xiu', '曹休传', NULL, '{"sourceId":"sanguozhi-wei-cao-xiu","locator":"曹休传"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-xiu-228-shiting', 'sanguozhi-wei-cao-xiu', '太和二年', '太和二年，帝为二道征吴……贼将伪降，休深入，战不利，退还宿石亭。军夜惊，士卒乱，弃甲兵辎重甚多……休因此痈发背薨，谥曰壮侯。', '{"sourceId":"sanguozhi-wei-cao-xiu","locator":"太和二年","quote":"太和二年，帝为二道征吴……贼将伪降，休深入，战不利，退还宿石亭。军夜惊，士卒乱，弃甲兵辎重甚多……休因此痈发背薨，谥曰壮侯。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhen-unknown-birth', 'sanguozhi-wei-cao-zhen', '曹真传', '太祖哀真少孤，收养与诸子同，使与文帝共止。', '{"sourceId":"sanguozhi-wei-cao-zhen","locator":"曹真传","quote":"太祖哀真少孤，收养与诸子同，使与文帝共止。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhen-219-hanzhong', 'sanguozhi-wei-cao-zhen', '夏侯渊没于阳平后', '是时，夏侯渊没于阳平，太祖忧之。以真为征蜀护军，督徐晃等破刘备别将高详于阳平。', '{"sourceId":"sanguozhi-wei-cao-zhen","locator":"夏侯渊没于阳平后","quote":"是时，夏侯渊没于阳平，太祖忧之。以真为征蜀护军，督徐晃等破刘备别将高详于阳平。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhen-220-west-command', 'sanguozhi-wei-cao-zhen', '文帝即王位', '文帝即王位，以真为镇西将军，假节都督雍、凉州诸军事。录前后功，进封东乡侯。', '{"sourceId":"sanguozhi-wei-cao-zhen","locator":"文帝即王位","quote":"文帝即王位，以真为镇西将军，假节都督雍、凉州诸军事。录前后功，进封东乡侯。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhen-226-regency', 'sanguozhi-wei-cao-zhen', '黄初七年', '七年，文帝寝疾，真与陈群、司马宣王等受遗诏辅政。明帝即位，进封邵陵侯……迁大将军。', '{"sourceId":"sanguozhi-wei-cao-zhen","locator":"黄初七年","quote":"七年，文帝寝疾，真与陈群、司马宣王等受遗诏辅政。明帝即位，进封邵陵侯……迁大将军。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhen-231-death', 'sanguozhi-wei-cao-zhen', '太和五年前后', '真病还洛阳，帝自幸其第省疾。真薨，谥曰元侯。子爽嗣。', '{"sourceId":"sanguozhi-wei-cao-zhen","locator":"太和五年前后","quote":"真病还洛阳，帝自幸其第省疾。真薨，谥曰元侯。子爽嗣。"}');
