INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-184-yellow-turban', 'sanguozhi-wei-wudi', '光和末', '光和末，黄巾起。拜骑都尉，讨颍川贼。迁为济南相。', '{"sourceId":"sanguozhi-wei-wudi","locator":"光和末","quote":"光和末，黄巾起。拜骑都尉，讨颍川贼。迁为济南相。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-189-dong-zhuo-east', 'sanguozhi-wei-wudi', '中平六年', '卓表太祖为骁骑校尉，欲与计事。太祖乃变易姓名，间行东归。', '{"sourceId":"sanguozhi-wei-wudi","locator":"中平六年","quote":"卓表太祖为骁骑校尉，欲与计事。太祖乃变易姓名，间行东归。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-192-yanzhou-qingzhou', 'sanguozhi-wei-wudi', '初平三年', '信乃与州吏万潜等至东郡迎太祖领兖州牧。冬，受降卒三十馀万，男女百馀万口，收其精锐者，号为青州兵。', '{"sourceId":"sanguozhi-wei-wudi","locator":"初平三年","quote":"信乃与州吏万潜等至东郡迎太祖领兖州牧。冬，受降卒三十馀万，男女百馀万口，收其精锐者，号为青州兵。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-197-wan-defeat', 'sanguozhi-wei-wudi', '建安二年', '二年春正月，公到宛。张绣降，旣而悔之，复反。公与战，军败，为流矢所中，长子昂、弟子安民遇害。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安二年","quote":"二年春正月，公到宛。张绣降，旣而悔之，复反。公与战，军败，为流矢所中，长子昂、弟子安民遇害。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-207-white-wolf', 'sanguozhi-wei-wudi', '建安十二年八月', '八月，登白狼山，卒与虏遇，衆甚盛。公登高，望虏陈不整，乃纵兵击之，使张辽为先锋，虏衆大崩。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安十二年八月","quote":"八月，登白狼山，卒与虏遇，衆甚盛。公登高，望虏陈不整，乃纵兵击之，使张辽为先锋，虏衆大崩。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-211-tongguan', 'sanguozhi-wei-wudi', '建安十六年', '超等屯潼关，公勑诸将：“关西兵精悍，坚壁勿与战。”秋七月，公西征。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安十六年","quote":"超等屯潼关，公勑诸将：“关西兵精悍，坚壁勿与战。”秋七月，公西征。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-cao-217-cao-pi-heir', 'sanguozhi-wei-wendi', '建安二十二年', '建安十六年，为五官中郎将、副丞相。二十二年，立为魏太子。', '{"sourceId":"sanguozhi-wei-wendi","locator":"建安二十二年","quote":"建安十六年，为五官中郎将、副丞相。二十二年，立为魏太子。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-pi-211-wuguan', 'sanguozhi-wei-wendi', '建安十六年', '建安十六年，为五官中郎将、副丞相。', '{"sourceId":"sanguozhi-wei-wendi","locator":"建安十六年","quote":"建安十六年，为五官中郎将、副丞相。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-pi-217-heir', 'sanguozhi-wei-wendi', '建安二十二年', '二十二年，立为魏太子。', '{"sourceId":"sanguozhi-wei-wendi","locator":"建安二十二年","quote":"二十二年，立为魏太子。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-pi-221-sun-quan-vassal', 'sanguozhi-wei-wendi', '黄初二年八月', '秋八月，孙权遣使奉章，并遣于禁等还。丁巳，使太常邢贞持节拜权为大将军，封吴王，加九锡。', '{"sourceId":"sanguozhi-wei-wendi","locator":"黄初二年八月","quote":"秋八月，孙权遣使奉章，并遣于禁等还。丁巳，使太常邢贞持节拜权为大将军，封吴王，加九锡。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-pi-222-south-campaign', 'sanguozhi-wei-wendi', '黄初三年', '六月辛亥，治兵于东郊。庚午，遂南征。', '{"sourceId":"sanguozhi-wei-wendi","locator":"黄初三年","quote":"六月辛亥，治兵于东郊。庚午，遂南征。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-pi-225-guangling', 'sanguozhi-wei-wendi', '黄初六年', '冬十月，行幸广陵故城，临江观兵，戎卒十馀万，旌旗数百里。', '{"sourceId":"sanguozhi-wei-wendi","locator":"黄初六年","quote":"冬十月，行幸广陵故城，临江观兵，戎卒十馀万，旌旗数百里。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-rui-204-born', 'sanguozhi-wei-mingdi', '明帝纪开篇', '明皇帝讳睿，字元仲，文帝太子也。生而太祖爱之，常令在左右。', '{"sourceId":"sanguozhi-wei-mingdi","locator":"明帝纪开篇","quote":"明皇帝讳睿，字元仲，文帝太子也。生而太祖爱之，常令在左右。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-rui-220-enfeoffment', 'sanguozhi-wei-mingdi', '黄初年间', '年十五，封武德侯，黄初二年为齐公，三年为平原王。以其母诛，故未建为嗣。', '{"sourceId":"sanguozhi-wei-mingdi","locator":"黄初年间","quote":"年十五，封武德侯，黄初二年为齐公，三年为平原王。以其母诛，故未建为嗣。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-rui-226-accession', 'sanguozhi-wei-mingdi', '黄初七年五月', '七年夏五月，帝病笃，乃立为皇太子。丁巳，即皇帝位，大赦。', '{"sourceId":"sanguozhi-wei-mingdi","locator":"黄初七年五月","quote":"七年夏五月，帝病笃，乃立为皇太子。丁巳，即皇帝位，大赦。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-rui-228-zhuge-liang-first-northern-expedition', 'sanguozhi-wei-mingdi', '太和二年', '蜀大将诸葛亮寇边，天水、南安、安定三郡吏民叛应亮。', '{"sourceId":"sanguozhi-wei-mingdi","locator":"太和二年","quote":"蜀大将诸葛亮寇边，天水、南安、安定三郡吏民叛应亮。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-rui-234-wuzhang', 'sanguozhi-wei-mingdi', '青龙二年', '是月，诸葛亮出斜谷，屯渭南，司马宣王率诸军拒之。会亮卒，其军退还。', '{"sourceId":"sanguozhi-wei-mingdi","locator":"青龙二年","quote":"是月，诸葛亮出斜谷，屯渭南，司马宣王率诸军拒之。会亮卒，其军退还。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-rui-238-liaodong', 'sanguozhi-wei-mingdi', '景初二年', '丙寅，司马宣王围公孙渊于襄平，大破之，传渊首于京都，海东诸郡平。', '{"sourceId":"sanguozhi-wei-mingdi","locator":"景初二年","quote":"丙寅，司马宣王围公孙渊于襄平，大破之，传渊首于京都，海东诸郡平。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-rui-239-death', 'sanguozhi-wei-mingdi', '景初三年正月', '即日，帝崩于嘉福殿，魏书曰：殡于九龙前殿。时年三十六。', '{"sourceId":"sanguozhi-wei-mingdi","locator":"景初三年正月","quote":"即日，帝崩于嘉福殿，魏书曰：殡于九龙前殿。时年三十六。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhang-early-martial', 'sanguozhi-wei-cao-zhang', '本传开篇', '任城威王彰，字子文。少善射御，膂力过人，手格猛兽，不避险阻。', '{"sourceId":"sanguozhi-wei-cao-zhang","locator":"本传开篇","quote":"任城威王彰，字子文。少善射御，膂力过人，手格猛兽，不避险阻。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhang-218-daijun', 'sanguozhi-wei-cao-zhang', '建安二十三年', '二十三年，代郡乌丸反，以彰为北中郎将，行骁骑将军。', '{"sourceId":"sanguozhi-wei-cao-zhang","locator":"建安二十三年","quote":"二十三年，代郡乌丸反，以彰为北中郎将，行骁骑将军。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhang-222-rencheng', 'sanguozhi-wei-cao-zhang', '黄初三年', '三年，立为任城王。', '{"sourceId":"sanguozhi-wei-cao-zhang","locator":"黄初三年","quote":"三年，立为任城王。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhang-223-death', 'sanguozhi-wei-cao-zhang', '黄初四年', '四年，朝京都，疾薨于邸，谥曰威。', '{"sourceId":"sanguozhi-wei-cao-zhang","locator":"黄初四年","quote":"四年，朝京都，疾薨于邸，谥曰威。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhi-192-birth', 'sanguozhi-wei-cao-zhi', '太和六年', '遂发疾薨，时年四十一。', '{"sourceId":"sanguozhi-wei-cao-zhi","locator":"太和六年","quote":"遂发疾薨，时年四十一。","note":"生年据卒年和享年反推。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhi-early-literary-talent', 'sanguozhi-wei-cao-zhi', '本传开篇', '陈思王植字子建。年十岁馀，诵读诗、论及辞赋数十万言，善属文。', '{"sourceId":"sanguozhi-wei-cao-zhi","locator":"本传开篇","quote":"陈思王植字子建。年十岁馀，诵读诗、论及辞赋数十万言，善属文。","note":"年份据曹植生年和“年十岁馀”约推。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhi-210-copper-terrace', 'sanguozhi-wei-cao-zhi', '邺铜雀台', '植援笔立成，可观，太祖甚异之。', '{"sourceId":"sanguozhi-wei-cao-zhi","locator":"邺铜雀台","quote":"植援笔立成，可观，太祖甚异之。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhi-217-succession-rivalry', 'sanguozhi-wei-cao-zhi', '建安二十二年前后', '太祖狐疑，几为太子者数矣。而植任性而行，不自雕励，饮酒不节。', '{"sourceId":"sanguozhi-wei-cao-zhi","locator":"建安二十二年前后","quote":"太祖狐疑，几为太子者数矣。而植任性而行，不自雕励，饮酒不节。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhi-221-demotion', 'sanguozhi-wei-cao-zhi', '黄初二年', '黄初二年，监国谒者灌均希指，奏“植醉酒悖慢，劫胁使者”。有司请治罪，帝以太后故，贬爵安乡侯。', '{"sourceId":"sanguozhi-wei-cao-zhi","locator":"黄初二年","quote":"黄初二年，监国谒者灌均希指，奏“植醉酒悖慢，劫胁使者”。有司请治罪，帝以太后故，贬爵安乡侯。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhi-232-death', 'sanguozhi-wei-cao-zhi', '太和六年', '其二月，以陈四县封植为陈王，邑三千五百户。植每欲求别见独谈，论及时政，幸兾试用，终不能得。旣还，怅然绝望。遂发疾薨，时年四十一。', '{"sourceId":"sanguozhi-wei-cao-zhi","locator":"太和六年","quote":"其二月，以陈四县封植为陈王，邑三千五百户。植每欲求别见独谈，论及时政，幸兾试用，终不能得。旣还，怅然绝望。遂发疾薨，时年四十一。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-chong-196-birth', 'sanguozhi-wei-cao-chong', '建安十三年', '年十三，建安十三年疾病。', '{"sourceId":"sanguozhi-wei-cao-chong","locator":"建安十三年","quote":"年十三，建安十三年疾病。","note":"生年据卒年和享年反推。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-chong-early-talent', 'sanguozhi-wei-cao-chong', '本传开篇', '少聦察岐嶷，生五六岁，智意所及，有若成人之智。', '{"sourceId":"sanguozhi-wei-cao-chong","locator":"本传开篇","quote":"少聦察岐嶷，生五六岁，智意所及，有若成人之智。","note":"年份据曹冲约生年和“五六岁”约推。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-chong-elephant', 'sanguozhi-wei-cao-chong', '称象', '冲曰：“置象大船之上，而刻其水痕所至，称物以载之，则校可知矣。”', '{"sourceId":"sanguozhi-wei-cao-chong","locator":"称象","quote":"冲曰：“置象大船之上，而刻其水痕所至，称物以载之，则校可知矣。”","note":"本传未明纪年，置于曹冲五六岁早慧阶段。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-chong-mercy', 'sanguozhi-wei-cao-chong', '马鞍鼠啮', '太祖马鞌在库，而为鼠所啮，库吏惧必死。冲谓曰：“待三日中，然后自归。”', '{"sourceId":"sanguozhi-wei-cao-chong","locator":"马鞍鼠啮","quote":"太祖马鞌在库，而为鼠所啮，库吏惧必死。冲谓曰：“待三日中，然后自归。”","note":"本传未明纪年，暂置于曹冲去世前数年。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-chong-208-death', 'sanguozhi-wei-cao-chong', '建安十三年', '年十三，建安十三年疾病，太祖亲为请命。及亡，哀甚。', '{"sourceId":"sanguozhi-wei-cao-chong","locator":"建安十三年","quote":"年十三，建安十三年疾病，太祖亲为请命。及亡，哀甚。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-ang-early-xiaolian', 'sanguozhi-wei-cao-ang', '本传', '丰愍王昂字子修。弱冠举孝廉。', '{"sourceId":"sanguozhi-wei-cao-ang","locator":"本传","quote":"丰愍王昂字子修。弱冠举孝廉。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-ang-197-death', 'sanguozhi-wei-cao-ang', '本传', '随太祖南征，为张绣所害。', '{"sourceId":"sanguozhi-wei-cao-ang","locator":"本传","quote":"随太祖南征，为张绣所害。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-ang-197-death', 'sanguozhi-wei-wudi', '建安二年', '公与战，军败，为流矢所中，长子昂、弟子安民遇害。', '{"sourceId":"sanguozhi-wei-wudi","locator":"建安二年","quote":"公与战，军败，为流矢所中，长子昂、弟子安民遇害。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-shuang-239-regency', 'sanguozhi-wei-cao-shuang', '明帝末年', '帝寝疾，乃引爽入卧内，拜大将军，假节钺，都督中外诸军事，录尚书事，与太尉司马宣王并受遗诏辅少主。', '{"sourceId":"sanguozhi-wei-cao-shuang","locator":"明帝末年","quote":"帝寝疾，乃引爽入卧内，拜大将军，假节钺，都督中外诸军事，录尚书事，与太尉司马宣王并受遗诏辅少主。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-shuang-240-power-network', 'sanguozhi-wei-cao-shuang', '正始初', '爽弟羲为中领军，训武衞将军，彦散骑常侍侍讲，其馀诸弟皆以列侯侍从，出入禁闼，贵宠莫盛焉。', '{"sourceId":"sanguozhi-wei-cao-shuang","locator":"正始初","quote":"爽弟羲为中领军，训武衞将军，彦散骑常侍侍讲，其馀诸弟皆以列侯侍从，出入禁闼，贵宠莫盛焉。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-shuang-244-shu-campaign', 'sanguozhi-wei-cao-shuang', '正始五年', '正始五年，爽乃西至长安，大发卒六七万人，从骆谷入。', '{"sourceId":"sanguozhi-wei-cao-shuang","locator":"正始五年","quote":"正始五年，爽乃西至长安，大发卒六七万人，从骆谷入。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-shuang-249-gaopingling', 'sanguozhi-wei-cao-shuang', '正始十年正月', '十年正月，车驾朝高平陵，爽兄弟皆从。宣王部勒兵马，先据武库，遂出屯洛水浮桥。', '{"sourceId":"sanguozhi-wei-cao-shuang","locator":"正始十年正月","quote":"十年正月，车驾朝高平陵，爽兄弟皆从。宣王部勒兵马，先据武库，遂出屯洛水浮桥。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-shuang-249-death', 'sanguozhi-wei-cao-shuang', '正始十年', '于是收爽、羲、训、晏、扬、谧、轨、胜、范、当等，皆伏诛，夷三族。', '{"sourceId":"sanguozhi-wei-cao-shuang","locator":"正始十年","quote":"于是收爽、羲、训、晏、扬、谧、轨、胜、范、当等，皆伏诛，夷三族。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-fang-235-qi-wang', 'sanguozhi-wei-qi-wang', '青龙三年', '青龙三年，立为齐王。', '{"sourceId":"sanguozhi-wei-qi-wang","locator":"青龙三年","quote":"青龙三年，立为齐王。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-fang-239-enthroned', 'sanguozhi-wei-qi-wang', '景初三年正月', '景初三年正月丁亥朔，帝甚病，乃立为皇太子。是日，即皇帝位，大赦。尊皇后曰皇太后。大将军曹爽、太尉司马宣王辅政。', '{"sourceId":"sanguozhi-wei-qi-wang","locator":"景初三年正月","quote":"景初三年正月丁亥朔，帝甚病，乃立为皇太子。是日，即皇帝位，大赦。尊皇后曰皇太后。大将军曹爽、太尉司马宣王辅政。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-fang-249-gaopingling', 'sanguozhi-wei-qi-wang', '嘉平元年春正月', '嘉平元年春正月甲午，车驾谒高平陵。太傅司马宣王奏免大将军曹爽、爽弟中领军羲、武卫将军训、散骑常侍彦官，以侯就第。', '{"sourceId":"sanguozhi-wei-qi-wang","locator":"嘉平元年春正月","quote":"嘉平元年春正月甲午，车驾谒高平陵。太傅司马宣王奏免大将军曹爽、爽弟中领军羲、武卫将军训、散骑常侍彦官，以侯就第。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-fang-254-deposed', 'sanguozhi-wei-qi-wang', '嘉平六年九月', '秋九月，大将军司马景王将谋废帝，以闻皇太后。甲戌，太后令曰：皇帝芳春秋已长，不亲万机……遣芳归藩于齐，以避皇位。', '{"sourceId":"sanguozhi-wei-qi-wang","locator":"嘉平六年九月","quote":"秋九月，大将军司马景王将谋废帝，以闻皇太后。甲戌，太后令曰：皇帝芳春秋已长，不亲万机……遣芳归藩于齐，以避皇位。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-mao-244-gaogui', 'sanguozhi-wei-gaogui-xianggong', '正始五年', '高贵乡公讳髦，字彦士，文帝孙，东海定王霖子也。正始五年，封歘县高贵乡公。少好学，夙成。', '{"sourceId":"sanguozhi-wei-gaogui-xianggong","locator":"正始五年","quote":"高贵乡公讳髦，字彦士，文帝孙，东海定王霖子也。正始五年，封歘县高贵乡公。少好学，夙成。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-mao-254-enthroned', 'sanguozhi-wei-gaogui-xianggong', '正元元年十月', '齐王废，公卿议迎立公。十月己丑，公至于玄武馆……其日即皇帝位于太极前殿。', '{"sourceId":"sanguozhi-wei-gaogui-xianggong","locator":"正元元年十月","quote":"齐王废，公卿议迎立公。十月己丑，公至于玄武馆……其日即皇帝位于太极前殿。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-mao-260-sima-zhao', 'sanguozhi-wei-gaogui-xianggong', '甘露五年五月', '帝见威权日去，不胜其忿。乃召侍中王沈、尚书王经、散骑常侍王业，谓曰：“司马昭之心，路人所知也。吾不能坐受废辱，今日当与卿等自出讨之。”', '{"sourceId":"sanguozhi-wei-gaogui-xianggong","locator":"甘露五年五月","quote":"帝见威权日去，不胜其忿。乃召侍中王沈、尚书王经、散骑常侍王业，谓曰：“司马昭之心，路人所知也。吾不能坐受废辱，今日当与卿等自出讨之。”"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-mao-260-death', 'sanguozhi-wei-gaogui-xianggong', '甘露五年五月', '中护军贾充又逆帝战于南阙下，帝自用剑。众欲退，太子舍人成济问充曰：“事急矣。当云何？”充曰：“畜养汝等，正谓今日。今日之事，无所问也。”济即前刺帝，刃出于背。', '{"sourceId":"sanguozhi-wei-gaogui-xianggong","locator":"甘露五年五月","quote":"中护军贾充又逆帝战于南阙下，帝自用剑。众欲退，太子舍人成济问充曰：“事急矣。当云何？”充曰：“畜养汝等，正谓今日。今日之事，无所问也。”济即前刺帝，刃出于背。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-huan-258-changdao', 'sanguozhi-wei-chenliu-wang', '甘露三年', '陈留王讳奂，字景明，武帝孙，燕王宇子也。甘露三年，封安次县常道乡公。', '{"sourceId":"sanguozhi-wei-chenliu-wang","locator":"甘露三年","quote":"陈留王讳奂，字景明，武帝孙，燕王宇子也。甘露三年，封安次县常道乡公。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-huan-260-enthroned', 'sanguozhi-wei-chenliu-wang', '甘露五年六月', '高贵乡公卒，公卿议迎立公。六月甲寅，入于洛阳，见皇太后，是日即皇帝位于太极前殿，大赦，改年。', '{"sourceId":"sanguozhi-wei-chenliu-wang","locator":"甘露五年六月","quote":"高贵乡公卒，公卿议迎立公。六月甲寅，入于洛阳，见皇太后，是日即皇帝位于太极前殿，大赦，改年。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-huan-263-shu-surrender', 'sanguozhi-wei-chenliu-wang', '景元四年十一月', '自邓艾、锺会率众伐蜀，所至辄克。是月，蜀主刘禅诣艾降，巴蜀皆平。', '{"sourceId":"sanguozhi-wei-chenliu-wang","locator":"景元四年十一月","quote":"自邓艾、锺会率众伐蜀，所至辄克。是月，蜀主刘禅诣艾降，巴蜀皆平。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-huan-265-abdication', 'sanguozhi-wei-chenliu-wang', '咸熙二年十二月', '十二月壬戌，天禄永终，历数在晋。诏群公卿士具仪设坛于南郊，使使者奉皇帝玺绶册，禅位于晋嗣王，如汉魏故事。', '{"sourceId":"sanguozhi-wei-chenliu-wang","locator":"咸熙二年十二月","quote":"十二月壬戌，天禄永终，历数在晋。诏群公卿士具仪设坛于南郊，使使者奉皇帝玺绶册，禅位于晋嗣王，如汉魏故事。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-ren-early', 'sanguozhi-wei-cao-ren', '本传开篇', '曹仁字子孝，太祖从弟也。少好弓马弋猎……遂从太祖，为别部司马，行厉锋校尉。', '{"sourceId":"sanguozhi-wei-cao-ren","locator":"本传开篇","quote":"曹仁字子孝，太祖从弟也。少好弓马弋猎……遂从太祖，为别部司马，行厉锋校尉。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-ren-208-jiangling', 'sanguozhi-wei-cao-ren', '平荆州后', '从平荆州，以仁行征南将军，留屯江陵，拒吴将周瑜。', '{"sourceId":"sanguozhi-wei-cao-ren","locator":"平荆州后","quote":"从平荆州，以仁行征南将军，留屯江陵，拒吴将周瑜。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-ren-219-fancheng', 'sanguozhi-wei-cao-ren', '关羽攻樊', '关羽攻樊，时汉水暴溢，于禁等七军皆没，禁降羽。仁人马数千人守城，城不没者数板……徐晃救至，水亦稍减，晃从外击羽，仁得溃围出，羽退走。', '{"sourceId":"sanguozhi-wei-cao-ren","locator":"关羽攻樊","quote":"关羽攻樊，时汉水暴溢，于禁等七军皆没，禁降羽。仁人马数千人守城，城不没者数板……徐晃救至，水亦稍减，晃从外击羽，仁得溃围出，羽退走。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-ren-222-grand-marshal', 'sanguozhi-wei-cao-ren', '文帝时期', '文帝遣使即拜仁大将军。又诏仁移屯临颍，迁大司马，复督诸军据乌江，还屯合肥。', '{"sourceId":"sanguozhi-wei-cao-ren","locator":"文帝时期","quote":"文帝遣使即拜仁大将军。又诏仁移屯临颍，迁大司马，复督诸军据乌江，还屯合肥。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-hong-190-save-cao-cao', 'sanguozhi-wei-cao-hong', '讨董卓荥阳败后', '太祖失马，贼追甚急，洪下，以马授太祖，太祖辞让，洪曰：“天下可无洪，不可无君。”遂步从到汴水。', '{"sourceId":"sanguozhi-wei-cao-hong","locator":"讨董卓荥阳败后","quote":"太祖失马，贼追甚急，洪下，以马授太祖，太祖辞让，洪曰：“天下可无洪，不可无君。”遂步从到汴水。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-hong-194-yan-zhou', 'sanguozhi-wei-cao-hong', '张邈迎吕布', '太祖征徐州，张邈举兖州叛迎吕布。时大饥荒，洪将兵在前，先据东平、范，聚粮谷以继军。', '{"sourceId":"sanguozhi-wei-cao-hong","locator":"张邈迎吕布","quote":"太祖征徐州，张邈举兖州叛迎吕布。时大饥荒，洪将兵在前，先据东平、范，聚粮谷以继军。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-hong-226-later-office', 'sanguozhi-wei-cao-hong', '明帝即位后', '明帝即位，拜后将军，更封乐城侯，邑千户，位特进，复拜骠骑将军。', '{"sourceId":"sanguozhi-wei-cao-hong","locator":"明帝即位后","quote":"明帝即位，拜后将军，更封乐城侯，邑千户，位特进，复拜骠骑将军。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-hong-232-death', 'sanguozhi-wei-cao-hong', '太和六年', '太和六年薨，谥曰恭侯。子馥，嗣侯。', '{"sourceId":"sanguozhi-wei-cao-hong","locator":"太和六年","quote":"太和六年薨，谥曰恭侯。子馥，嗣侯。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-xiu-early-qianliju', 'sanguozhi-wei-cao-xiu', '早年归曹操', '太祖谓左右曰：“此吾家千里驹也。”使与文帝同止，见待如子。常从征伐，使领虎豹骑宿卫。', '{"sourceId":"sanguozhi-wei-cao-xiu","locator":"早年归曹操","quote":"太祖谓左右曰：“此吾家千里驹也。”使与文帝同止，见待如子。常从征伐，使领虎豹骑宿卫。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-xiu-218-xiabian', 'sanguozhi-wei-cao-xiu', '刘备遣吴兰屯下辩', '刘备遣将吴兰屯下辩，太祖遣曹洪征之，以休为骑都尉，参洪军事。太祖谓休曰：“汝虽参军，其实帅也。”', '{"sourceId":"sanguozhi-wei-cao-xiu","locator":"刘备遣吴兰屯下辩","quote":"刘备遣将吴兰屯下辩，太祖遣曹洪征之，以休为骑都尉，参洪军事。太祖谓休曰：“汝虽参军，其实帅也。”"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhen-early-adopted', 'sanguozhi-wei-cao-zhen', '本传开篇', '太祖哀真少孤，收养与诸子同，使与文帝共止……太祖壮其鸷勇，使将虎豹骑。', '{"sourceId":"sanguozhi-wei-cao-zhen","locator":"本传开篇","quote":"太祖哀真少孤，收养与诸子同，使与文帝共止……太祖壮其鸷勇，使将虎豹骑。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhen-228-qishan', 'sanguozhi-wei-cao-zhen', '诸葛亮围祁山', '诸葛亮围祁山，南安、天水、安定三郡反应亮。帝遣真督诸军军郿，遣张合击亮将马谡，大破之。', '{"sourceId":"sanguozhi-wei-cao-zhen","locator":"诸葛亮围祁山","quote":"诸葛亮围祁山，南安、天水、安定三郡反应亮。帝遣真督诸军军郿，遣张合击亮将马谡，大破之。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zhen-230-southern-campaign', 'sanguozhi-wei-cao-zhen', '太和四年', '真以“蜀连出侵边境，宜遂伐之。数道并入，可大克也”。帝从其计……真以八月发长安，从子午道南入……会大霖雨三十馀日，或栈道断绝，诏真还军。', '{"sourceId":"sanguozhi-wei-cao-zhen","locator":"太和四年","quote":"真以“蜀连出侵边境，宜遂伐之。数道并入，可大克也”。帝从其计……真以八月发长安，从子午道南入……会大霖雨三十馀日，或栈道断绝，诏真还军。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-xiong-royal-house-record', 'sanguozhi-wei-cao-xiong', '本传', '萧怀王熊，早薨。黄初二年追封谥萧怀公。太和三年，又追封爵为王。', '{"sourceId":"sanguozhi-wei-cao-xiong","locator":"本传","quote":"萧怀王熊，早薨。黄初二年追封谥萧怀公。太和三年，又追封爵为王。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-shuo-royal-house-record', 'sanguozhi-wei-cao-shuo', '本传', '相殇王铄，早薨，太和三年追封谥。青龙元年，子愍王潜嗣，其年薨。', '{"sourceId":"sanguozhi-wei-cao-shuo","locator":"本传","quote":"相殇王铄，早薨，太和三年追封谥。青龙元年，子愍王潜嗣，其年薨。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-ju-royal-house-record', 'sanguozhi-wei-cao-ju', '本传', '彭城王据，建安十六年封范阳侯。二十二年，徙封宛侯。黄初二年，进爵为公。三年，为章陵王……太和六年，改封诸王，皆以郡为国，据复封彭城。', '{"sourceId":"sanguozhi-wei-cao-ju","locator":"本传","quote":"彭城王据，建安十六年封范阳侯。二十二年，徙封宛侯。黄初二年，进爵为公。三年，为章陵王……太和六年，改封诸王，皆以郡为国，据复封彭城。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-yu-royal-house-record', 'sanguozhi-wei-cao-yu', '本传', '燕王宇字彭祖。建安十六年，封都乡侯……太和六年，改封燕王。明帝少与宇同止，常爱异之……冬十二月，明帝疾笃，拜宇为大将军，属以后事。受署四日，宇深固让；帝意亦变，遂免宇官。', '{"sourceId":"sanguozhi-wei-cao-yu","locator":"本传","quote":"燕王宇字彭祖。建安十六年，封都乡侯……太和六年，改封燕王。明帝少与宇同止，常爱异之……冬十二月，明帝疾笃，拜宇为大将军，属以后事。受署四日，宇深固让；帝意亦变，遂免宇官。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-lin-royal-house-record', 'sanguozhi-wei-cao-lin', '本传', '沛穆王林，建安十六年封饶阳侯……太和六年，改封沛。景初、正元、景元中，累增邑，并前四千七百户。林薨，子纬嗣。', '{"sourceId":"sanguozhi-wei-cao-lin","locator":"本传","quote":"沛穆王林，建安十六年封饶阳侯……太和六年，改封沛。景初、正元、景元中，累增邑，并前四千七百户。林薨，子纬嗣。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-gun-royal-house-record', 'sanguozhi-wei-cao-gun', '本传', '中山恭王衮，建安二十一年封平乡侯。少好学，年十余岁能属文……每兄弟游娱，衮独谭思经典。', '{"sourceId":"sanguozhi-wei-cao-gun","locator":"本传","quote":"中山恭王衮，建安二十一年封平乡侯。少好学，年十余岁能属文……每兄弟游娱，衮独谭思经典。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-xuan-royal-house-record', 'sanguozhi-wei-cao-xuan', '本传', '济阳怀王玹，建安十六年封西乡侯。早薨，无子。二十年，以沛王林子赞袭玹爵邑，早薨，无子。', '{"sourceId":"sanguozhi-wei-cao-xuan","locator":"本传","quote":"济阳怀王玹，建安十六年封西乡侯。早薨，无子。二十年，以沛王林子赞袭玹爵邑，早薨，无子。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-jun-royal-house-record', 'sanguozhi-wei-cao-jun', '本传', '陈留恭王峻字子安，建安二十一年封郿侯。二十二年，徙封襄邑。黄初二年，进爵为公。三年，为陈留王……甘露四年薨。', '{"sourceId":"sanguozhi-wei-cao-jun","locator":"本传","quote":"陈留恭王峻字子安，建安二十一年封郿侯。二十二年，徙封襄邑。黄初二年，进爵为公。三年，为陈留王……甘露四年薨。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-ju-fanyang-royal-house-record', 'sanguozhi-wei-cao-ju-fanyang', '本传', '范阳闵王矩，早薨，无子。建安二十二年，以樊安公均子敏奉矩后，封临晋侯。', '{"sourceId":"sanguozhi-wei-cao-ju-fanyang","locator":"本传","quote":"范阳闵王矩，早薨，无子。建安二十二年，以樊安公均子敏奉矩后，封临晋侯。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-gan-royal-house-record', 'sanguozhi-wei-cao-gan', '本传', '赵王干，建安二十年封高平亭侯……太和六年，改封赵王。干母有宠于太祖。及文帝为嗣，干母有力。文帝临崩，有遗诏，是以明帝常加恩意。', '{"sourceId":"sanguozhi-wei-cao-gan","locator":"本传","quote":"赵王干，建安二十年封高平亭侯……太和六年，改封赵王。干母有宠于太祖。及文帝为嗣，干母有力。文帝临崩，有遗诏，是以明帝常加恩意。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-shang-royal-house-record', 'sanguozhi-wei-cao-shang', '本传', '临邑殇公子上，早薨。太和五年，追封谥。无后。', '{"sourceId":"sanguozhi-wei-cao-shang","locator":"本传","quote":"临邑殇公子上，早薨。太和五年，追封谥。无后。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-biao-royal-house-record', 'sanguozhi-wei-cao-biao', '本传', '楚王彪字朱虎。建安二十一年，封寿春侯……嘉平元年，兖州刺史令狐愚与太尉王凌谋迎彪都许昌。语在凌传。乃遣傅及侍御史就国案验……使自图焉。', '{"sourceId":"sanguozhi-wei-cao-biao","locator":"本传","quote":"楚王彪字朱虎。建安二十一年，封寿春侯……嘉平元年，兖州刺史令狐愚与太尉王凌谋迎彪都许昌。语在凌传。乃遣傅及侍御史就国案验……使自图焉。"}');
