INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-zheng-royal-house-record', 'sanguozhi-wei-cao-zheng', '本传', '郿戴公子整，奉从叔父郎中绍后。建安二十二年，封郿侯。二十三年薨。无子。黄初二年追进爵，谥曰戴公。', '{"sourceId":"sanguozhi-wei-cao-zheng","locator":"本传","quote":"郿戴公子整，奉从叔父郎中绍后。建安二十二年，封郿侯。二十三年薨。无子。黄初二年追进爵，谥曰戴公。"}');
