INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-ji-royal-house-record', 'sanguozhi-wei-cao-ji', '本传', '广宗殇公子棘，早薨。太和五年追封谥。无后。', '{"sourceId":"sanguozhi-wei-cao-ji","locator":"本传","quote":"广宗殇公子棘，早薨。太和五年追封谥。无后。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-hui-royal-house-record', 'sanguozhi-wei-cao-hui', '本传', '东平灵王徽，奉叔公朗陵哀侯王后。建安二十二年，封历城侯……太和六年，改封东平。青龙二年，徽使官属檛寿张县吏，为有司所奏。诏削县一，户五百。其年复所削县。正始三年薨。', '{"sourceId":"sanguozhi-wei-cao-hui","locator":"本传","quote":"东平灵王徽，奉叔公朗陵哀侯王后。建安二十二年，封历城侯……太和六年，改封东平。青龙二年，徽使官属檛寿张县吏，为有司所奏。诏削县一，户五百。其年复所削县。正始三年薨。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-mao-prince-royal-house-record', 'sanguozhi-wei-cao-mao-prince', '本传', '乐陵王茂，建安二十二年封万岁亭侯……茂性慠佷，少无宠于太祖。及文帝世，又独不王。太和元年，徙封聊城公，其年为王。', '{"sourceId":"sanguozhi-wei-cao-mao-prince","locator":"本传","quote":"乐陵王茂，建安二十二年封万岁亭侯……茂性慠佷，少无宠于太祖。及文帝世，又独不王。太和元年，徙封聊城公，其年为王。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-xie-royal-house-record', 'sanguozhi-wei-cao-xie', '本传', '赞哀王协，早薨。太和五年追封谥曰经殇公。青龙二年，更追改号谥。三年，子殇王寻嗣。', '{"sourceId":"sanguozhi-wei-cao-xie","locator":"本传","quote":"赞哀王协，早薨。太和五年追封谥曰经殇公。青龙二年，更追改号谥。三年，子殇王寻嗣。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-rui-prince-royal-house-record', 'sanguozhi-wei-cao-rui-prince', '本传', '北海悼王蕤，黄初七年，明帝即位，立为阳平县王。太和六年，改封北海。青龙元年薨。', '{"sourceId":"sanguozhi-wei-cao-rui-prince","locator":"本传","quote":"北海悼王蕤，黄初七年，明帝即位，立为阳平县王。太和六年，改封北海。青龙元年薨。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-jian-royal-house-record', 'sanguozhi-wei-cao-jian', '本传', '东武阳怀王鉴，黄初六年立。其年薨。青龙三年赐谥。无子。国除。', '{"sourceId":"sanguozhi-wei-cao-jian","locator":"本传","quote":"东武阳怀王鉴，黄初六年立。其年薨。青龙三年赐谥。无子。国除。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-lin-donghai-royal-house-record', 'sanguozhi-wei-cao-lin-donghai', '本传', '东海定王霖，黄初三年立为河东王。六年，改封馆陶县。明帝即位，以先帝遗意，爱宠霖异于诸国。而霖性粗暴，闺门之内，婢妾之间，多所残害。太和六年，改封东海。嘉平元年薨……高贵乡公髦，霖之子也，入继大宗。', '{"sourceId":"sanguozhi-wei-cao-lin-donghai","locator":"本传","quote":"东海定王霖，黄初三年立为河东王。六年，改封馆陶县。明帝即位，以先帝遗意，爱宠霖异于诸国。而霖性粗暴，闺门之内，婢妾之间，多所残害。太和六年，改封东海。嘉平元年薨……高贵乡公髦，霖之子也，入继大宗。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-li-royal-house-record', 'sanguozhi-wei-cao-li', '本传', '元城哀王礼，黄初二年封秦公，以京兆郡为国。三年，改为京兆王。六年，改封元城王。太和三年薨。', '{"sourceId":"sanguozhi-wei-cao-li","locator":"本传","quote":"元城哀王礼，黄初二年封秦公，以京兆郡为国。三年，改为京兆王。六年，改封元城王。太和三年薨。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-yong-royal-house-record', 'sanguozhi-wei-cao-yong', '本传', '邯郸怀王邕，黄初二年封淮南公，以九江郡为国。三年，进为淮南王。四年，改封陈。六年，改封邯郸。太和三年薨。', '{"sourceId":"sanguozhi-wei-cao-yong","locator":"本传","quote":"邯郸怀王邕，黄初二年封淮南公，以九江郡为国。三年，进为淮南王。四年，改封陈。六年，改封邯郸。太和三年薨。"}');
