INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-shuang-249-gaopingling', 'zizhi-tongjian-75', '嘉平元年春正月甲午', '帝谒高平陵，大将军爽与弟中领军羲、武卫将军训、散骑常侍彦皆从。太傅懿以皇太后令，闭诸城门，勒兵据武库。', '{"lifeEventId":"cao-shuang-249-gaopingling","sourceId":"zizhi-tongjian-75","locator":"嘉平元年春正月甲午","quote":"帝谒高平陵，大将军爽与弟中领军羲、武卫将军训、散骑常侍彦皆从。太傅懿以皇太后令，闭诸城门，勒兵据武库。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-shuang-249-death', 'zizhi-tongjian-75', '嘉平元年正月戊戌', '于是收爽、羲、训、晏、颺、谧、轨、胜并桓范皆下狱，劾以大逆不道，与张当俱夷三族。', '{"lifeEventId":"cao-shuang-249-death","sourceId":"zizhi-tongjian-75","locator":"嘉平元年正月戊戌","quote":"于是收爽、羲、训、晏、颺、谧、轨、胜并桓范皆下狱，劾以大逆不道，与张当俱夷三族。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-fang-249-gaopingling', 'zizhi-tongjian-75', '嘉平元年春正月甲午', '帝谒高平陵，大将军爽与弟中领军羲、武卫将军训、散骑常侍彦皆从。太傅懿以皇太后令，闭诸城门，勒兵据武库。', '{"lifeEventId":"cao-fang-249-gaopingling","sourceId":"zizhi-tongjian-75","locator":"嘉平元年春正月甲午","quote":"帝谒高平陵，大将军爽与弟中领军羲、武卫将军训、散骑常侍彦皆从。太傅懿以皇太后令，闭诸城门，勒兵据武库。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-fang-254-deposed', 'zizhi-tongjian-76', '正元元年九月甲戌', '昭引兵入城，大将军师乃谋废帝。甲戌，师以皇太后令召群臣会议，以帝荒淫无度，亵近倡优，不可以承天绪。', '{"lifeEventId":"cao-fang-254-deposed","sourceId":"zizhi-tongjian-76","locator":"正元元年九月甲戌","quote":"昭引兵入城，大将军师乃谋废帝。甲戌，师以皇太后令召群臣会议，以帝荒淫无度，亵近倡优，不可以承天绪。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-mao-260-sima-zhao', 'zizhi-tongjian-77', '景元元年五月己丑', '帝见威权日去，不胜其忿。五月，己丑，召侍中王沈、尚书王经、散骑常侍王业，谓曰：“司马昭之心，路人所知也。”', '{"lifeEventId":"cao-mao-260-sima-zhao","sourceId":"zizhi-tongjian-77","locator":"景元元年五月己丑","quote":"帝见威权日去，不胜其忿。五月，己丑，召侍中王沈、尚书王经、散骑常侍王业，谓曰：“司马昭之心，路人所知也。”"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-mao-260-death', 'zizhi-tongjian-77', '景元元年五月己丑', '中护军贾充自外入，逆与帝战于南阙下。济即抽戈前刺帝，殒于车下。', '{"lifeEventId":"cao-mao-260-death","sourceId":"zizhi-tongjian-77","locator":"景元元年五月己丑","quote":"中护军贾充自外入，逆与帝战于南阙下。济即抽戈前刺帝，殒于车下。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-huan-263-shu-surrender', 'zizhi-tongjian-78', '景元四年冬十月', '汉主乃遣侍中张绍等奉玺绶以降于艾。艾至成都城北，汉主率太子诸王及群臣六十余人，面缚舆榇诣军门。', '{"lifeEventId":"cao-huan-263-shu-surrender","sourceId":"zizhi-tongjian-78","locator":"景元四年冬十月","quote":"汉主乃遣侍中张绍等奉玺绶以降于艾。艾至成都城北，汉主率太子诸王及群臣六十余人，面缚舆榇诣军门。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('liu-shan-263-surrender', 'zizhi-tongjian-78', '景元四年冬十月', '汉主乃遣侍中张绍等奉玺绶以降于艾。艾至成都城北，汉主率太子诸王及群臣六十余人，面缚舆榇诣军门。', '{"lifeEventId":"liu-shan-263-surrender","sourceId":"zizhi-tongjian-78","locator":"景元四年冬十月","quote":"汉主乃遣侍中张绍等奉玺绶以降于艾。艾至成都城北，汉主率太子诸王及群臣六十余人，面缚舆榇诣军门。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('deng-ai-263-yinping', 'zizhi-tongjian-78', '景元四年冬十月', '汉主乃遣侍中张绍等奉玺绶以降于艾。艾至成都城北，汉主率太子诸王及群臣六十余人，面缚舆榇诣军门。', '{"lifeEventId":"deng-ai-263-yinping","sourceId":"zizhi-tongjian-78","locator":"景元四年冬十月","quote":"汉主乃遣侍中张绍等奉玺绶以降于艾。艾至成都城北，汉主率太子诸王及群臣六十余人，面缚舆榇诣军门。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('deng-ai-264-death', 'zizhi-tongjian-78', '咸熙元年正月', '卫瓘乃遣护军田续等将兵袭艾，遇于绵竹西，斩艾父子。', '{"lifeEventId":"deng-ai-264-death","sourceId":"zizhi-tongjian-78","locator":"咸熙元年正月","quote":"卫瓘乃遣护军田续等将兵袭艾，遇于绵竹西，斩艾父子。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('zhong-hui-264-death', 'zizhi-tongjian-78', '咸熙元年正月', '姜维率会左右战，手杀五六人，众格斩维，争前杀会。', '{"lifeEventId":"zhong-hui-264-death","sourceId":"zizhi-tongjian-78","locator":"咸熙元年正月","quote":"姜维率会左右战，手杀五六人，众格斩维，争前杀会。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-biao-royal-house-record', 'zizhi-tongjian-75', '嘉平元年秋九月', '凌与愚阴谋，以帝暗弱，制于强臣，闻楚王彪有智勇，欲共立之，迎都许昌。', '{"lifeEventId":"cao-biao-royal-house-record","sourceId":"zizhi-tongjian-75","locator":"嘉平元年秋九月","quote":"凌与愚阴谋，以帝暗弱，制于强臣，闻楚王彪有智勇，欲共立之，迎都许昌。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('cao-biao-royal-house-record', 'zizhi-tongjian-75', '嘉平三年六月', '六月，赐楚王彪死。尽录诸王公置邺，使有司察之，不得与人交关。', '{"lifeEventId":"cao-biao-royal-house-record","sourceId":"zizhi-tongjian-75","locator":"嘉平三年六月","quote":"六月，赐楚王彪死。尽录诸王公置邺，使有司察之，不得与人交关。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('wang-ling-249-251-cao-biao-plot', 'zizhi-tongjian-75', '嘉平元年秋九月至嘉平三年五月', '凌与愚阴谋，以帝暗弱，制于强臣，闻楚王彪有智勇，欲共立之，迎都许昌。', '{"lifeEventId":"wang-ling-249-251-cao-biao-plot","sourceId":"zizhi-tongjian-75","locator":"嘉平元年秋九月至嘉平三年五月","quote":"凌与愚阴谋，以帝暗弱，制于强臣，闻楚王彪有智勇，欲共立之，迎都许昌。"}');
INSERT INTO "person_life_event_source_refs" ("life_event_id", "source_id", "locator", "quote", "raw_json") VALUES ('wang-ling-249-251-cao-biao-plot', 'zizhi-tongjian-75', '嘉平三年五月甲寅', '凌行到项，遂饮药死。', '{"lifeEventId":"wang-ling-249-251-cao-biao-plot","sourceId":"zizhi-tongjian-75","locator":"嘉平三年五月甲寅","quote":"凌行到项，遂饮药死。"}');
