INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('cao-cao-han-xiandi-court-control', 'cao-cao', 'han-xiandi', 'court-control', 196, 220, '曹操迎献帝至许，以汉廷名义整合政治合法性，同时实际掌握朝政。', 'medium', '{"id":"cao-cao-han-xiandi-court-control","sourcePersonId":"cao-cao","targetPersonId":"han-xiandi","type":"court-control","startYear":196,"endYear":220,"summary":"曹操迎献帝至许，以汉廷名义整合政治合法性，同时实际掌握朝政。","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安元年前后"},{"sourceId":"houhanshu-xiandi","locator":"建安元年"}]}');
INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('cao-cao-cao-pi-family-successor', 'cao-cao', 'cao-pi', 'family-successor', 187, 220, '曹丕为曹操之子，继承魏王地位并在同年受禅称帝。', 'medium', '{"id":"cao-cao-cao-pi-family-successor","sourcePersonId":"cao-cao","targetPersonId":"cao-pi","type":"family-successor","startYear":187,"endYear":220,"summary":"曹丕为曹操之子，继承魏王地位并在同年受禅称帝。","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安二十五年"},{"sourceId":"sanguozhi-wei-wendi","locator":"黄初元年"}]}');
INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('cao-pi-han-xiandi-abdication', 'cao-pi', 'han-xiandi', 'abdication', 220, 220, '曹丕接受汉献帝禅让，建立曹魏，东汉正式结束。', 'medium', '{"id":"cao-pi-han-xiandi-abdication","sourcePersonId":"cao-pi","targetPersonId":"han-xiandi","type":"abdication","startYear":220,"endYear":220,"summary":"曹丕接受汉献帝禅让，建立曹魏，东汉正式结束。","sourceRefs":[{"sourceId":"sanguozhi-wei-wendi","locator":"黄初元年"},{"sourceId":"houhanshu-xiandi","locator":"延康元年"}]}');
INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('cao-cao-yuan-shao-rivalry', 'cao-cao', 'yuan-shao', 'rival', 190, 202, '二人从讨董盟友转为北方霸权竞争者，官渡之战后袁绍集团优势瓦解。', 'medium', '{"id":"cao-cao-yuan-shao-rivalry","sourcePersonId":"cao-cao","targetPersonId":"yuan-shao","type":"rival","startYear":190,"endYear":202,"summary":"二人从讨董盟友转为北方霸权竞争者，官渡之战后袁绍集团优势瓦解。","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"官渡相关记载"},{"sourceId":"sanguozhi-wei-yuan-shao","locator":"袁绍传"}]}');
INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('yuan-shao-gongsun-zan-north-rivalry', 'yuan-shao', 'gongsun-zan', 'rival', 191, 199, '袁绍与公孙瓒围绕冀州、幽州及河北北部持续争夺。', 'medium', '{"id":"yuan-shao-gongsun-zan-north-rivalry","sourcePersonId":"yuan-shao","targetPersonId":"gongsun-zan","type":"rival","startYear":191,"endYear":199,"summary":"袁绍与公孙瓒围绕冀州、幽州及河北北部持续争夺。","sourceRefs":[{"sourceId":"sanguozhi-wei-yuan-shao","locator":"袁绍传"},{"sourceId":"sanguozhi-wei-gongsun-zan","locator":"公孙瓒传"}]}');
INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('cao-cao-lu-bu-enemy', 'cao-cao', 'lu-bu', 'enemy', 194, 199, '吕布袭取兖州后与曹操成为直接军事敌手，后曹操攻下下邳。', 'medium', '{"id":"cao-cao-lu-bu-enemy","sourcePersonId":"cao-cao","targetPersonId":"lu-bu","type":"enemy","startYear":194,"endYear":199,"summary":"吕布袭取兖州后与曹操成为直接军事敌手，后曹操攻下下邳。","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"兴平至建安三年"},{"sourceId":"sanguozhi-wei-lubu","locator":"吕布传"}]}');
INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('cao-cao-liu-bei-ally-to-rival', 'cao-cao', 'liu-bei', 'ally-rival', 198, 220, '刘备曾与曹操协力攻吕布，也曾短暂依附曹操；此后双方围绕徐州、荆州、益州和汉中长期对抗。', 'medium', '{"id":"cao-cao-liu-bei-ally-to-rival","sourcePersonId":"cao-cao","targetPersonId":"liu-bei","type":"ally-rival","startYear":198,"endYear":220,"summary":"刘备曾与曹操协力攻吕布，也曾短暂依附曹操；此后双方围绕徐州、荆州、益州和汉中长期对抗。","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安三年至二十四年"},{"sourceId":"sanguozhi-shu-xianzhu","locator":"先主传徐州、荆州、汉中相关记载"}]}');
INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('cao-cao-sun-quan-rivalry', 'cao-cao', 'sun-quan', 'rival', 208, 220, '赤壁之后，曹操集团与孙权集团长期围绕江淮、荆州与长江防线竞争，南北对峙格局趋于稳定。', 'medium', '{"id":"cao-cao-sun-quan-rivalry","sourcePersonId":"cao-cao","targetPersonId":"sun-quan","type":"rival","startYear":208,"endYear":220,"summary":"赤壁之后，曹操集团与孙权集团长期围绕江淮、荆州与长江防线竞争，南北对峙格局趋于稳定。","sourceRefs":[{"sourceId":"sanguozhi-wei-wudi","locator":"建安十三年以后南方战事"},{"sourceId":"sanguozhi-wu-wuzhu","locator":"吴主传赤壁至合肥相关记载"},{"sourceId":"zizhi-tongjian-65","locator":"建安十三年"}]}');
INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('liu-bei-zhuge-liang-advisor', 'liu-bei', 'zhuge-liang', 'advisor', 207, 223, '刘备延揽诸葛亮后，以隆中对为重要战略构想，逐步形成荆益并重的路线。', 'medium', '{"id":"liu-bei-zhuge-liang-advisor","sourcePersonId":"liu-bei","targetPersonId":"zhuge-liang","type":"advisor","startYear":207,"endYear":223,"summary":"刘备延揽诸葛亮后，以隆中对为重要战略构想，逐步形成荆益并重的路线。","sourceRefs":[{"sourceId":"sanguozhi-shu-zhuge-liang","locator":"隆中对相关记载"},{"sourceId":"sanguozhi-shu-xianzhu","locator":"建安十二年前后"}]}');
INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('liu-bei-guan-yu-core-ally', 'liu-bei', 'guan-yu', 'core-ally', 184, 220, '关羽长期追随刘备，是刘备集团早期和荆州阶段的核心将领。', 'medium', '{"id":"liu-bei-guan-yu-core-ally","sourcePersonId":"liu-bei","targetPersonId":"guan-yu","type":"core-ally","startYear":184,"endYear":220,"summary":"关羽长期追随刘备，是刘备集团早期和荆州阶段的核心将领。","sourceRefs":[{"sourceId":"sanguozhi-shu-guan-yu","locator":"关羽传"},{"sourceId":"sanguozhi-shu-xianzhu","locator":"先主传"}]}');
