INSERT INTO "person_relations" ("id", "source_person_id", "target_person_id", "type", "start_year", "end_year", "summary", "confidence", "raw_json") VALUES ('cao-pi-cao-zhi-succession-rivalry', 'cao-pi', 'cao-zhi', 'succession-rival', 211, 221, '曹丕与曹植围绕魏太子地位形成继承竞争；曹丕胜出后，曹植在黄初年间受到宗室法制约束和贬爵。', 'medium', '{"id":"cao-pi-cao-zhi-succession-rivalry","sourcePersonId":"cao-pi","targetPersonId":"cao-zhi","type":"succession-rival","startYear":211,"endYear":221,"summary":"曹丕与曹植围绕魏太子地位形成继承竞争；曹丕胜出后，曹植在黄初年间受到宗室法制约束和贬爵。","sourceRefs":[{"sourceId":"sanguozhi-wei-cao-zhi","locator":"建安二十二年前后","quote":"太祖狐疑，几为太子者数矣。而植任性而行，不自雕励，饮酒不节。"},{"sourceId":"sanguozhi-wei-cao-zhi","locator":"黄初二年","quote":"帝以太后故，贬爵安乡侯。"}]}');
